  ('srd-2024_aboleth', 'Aboleth', 'Aberration', 'Large', 10, 5900, 17, 150, '{"key":"srd-2024_aboleth","name":"Aboleth","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"type":{"name":"Aberration","key":"aberration"},"size":{"name":"Large","key":"large"},"challenge_rating":10,"proficiency_bonus":null,"speed":{"walk":10,"unit":"feet","swim":40},"speed_all":{"unit":"feet","walk":10,"crawl":5,"hover":false,"fly":0,"burrow":0,"climb":5,"swim":40},"category":"Monsters","subcategory":null,"alignment":"lawful evil","languages":{"as_string":"Deep Speech; telepathy 120 ft.","data":[{"name":"Deep Speech","key":"deep-speech","desc":"Typical speakers include aboleths and cloakers. It is only spoken."}]},"armor_class":17,"armor_detail":"natural armor","hit_points":150,"hit_dice":"20d10 + 40","experience_points":5900,"ability_scores":{"strength":21,"dexterity":9,"constitution":15,"intelligence":18,"wisdom":15,"charisma":18},"modifiers":{"strength":5,"dexterity":-1,"constitution":2,"intelligence":4,"wisdom":2,"charisma":4},"initiative_bonus":7,"saving_throws":{"strength":5,"dexterity":3,"constitution":6,"intelligence":8,"wisdom":6,"charisma":4},"saving_throws_all":{"strength":5,"dexterity":3,"constitution":6,"intelligence":8,"wisdom":6,"charisma":4},"skill_bonuses":{"history":12,"perception":10},"skill_bonuses_all":{"acrobatics":-1,"animal_handling":2,"arcana":4,"athletics":5,"deception":4,"history":12,"insight":2,"intimidation":4,"investigation":4,"medicine":2,"nature":4,"perception":10,"performance":4,"persuasion":4,"religion":4,"sleight_of_hand":-1,"stealth":-1,"survival":2},"passive_perception":20,"resistances_and_immunities":{"damage_immunities_display":"","damage_immunities":[],"damage_resistances_display":"","damage_resistances":[],"damage_vulnerabilities_display":"","damage_vulnerabilities":[],"condition_immunities_display":"","condition_immunities":[]},"normal_sight_range":10560,"darkvision_range":120,"blindsight_range":null,"tremorsense_range":null,"truesight_range":null,"actions":[{"name":"Consume Memories","desc":"Intelligence Saving Throw: DC 16, one creature within 30 feet that is Charmed or Grappled by the aboleth. Failure: 10 (3d6) Psychic damage. Success: Half damage. Failure or Success: The aboleth gains the target''s memories if the target is a Humanoid and is reduced to 0 Hit Points by this action.","attacks":[],"action_type":"ACTION","order_in_statblock":2,"legendary_action_cost":1,"limited_to_form":null,"usage_limits":null},{"name":"Dominate Mind","desc":"Wisdom Saving Throw: DC 16, one creature the aboleth can see within 30 feet. Failure: The target has the Charmed condition until the aboleth dies or is on a different plane of existence from the target. While Charmed, the target acts as an ally to the aboleth and is under its control while within 60 feet of it. In addition, the aboleth and the target can communicate telepathically with each other over any distance. The target repeats the save whenever it takes damage as well as after every 24 hours it spends at least 1 mile away from the aboleth, ending the effect on itself on a success.","attacks":[],"action_type":"ACTION","order_in_statblock":3,"legendary_action_cost":null,"limited_to_form":null,"usage_limits":{"type":"PER_DAY","param":2}},{"name":"Lash","desc":"The aboleth makes one Tentacle attack.","attacks":[],"action_type":"LEGENDARY_ACTION","order_in_statblock":0,"legendary_action_cost":1,"limited_to_form":null,"usage_limits":null},{"name":"Multiattack","desc":"The aboleth makes two Tentacle attacks and uses either Consume Memories or Dominate Mind if available.","attacks":[],"action_type":"ACTION","order_in_statblock":0,"legendary_action_cost":null,"limited_to_form":null,"usage_limits":null},{"name":"Psychic Drain","desc":"If the aboleth has at least one creature Charmed or Grappled, it uses Consume Memories and regains 5 (1d10) Hit Points.","attacks":[],"action_type":"LEGENDARY_ACTION","order_in_statblock":1,"legendary_action_cost":1,"limited_to_form":null,"usage_limits":null},{"name":"Tentacle","desc":"Melee Attack Roll: +9, reach 15 ft. 12 (2d6 + 5) Bludgeoning damage. If the target is a Large or smaller creature, it has the Grappled condition (escape DC 14) from one of four tentacles.","attacks":[{"name":"Tentacle attack","attack_type":"WEAPON","to_hit_mod":9,"reach":15,"range":null,"long_range":null,"target_creature_only":false,"damage_die_count":2,"damage_die_type":"D6","damage_bonus":5,"damage_type":null,"extra_damage_die_count":null,"extra_damage_die_type":null,"extra_damage_bonus":null,"extra_damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"distance_unit":"feet"}],"action_type":"ACTION","order_in_statblock":1,"legendary_action_cost":1,"limited_to_form":null,"usage_limits":null}],"traits":[{"name":"Amphibious","desc":"The aboleth can breathe air and water."},{"name":"Eldritch Restoration","desc":"If destroyed, the aboleth gains a new body in 5d10 days, reviving with all its Hit Points in the Far Realm or another location chosen by the DM."},{"name":"Legendary Resistance (3/Day, or 4/Day in Lair)","desc":"If the aboleth fails a saving throw, it can choose to succeed instead."},{"name":"Mucus Cloud","desc":"While underwater, the aboleth is surrounded by mucus. Constitution Saving Throw: DC 14, each creature in a 5-foot Emanation originating from the aboleth at the end of the aboleth''s turn. Failure: The target is cursed. Until the curse ends, the target''s skin becomes slimy, the target can breathe air and water, and it can''t regain Hit Points unless it is underwater. While the cursed creature is outside a body of water, the creature takes 6 (1d12) Acid damage at the end of every 10 minutes unless moisture is applied to its skin before those minutes have passed."},{"name":"Probing Telepathy","desc":"If a creature the aboleth can see communicates telepathically with the aboleth, the aboleth learns the creature''s greatest desires."}],"creaturesets":[],"environments":[],"illustration":null,"crossreferences":{"to":[]}}'::jsonb),
