ed_to_form":null,"usage_limits":null},{"name":"Possession","desc":"Charisma Saving Throw: DC 13, one Humanoid the ghost can see within 5 feet. Failure: The target is possessed by the ghost; the ghost disappears, and the target has the Incapacitated condition and loses control of its body. The ghost now controls the body, but the target retains awareness. The ghost can''t be targeted by any attack, spell, or other effect, except ones that specifically target Undead. The ghost''s game statistics are the same, except it uses the possessed target''s Speed, as well as the target''s Strength, Dexterity, and Constitution modifiers. The possession lasts until the body drops to 0 Hit Points or the ghost leaves as a Bonus Action. When the possession ends, the ghost appears in an unoccupied space within 5 feet of the target, and the target is immune to this ghost''s Possession for 24 hours. Success: The target is immune to this ghost''s Possession for 24 hours.","attacks":[],"action_type":"ACTION","order_in_statblock":3,"legendary_action_cost":1,"limited_to_form":null,"usage_limits":{"type":"RECHARGE_ON_ROLL","param":6}},{"name":"Withering Touch","desc":"Melee Attack Roll: +5, reach 5 ft. 19 (3d10 + 3) Necrotic damage.","attacks":[{"name":"Withering Touch attack","attack_type":"WEAPON","to_hit_mod":5,"reach":5,"range":null,"long_range":null,"target_creature_only":false,"damage_die_count":3,"damage_die_type":"D10","damage_bonus":3,"damage_type":null,"extra_damage_die_count":null,"extra_damage_die_type":null,"extra_damage_bonus":null,"extra_damage_type":{"name":"Necrotic","key":"necrotic"},"distance_unit":"feet"}],"action_type":"ACTION","order_in_statblock":1,"legendary_action_cost":1,"limited_to_form":null,"usage_limits":null}],"traits":[{"name":"Ethereal Sight","desc":"The ghost can see 60 feet into the Ethereal Plane when it is on the Material Plane."},{"name":"Incorporeal Movement","desc":"The ghost can move through other creatures and objects as if they were Difficult Terra