  ('srd-2024_vampire', 'Vampire', 'Undead', 'Small', 13, 10000, 16, 195, '{"key":"srd-2024_vampire","name":"Vampire","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"type":{"name":"Undead","key":"undead"},"size":{"name":"Small","key":"small"},"challenge_rating":13,"proficiency_bonus":null,"speed":{"walk":40,"unit":"feet","climb":40},"speed_all":{"unit":"feet","walk":40,"crawl":20,"hover":false,"fly":0,"burrow":0,"climb":40,"swim":20},"category":"Monsters","subcategory":null,"alignment":"lawful evil","languages":{"as_string":"Common plus two other languages","data":[{"name":"Common","key":"common","desc":"Typical speakers are Humans."}]},"armor_class":16,"armor_detail":"natural armor","hit_points":195,"hit_dice":"23d8 + 92","experience_points":10000,"ability_scores":{"strength":18,"dexterity":18,"constitution":18,"intelligence":17,"wisdom":15,"charisma":18},"modifiers":{"strength":4,"dexterity":4,"constitution":4,"intelligence":3,"wisdom":2,"charisma":4},"initiative_bonus":14,"saving_throws":{"strength":4,"dexterity":9,"constitution":9,"intelligence":3,"wisdom":7,"charisma":9},"saving_throws_all":{"strength":4,"dexterity":9,"constitution":9,"intelligence":3,"wisdom":7,"charisma":9},"skill_bonuses":{"perception":7,"stealth":9},"skill_bonuses_all":{"acrobatics":4,"animal_handling":2,"arcana":3,"athletics":4,"deception":4,"history":3,"insight":2,"intimidation":4,"investigation":3,"medicine":2,"nature":3,"perception":7,"performance":4,"persuasion":4,"religion":3,"sleight_of_hand":4,"stealth":9,"survival":2},"passive_perception":17,"resistances_and_immunities":{"damage_immunities_display":"","damage_immunities":[],"damage_resistances_display":"necrotic","damage_resistances":[{"name":"Necrotic","key":"necrotic"}],"damage_vulnerabilities_display":"","damage_vulnerabilities":[],"condition_immunities_display":"","condition_immunities":[]},"normal_sight_range":10560,"darkvision_range":120,"blindsight_range":null,"tremorsense_range":null,"truesight_range":null,"actions":[{"name":"Beguile","desc":"The vampire casts Command, requiring no spell components and using Charisma as the spellcasting ability (spell save DC 17). The vampire can''t take this action again until the start of its next turn.","attacks":[],"action_type":"LEGENDARY_ACTION","order_in_statblock":1,"legendary_action_cost":1,"limited_to_form":null,"usage_limits":null},{"name":"Bite","desc":"Constitution Saving Throw: DC 17, one creature within 5 feet that is willing or that has the Grappled, Incapacitated, or Restrained condition. Failure: 6 (1d4 + 4) Piercing damage plus 13 (3d8) Necrotic damage. The target''s Hit Point maximum decreases by an amount equal to the Necrotic damage taken, and the vampire regains Hit Points equal to that amount. A Humanoid reduced to 0 Hit Points by this damage and then buried rises the following sunset as a Vampire Spawn under the vampire''s control.","attacks":[],"action_type":"ACTION","order_in_statblock":2,"legendary_action_cost":null,"limited_to_form":"Bat or Vampire Form Only","usage_limits":null},{"name":"Deathless Strike","desc":"The vampire moves up to half its Speed, and it makes one Grave Strike attack.","attacks":[],"action_type":"LEGENDARY_ACTION","order_in_statblock":0,"legendary_action_cost":1,"limited_to_form":null,"usage_limits":null},{"name":"Grave Strike","desc":"Melee Attack Roll: +9, reach 5 ft. 8 (1d8 + 4) Bludgeoning damage plus 7 (2d6) Necrotic damage. If the target is a Large or smaller creature, it has the Grappled condition (escape DC 14) from one of two hands.","attacks":[{"name":"Grave Strike attack","attack_type":"WEAPON","to_hit_mod":9,"reach":5,"range":null,"long_range":null,"target_creature_only":false,"damage_die_count":1,"damage_die_type":"D8","damage_bonus":4,"damage_type":null,"extra_damage_die_count":null,"extra_damage_die_type":null,"extra_damage_bonus":null,"extra_damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"distance_unit":"feet"}],"action_type":"ACTION","order_in_statblock":1,"legendary_action_cost":null,"limited_to_form":"Vampire Form Only","usage_limits":null},{"name":"Multiattack","desc":"The vampire makes two Grave Strike attacks and uses Bite.","attacks":[],"action_type":"ACTION","order_in_statblock":0,"legendary_action_cost":null,"limited_to_form":"Vampire Form Only","usage_limits":null},{"name":"Shape-Shift","desc":"If the vampire isn''t in sunlight or running water, it shape-shifts into a Tiny bat (Speed 5 ft., Fly Speed 30 ft.) or a Medium cloud of mist (Speed 5 ft., Fly Speed 20 ft. [hover]), or it returns to its vampire form. Anything it is wearing transforms with it. While in bat form, the vampire can''t speak. Its game statistics, other than its size and Speed, are unchanged. While in mist form, the vampire can''t take any actions, speak, or manipulate objects. It is weightless and can enter an enemy''s space and stop there. If air can pass through a space, the mist can do so, but it can''t pass through liquid. It has Resistance to all damage, except the damage it takes from sunlight.","attacks":[],"action_type":"BONUS_ACTION","order_in_statblock":0,"legendary_action_cost":null,"limited_to_form":null,"usage_limits":null},{"name":"Charm","desc":"The vampire casts Charm Person, requiring no spell components and using Charisma as the spellcasting ability (spell save DC 17), and the duration is 24 hours. The Charmed target is a willing recipient of the vampire''s Bite, the damage of which doesn''t end the spell. When the spell ends, the target is unaware it was Charmed by the vampire.","attacks":[],"action_type":"BONUS_ACTION","order_in_statblock":1,"legendary_action_cost":null,"limited_to_form":null,"usage_limits":{"type":"RECHARGE","param":5}}],"traits":[{"name":"Legendary Resistance (3/Day, or 4/Day in Lair)","desc":"If the vampire fails a saving throw, it can choose to succeed instead."},{"name":"Misty Escape","desc":"If the vampire drops to 0 Hit Points outside its resting place, the vampire uses Shape-Shift to become mist (no action required). If it can''t use Shape-Shift, it is destroyed. While it has 0 Hit Points in mist form, it can''t return to its vampire form, and it must reach its resting place within 2 hours or be destroyed. Once in its resting place, it returns to its vampire form and has the Paralyzed condition until it regains any Hit Points, and it regains 1 Hit Point after spending 1 hour there."},{"name":"Spider Climb","desc":"The vampire can climb difficult surfaces, including along ceilings, without needing to make an ability check."},{"name":"Vampire Weakness","desc":"The vampire has these weaknesses:\n\n- **Forbiddance:** The vampire can''t enter a residence without an invitation from an occupant.\n- **Running Water:** The vampire takes 20 Acid damage if it ends its turn in running water.\n- **Stake to the Heart:** If a weapon that deals Piercing damage is driven into the vampire''s heart while the vampire has the Incapacitated condition in its resting place, the vampire has the Paralyzed condition until the weapon is removed.\n- **Sunlight:** The vampire takes 20 Radiant damage if it starts its turn in sunlight. While in sunlight, it has Disadvantage on attack rolls and ability checks."}],"creaturesets":[],"environments":[],"illustration":null,"crossreferences":{"to":[]}}'::jsonb),
