values
  ('srd-2024_acid-arrow', 'Acid Arrow', 'Evocation', 2, false, false, '{"key":"srd-2024_acid-arrow","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_3","damage_roll":"5d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":"6d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"7d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"8d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"9d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"10d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"11d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Acid Arrow","desc":"A shimmering green arrow streaks toward a target within range and bursts in a spray of acid. Make a ranged spell attack against the target. On a hit, the target takes 4d4 Acid damage and 2d4 Acid damage at the end of its next turn. On a miss, the arrow splashes the target with acid for half as much of the initial damage only.","level":2,"higher_level":"The damage (both initial and later) increases by 1d4 for each spell slot level above 2.","target_type":"creature","range_text":"90 feet","range":90,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"powdered rhubarb leaf","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"4d4","damage_types":["acid"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_acid-splash', 'Acid Splash', 'Evocation', 0, false, false, '{"key":"srd-2024_acid-splash","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"player_level_5","damage_roll":"2d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"player_level_11","damage_roll":"3d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"player_level_17","damage_roll":"4d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Acid Splash","desc":"You create an acidic bubble at a point within range, where it explodes in a 5-foot-radius Sphere. Each creature in that Sphere must succeed on a Dexterity saving throw or take 1d6 Acid damage.","level":0,"higher_level":"The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"1d6","damage_types":["acid"],"duration":"instantaneous","shape_type":"sphere","shape_size":5,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_aid', 'Aid', 'Abjuration', 2, false, false, '{"key":"srd-2024_aid","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_3","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Each target''s Hit Points increase by 5."},{"type":"slot_level_4","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Each target''s Hit Points increase by 10."},{"type":"slot_level_5","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Each target''s Hit Points increase by 15."},{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Each target''s Hit Points increase by 20."},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Each target''s Hit Points increase by 25."},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Each target''s Hit Points increase by 30."},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Each target''s Hit Points increase by 35."}],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Paladin","key":"srd-2024_paladin"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Aid","desc":"Choose up to three creatures within range. Each target''s Hit Point maximum and current Hit Points increase by 5 for the duration.","level":2,"higher_level":"Each target''s Hit Points increase by 5 for each spell slot level above 2.","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a strip of white cloth","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"8 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_alarm', 'Alarm', 'Abjuration', 1, false, true, '{"key":"srd-2024_alarm","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Ranger","key":"srd-2024_ranger"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Alarm","desc":"You set an alarm against intrusion. Choose a door, a window, or an area within range that is no larger than a 20-foot Cube. Until the spell ends, an alarm alerts you whenever a creature touches or enters the warded area. When you cast the spell, you can designate creatures that won''t set off the alarm. You also choose whether the alarm is audible or mental:\n\n**Audible Alarm.** The alarm produces the sound of a handbell for 10 seconds within 60 feet of the warded area.\n\n**Mental Alarm.** You are alerted by a mental ping if you are within 1 mile of the warded area. This ping awakens you if you''re asleep.","level":1,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":true,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a bell and silver wire","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"8 hours","shape_type":"cube","shape_size":20,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_alter-self', 'Alter Self', 'Transmutation', 2, true, false, '{"key":"srd-2024_alter-self","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Alter Self","desc":"You alter your physical form. Choose one of the following options. Its effects last for the duration, during which you can take a Magic action to replace the option you chose with a different one. _Aquatic Adaptation._ You sprout gills and grow webs between your fingers. You can breathe underwater and gain a Swim Speed equal to your Speed. _Change Appearance._ You alter your appearance. You decide what you look like, including your height, weight, facial features, sound of your voice, hair length, coloration, and other distinguishing characteristics. You can make yourself appear as a member of another species, though none of your statistics change. You can''t appear as a creature of a different size, and your basic shape stays the same; if you''re bipedal, you can''t use this spell to become quadrupedal, for instance. For the duration, you can take a Magic action to change your appearance in this way again. _Natural Weapons._ You grow claws (Slashing), fangs (Piercing), horns (Piercing), or hooves (Bludgeoning). When you use your Unarmed Strike to deal damage with that new growth, it deals 1d6 damage of the type in parentheses instead of dealing the normal damage for your Unarmed Strike, and you use your spellcasting ability modifier for the attack and damage rolls rather than using Strength.","level":2,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"1d6","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_animal-friendship', 'Animal Friendship', 'Enchantment', 1, false, false, '{"key":"srd-2024_animal-friendship","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":null,"target_count":2,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_3","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":null,"target_count":4,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":null,"target_count":5,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":6,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":7,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":8,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":9,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Animal Friendship","desc":"Target a Beast that you can see within range. The target must succeed on a Wisdom saving throw or have the Charmed condition for the duration. If you or one of your allies deals damage to the target, the spells ends.","level":1,"higher_level":"You can target one additional Beast for each spell slot level above 1.","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a morsel of food","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"24 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_animal-messenger', 'Animal Messenger', 'Enchantment', 2, false, true, '{"key":"srd-2024_animal-messenger","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_3","damage_roll":null,"target_count":null,"duration":"72 hours","range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":null,"target_count":null,"duration":"120 hours","range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":null,"target_count":null,"duration":"168 hours","range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":"216 hours","range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":"264 hours","range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":"312 hours","range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":"360 hours","range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Animal Messenger","desc":"A Tiny Beast of your choice that you can see within range must succeed on a Charisma saving throw, or it attempts to deliver a message for you (if the target''s Challenge Rating isn''t 0, it automatically succeeds). You specify a location you have visited and a recipient who matches a general description, such as \"a person dressed in the uniform of the town guard\" or \"a red-haired dwarf wearing a pointed hat.\" You also communicate a message of up to twenty-five words. The Beast travels for the duration toward the specified location, covering about 25 miles per 24 hours or 50 miles if the Beast can fly. When the Beast arrives, it delivers your message to the creature that you described, mimicking your communication. If the Beast doesn''t reach its destination before the spell ends, the message is lost, and the Beast returns to where you cast the spell.","level":2,"higher_level":"The spell''s duration increases by 48 hours for each spell slot level above 2.","target_type":"creature","range_text":"30 feet","range":30,"ritual":true,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a morsel of food","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"charisma","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"24 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_animal-shapes', 'Animal Shapes', 'Transmutation', 8, false, false, '{"key":"srd-2024_animal-shapes","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Animal Shapes","desc":"Choose any number of willing creatures that you can see within range. Each target shape-shifts into a Large or smaller Beast of your choice that has a Challenge Rating of 4 or lower. You can choose a different form for each target. On later turns, you can take a Magic action to transform the targets again. A target''s game statistics are replaced by the chosen Beast''s statistics, but the target retains its creature type; Hit Points; Hit Point Dice; alignment; ability to communicate; and Intelligence, Wisdom, and Charisma scores. The target''s actions are limited by the Beast form''s anatomy, and it can''t cast spells. The target''s equipment melds into the new form, and the target can''t use any of that equipment while in that form. The target gains a number of Temporary Hit Points equal to the Hit Points of the first form into which it shape-shifts. These Temporary Hit Points vanish if any remain when the spell ends. The transformation lasts for the duration or until the target ends it as a Bonus Action.","level":8,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"24 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_animate-dead', 'Animate Dead', 'Necromancy', 3, false, false, '{"key":"srd-2024_animate-dead","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_4","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"You animate or reassert control over 2 additional Undead creatures."},{"type":"slot_level_5","damage_roll":null,"target_count":5,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"You animate or reassert control over 4 additional Undead creatures."},{"type":"slot_level_6","damage_roll":null,"target_count":7,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"You animate or reassert control over 6 additional Undead creatures."},{"type":"slot_level_7","damage_roll":null,"target_count":9,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"You animate or reassert control over 8 additional Undead creatures."},{"type":"slot_level_8","damage_roll":null,"target_count":11,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"You animate or reassert control over 10 additional Undead creatures."},{"type":"slot_level_9","damage_roll":null,"target_count":13,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"You animate or reassert control over 12 additional Undead creatures."}],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Animate Dead","desc":"Choose a pile of bones or a corpse of a Medium or Small Humanoid within range. The target becomes an Undead creature: a Skeleton if you chose bones or a Zombie if you chose a corpse (see \"Monsters\" for the stat blocks). On each of your turns, you can take a Bonus Action to mentally command any creature you made with this spell if the creature is within 60 feet of you (if you control multiple creatures, you can command any of them at the same time, issuing the same command to each one). You decide what action the creature will take and where it will move on its next turn, or you can issue a general command, such as to guard a chamber or corridor. If you issue no commands, the creature takes the Dodge action and moves only to avoid harm. Once given an order, the creature continues to follow it until its task is complete. The creature is under your control for 24 hours, after which it stops obeying any command you''ve given it. To maintain control of the creature for another 24 hours, you must cast this spell on the creature again before the current 24-hour period ends. This use of the spell reasserts your control over up to four creatures you have animated with this spell rather than animating a new creature.","level":3,"higher_level":"You animate or reassert control over two additional Undead creatures for each spell slot level above 3. Each of the creatures must come from a different corpse or pile of bones.","target_type":"creature","range_text":"10 feet","range":10,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a drop of blood, a piece of flesh, and a pinch of bone dust","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_animate-objects', 'Animate Objects', 'Transmutation', 5, true, false, '{"key":"srd-2024_animate-objects","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"damage increases by 2d4 (Medium or smaller), 2d6 (Large), or 2d12 (Huge)"},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"damage increases by 3d4 (Medium or smaller), 3d6 (Large), or 3d12 (Huge)"},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"damage increases by 4d4 (Medium or smaller), 4d6 (Large), or 4d12 (Huge)"},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"damage increases by 5d4 (Medium or smaller), 5d6 (Large), or 5d12 (Huge)"}],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Animate Objects","desc":"Objects animate at your command. Choose a number of nonmagical objects within range that aren''t being worn or carried, aren''t fixed to a surface, and aren''t Gargantuan. The maximum number of objects is equal to your spellcasting ability modifier; for this number, a Medium or smaller target counts as one object, a Large target counts as two, and a Huge target counts as three. Each target animates, sprouts legs, and becomes a Construct that uses the Animated Object stat block; this creature is under your control until the spell ends or until it is reduced to 0 Hit Points. Each creature you make with this spell is an ally to you and your allies. In combat, it shares your Initiative count and takes its turn immediately after yours. Until the spell ends, you can take a Bonus Action to mentally command any creature you made with this spell if the creature is within 500 feet of you (if you control multiple creatures, you can command any of them at the same time, issuing the same command to each one). If you issue no commands, the creature takes the Dodge action and moves only to avoid harm. When the creature drops to 0 Hit Points, it reverts to its object form, and any remaining damage carries over to that form.","level":5,"higher_level":"The creature''s Slam damage increases by 1d4 (Medium or smaller), 1d6 (Large), or 1d12 (Huge) for each spell slot level above 5.","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_antilife-shell', 'Antilife Shell', 'Abjuration', 5, true, false, '{"key":"srd-2024_antilife-shell","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Antilife Shell","desc":"An aura extends from you in a 10-foot Emanation for the duration. The aura prevents creatures other than Constructs and Undead from passing or reaching through it. An affected creature can cast spells or make attacks with Ranged or Reach weapons through the barrier. If you move so that an affected creature is forced to pass through the barrier, the spell ends.","level":5,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_antimagic-field', 'Antimagic Field', 'Abjuration', 8, true, false, '{"key":"srd-2024_antimagic-field","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Antimagic Field","desc":"An aura of antimagic surrounds you in 10-foot Emanation. No one can cast spells, take Magic actions, or create other magical effects inside the aura, and those things can''t target or otherwise affect anything inside it. Magical properties of magic items don''t work inside the aura or on anything inside it. Areas of effect created by spells or other magic can''t extend into the aura, and no one can teleport into or out of it or use planar travel there. Portals close temporarily while in the aura. Ongoing spells, except those cast by an Artifact or a deity, are suppressed in the area. While an effect is suppressed, it doesn''t function, but the time it spends suppressed counts against its duration.","level":8,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"iron filings","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_antipathysympathy', 'Antipathy/Sympathy', 'Enchantment', 8, false, false, '{"key":"srd-2024_antipathysympathy","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Antipathy/Sympathy","desc":"As you cast the spell, choose whether it creates antipathy or sympathy, and target one creature or object that is Huge or smaller. Then specify a kind of creature, such as red dragons, goblins, or vampires. A creature of the chosen kind makes a Wisdom saving throw when it comes within 120 feet of the target. Your choice of antipathy or sympathy determines what happens to a creature when it fails that save:\n\n**Antipathy**. The creature has the Frightened condition. The Frightened creature must use its movement on its turns to get as far away as possible from the target, moving by the safest route.\n\n**Sympathy**. The creature has the Charmed condition. The Charmed creature must use its movement on its turns to get as close as possible to the target, moving by the safest route. If the creature is within 5 feet of the target, the creature can''t willingly move away. If the target damages the Charmed creature, that creature can make a Wisdom saving throw to end the effect, as described below.\n\n**Ending the Effect**. If the Frightened or Charmed creature ends its turn more than 120 feet away from the target, the creature makes a Wisdom saving throw. On a successful save, the creature is no longer affected by the target. A creature that successfully saves against this effect is immune to it for 1 minute, after which it can be affected again.","level":8,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"1hour","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a mix of vinegar and honey","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 days","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_arcane-eye', 'Arcane Eye', 'Divination', 4, true, false, '{"key":"srd-2024_arcane-eye","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Arcane Eye","desc":"You create an Invisible, invulnerable eye within range that hovers for the duration. You mentally receive visual information from the eye, which can see in every direction. It also has Darkvision with a range of 30 feet. As a Bonus Action, you can move the eye up to 30 feet in any direction. A solid barrier blocks the eye''s movement, but the eye can pass through an opening as small as 1 inch in diameter.","level":4,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a bit of bat fur","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_arcane-hand', 'Arcane Hand', 'Evocation', 5, true, false, '{"key":"srd-2024_arcane-hand","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Clenched Fist deals 6d8 Force damage. Grasping Hand deals 4d6 Bludgeoning damage."},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Clenched Fist deals 8d8 Force damage. Grasping Hand deals 6d6 Bludgeoning damage."},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Clenched Fist deals 10d8 Force damage. Grasping Hand deals 8d6 Bludgeoning damage."},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Clenched Fist deals 12d8 Force damage. Grasping Hand deals 10d6 Bludgeoning damage."}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Arcane Hand","desc":"You create a Large hand of shimmering magical energy in an unoccupied space that you can see within range. The hand lasts for the duration, and it moves at your command, mimicking the movements of your own hand. The hand is an object that has AC 20 and Hit Points equal to your Hit Point maximum. If it drops to 0 Hit Points, the spell ends. The hand doesn''t occupy its space. When you cast the spell and as a Bonus Action on your later turns, you can move the hand up to 60 feet and then cause one of the following effects:\n\n**Clenched Fist.** The hand strikes a target within 5 feet of it. Make a melee spell attack. On a hit, the target takes 5d8 Force damage.\n\n**Forceful Hand.** The hand attempts to push a Huge or smaller creature within 5 feet of it. The target must succeed on a Strength saving throw, or the hand pushes the target up to 5 feet plus a number of feet equal to five times your spellcasting ability modifier. The hand moves with the target, remaining within 5 feet of it.\n\n**Grasping Hand.** The hand attempts to grapple a Huge or smaller creature within 5 feet of it. The target must succeed on a Dexterity saving throw, or the target has the Grappled condition, with an escape DC equal to your spell save DC. While the hand grapples the target, you can take a Bonus Action to cause the hand to crush it, dealing Bludgeoning damage to the target equal to 4d6 plus your spellcasting ability modifier.\n\n**Interposing Hand.** The hand grants you Half Cover against attacks and other effects that originate from its space or that pass through it. In addition, its space counts as Difficult Terrain for your enemies.","level":5,"higher_level":"The damage of the Clenched Fist increases by 2d8 and the damage of the Grasping Hand increases by 2d6 for each spell slot level above 5.","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"an eggshell and a glove","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_arcane-lock', 'Arcane Lock', 'Abjuration', 2, false, false, '{"key":"srd-2024_arcane-lock","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Arcane Lock","desc":"You touch a closed door, window, gate, container, or hatch and magically lock it for the duration. This lock can''t be unlocked by any nonmagical means. You and any creatures you designate when you cast the spell can open and close the object despite the lock. You can also set a password that, when spoken within 5 feet of the object, unlocks it for 1 minute.","level":2,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"gold dust worth 25+ GP, which the spell consumes","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"until dispelled","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_arcane-sword', 'Arcane Sword', 'Evocation', 7, true, false, '{"key":"srd-2024_arcane-sword","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Arcane Sword","desc":"You create a spectral sword that hovers within range. It lasts for the duration. When the sword appears, you make a melee spell attack against a target within 5 feet of the sword. On a hit, the target takes Force damage equal to 4d12 plus your spellcasting ability modifier. On your later turns, you can take a Bonus Action to move the sword up to 30 feet to a spot you can see and repeat the attack against the same target or a different one.","level":7,"higher_level":"","target_type":"creature","range_text":"90 feet","range":90,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a miniature sword worth 250+ GP","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"4d12","damage_types":["force"],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_arcanists-magic-aura', 'Arcanist''s Magic Aura', 'Illusion', 2, false, false, '{"key":"srd-2024_arcanists-magic-aura","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Illusion","key":"illusion"},"classes":[{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Arcanist''s Magic Aura","desc":"With a touch, you place an illusion on a willing creature or an object that isn''t being worn or carried. A creature gains the Mask effect below, and an object gains the False Aura effect below. The effect lasts for the duration. If you cast the spell on the same target every day for 30 days, the illusion lasts until dispelled.\n\n**Mask (Creature).** Choose a creature type other than the target''s actual type. Spells and other magical effects treat the target as if it were a creature of the chosen type.\n\n**False Aura (Object).** You change the way the target appears to spells and magical effects that detect magical auras, such as Detect Magic. You can make a nonmagical object appear magical, make a magic item appear nonmagical, or change the object''s aura so that it appears to belong to a school of magic you choose.","level":2,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a small square of silk","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"24 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_astral-projection', 'Astral Projection', 'Necromancy', 9, false, false, '{"key":"srd-2024_astral-projection","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Astral Projection","desc":"You and up to eight willing creatures within range project your astral bodies into the Astral Plane (the spell ends instantly if you are already on that plane). Each target''s body is left behind in a state of suspended animation; it has the Unconscious condition, doesn''t need food or air, and doesn''t age. A target''s astral form resembles its body in almost every way, replicating its game statistics and possessions. The principal difference is the addition of a silvery cord that trails from between the shoulder blades of the astral form. The cord fades from view after 1 foot. If the cord is cut—which happens only when an effect states that it does so—the target''s body and astral form both die. A target''s astral form can travel through the Astral Plane. The moment an astral form leaves that plane, the target''s body and possessions travel along the silver cord, causing the target to re-enter its body on the new plane. Any damage or other effects that apply to an astral form have no effect on the target''s body and vice versa. If a target''s body or astral form drops to 0 Hit Points, the spell ends for that target. The spell ends for all the targets if you take a Magic action to dismiss it. When the spell ends for a target who isn''t dead, the target reappears in its body and exits the state of suspended animation.","level":9,"higher_level":"","target_type":"creature","range_text":"10 feet","range":10,"ritual":false,"casting_time":"1hour","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"for each of the spell''s targets, one jacinth worth 1,000+ GP and one silver bar worth 100+ GP, all of which the spell consumes","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"until dispelled","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_augury', 'Augury', 'Divination', 2, false, true, '{"key":"srd-2024_augury","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Augury","desc":"You receive an omen from an otherworldly entity about the results of a course of action that you plan to take within the next 30 minutes. The GM chooses the omen from the Omens table. Table: Omens | Omen | For Results That Will Be … | |--------------|----------------------------| | Weal | Good | | Woe | Bad | | Weal and woe | Good and bad | | Indifference | Neither good nor bad | The spell doesn''t account for circumstances, such as other spells, that might change the results. If you cast the spell more than once before finishing a Long Rest, there is a cumulative 25 percent chance for each casting after the first that you get no answer.","level":2,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":true,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"specially marked sticks, bones, cards, or other divinatory tokens worth 25+ GP","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_aura-of-life', 'Aura of Life', 'Abjuration', 4, true, false, '{"key":"srd-2024_aura-of-life","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Paladin","key":"srd-2024_paladin"}],"range_unit":"feet","shape_size_unit":"feet","name":"Aura of Life","desc":"An aura radiates from you in a 30-foot Emanation for the duration. While in the aura, you and your allies have Resistance to Necrotic damage, and your Hit Point maximums can''t be reduced. If an ally with 0 Hit Points starts its turn in the aura, that ally regains 1 Hit Point.","level":4,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":["necrotic"],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_awaken', 'Awaken', 'Transmutation', 5, false, false, '{"key":"srd-2024_awaken","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Awaken","desc":"You spend the casting time tracing magical pathways within a precious gemstone, and then touch the target. The target must be either a Beast or Plant creature with an Intelligence of 3 or less or a natural plant that isn''t a creature. The target gains an Intelligence of 10 and the ability to speak one language you know. If the target is a natural plant, it becomes a Plant creature and gains the ability to move its limbs, roots, vines, creepers, and so forth, and it gains senses similar to a human''s. The GM chooses statistics appropriate for the awakened Plant, such as the statistics for the Awakened Shrub or Awakened Tree in \"Monsters.\" The awakened target has the Charmed condition for 30 days or until you or your allies deal damage to it. When that condition ends, the awakened creature chooses its attitude toward you.","level":5,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"1hour","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"an agate worth 1,000+ GP, which the spell consumes","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_bane', 'Bane', 'Enchantment', 1, true, false, '{"key":"srd-2024_bane","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":null,"target_count":2,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_3","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":null,"target_count":4,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":null,"target_count":5,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":6,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":7,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":8,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":9,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Warlock","key":"srd-2024_warlock"}],"range_unit":"feet","shape_size_unit":"feet","name":"Bane","desc":"Up to three creatures of your choice that you can see within range must each make a Charisma saving throw. Whenever a target that fails this save makes an attack roll or a saving throw before the spell ends, the target must subtract 1d4 from the attack roll or save.","level":1,"higher_level":"You can target one additional creature for each spell slot level above 1.","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a drop of blood","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"charisma","attack_roll":true,"damage_roll":"1d4","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_banishment', 'Banishment', 'Abjuration', 4, true, false, '{"key":"srd-2024_banishment","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_5","damage_roll":null,"target_count":2,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":4,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":5,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":6,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Paladin","key":"srd-2024_paladin"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Banishment","desc":"One creature that you can see within range must succeed on a Charisma saving throw or be transported to a harmless demiplane for the duration. While there, the target has the Incapacitated condition. When the spell ends, the target reappears in the space it left or in the nearest unoccupied space if that space is occupied. If the target is an Aberration, a Celestial, an Elemental, a Fey, or a Fiend, the target doesn''t return if the spell lasts for 1 minute. The target is instead transported to a random location on a plane (GM''s choice) associated with its creature type.","level":4,"higher_level":"You can target one additional creature for each spell slot level above 4.","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a pentacle","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"charisma","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_barkskin', 'Barkskin', 'Transmutation', 2, false, false, '{"key":"srd-2024_barkskin","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Barkskin","desc":"You touch a willing creature. Until the spell ends, the target''s skin assumes a bark-like appearance, and the target has an Armor Class of 17 if its AC is lower than that.","level":2,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"bonus-action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a handful of bark","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_beacon-of-hope', 'Beacon of Hope', 'Abjuration', 3, true, false, '{"key":"srd-2024_beacon-of-hope","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Beacon of Hope","desc":"Choose any number of creatures within range. For the duration, each target has Advantage on Wisdom saving throws and Death Saving Throws and regains the maximum number of Hit Points possible from any healing.","level":3,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_befuddlement', 'Befuddlement', 'Enchantment', 8, false, false, '{"key":"srd-2024_befuddlement","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Befuddlement","desc":"You blast the mind of a creature that you can see within range. The target makes an Intelligence saving throw. On a failed save, the target takes 10d12 Psychic damage and can''t cast spells or take the Magic action. At the end of every 30 days, the target repeats the save, ending the effect on a success. The effect can also be ended by the Greater Restoration, Heal, or Wish spell. On a successful save, the target takes half as much damage only.","level":8,"higher_level":"","target_type":"creature","range_text":"150 feet","range":150,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a key ring with no keys","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"intelligence","attack_roll":false,"damage_roll":"10d12","damage_types":["psychic"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_bestow-curse', 'Bestow Curse', 'Necromancy', 3, true, false, '{"key":"srd-2024_bestow-curse","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_5","damage_roll":null,"target_count":null,"duration":"8 hours","range":null,"concentration":false,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":"8 hours","range":null,"concentration":false,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":"24 hours","range":null,"concentration":false,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":"24 hours","range":null,"concentration":false,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":"until dispelled","range":null,"concentration":false,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":null,"target_count":null,"duration":"10 minutes","range":null,"concentration":true,"shape_size":null,"desc":"You can maintain Concentration for up to 10 minutes."}],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Bestow Curse","desc":"You touch a creature, which must succeed on a Wisdom saving throw or become cursed for the duration. Until the curse ends, the target suffers one of the following effects of your choice: - Choose one ability. The target has Disadvantage on ability checks and saving throws made with that ability. - The target has Disadvantage on attack rolls against you. - In combat, the target must succeed on a Wisdom saving throw at the start of each of its turns or be forced to take the Dodge action on that turn. - If you deal damage to the target with an attack roll or a spell, the target takes an extra 1d8 Necrotic damage.","level":3,"higher_level":"If you cast this spell using a level 4 spell slot, you can maintain Concentration on it for up to 10 minutes. If you use a level 5+ spell slot, the spell doesn''t require Concentration, and the duration becomes 8 hours (level 5–6 slot) or 24 hours (level 7–8 slot). If you use a level 9 spell slot, the spell lasts until dispelled.","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":true,"damage_roll":"1d8","damage_types":["necrotic"],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_black-tentacles', 'Black Tentacles', 'Conjuration', 4, true, false, '{"key":"srd-2024_black-tentacles","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Black Tentacles","desc":"Squirming, ebony tentacles fill a 20-foot square on ground that you can see within range. For the duration, these tentacles turn the ground in that area into Difficult Terrain. Each creature in that area makes a Strength saving throw. On a failed save, it takes 3d6 Bludgeoning damage, and it has the Restrained condition until the spell ends. A creature also makes that save if it enters the area or ends it turn there. A creature makes that save only once per turn. A Restrained creature can take an action to make a Strength (Athletics) check against your spell save DC, ending the condition on itself on a success.","level":4,"higher_level":"","target_type":"creature","range_text":"90 feet","range":90,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a tentacle","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"strength","attack_roll":false,"damage_roll":"3d6","damage_types":["bludgeoning"],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_blade-barrier', 'Blade Barrier', 'Evocation', 6, true, false, '{"key":"srd-2024_blade-barrier","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Blade Barrier","desc":"You create a wall of whirling blades made of magical energy. The wall appears within range and lasts for the duration. You make a straight wall up to 100 feet long, 20 feet high, and 5 feet thick, or a ringed wall up to 60 feet in diameter, 20 feet high, and 5 feet thick. The wall provides Three-Quarters Cover, and its space is Difficult Terrain. Any creature in the wall''s space makes a Dexterity saving throw, taking 6d10 Force damage on a failed save or half as much damage on a successful one. A creature also makes that save if it enters the wall''s space or ends it turn there. A creature makes that save only once per turn.","level":6,"higher_level":"","target_type":"creature","range_text":"90 feet","range":90,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"6d10","damage_types":["force"],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
