ture for each spell slot level above 1.","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a Holy Symbol worth 5+ GP","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"1d4","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_blight', 'Blight', 'Necromancy', 4, false, false, '{"key":"srd-2024_blight","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_5","damage_roll":"9d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"10d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"11d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"12d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"13d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Blight","desc":"A creature that you can see within range makes a Constitution saving throw, taking 8d8 Necrotic damage on a failed save or half as much damage on a successful one. A Plant creature automatically fails the save. Alternatively, target a nonmagical plant that isn''t a creature, such as a tree or shrub. It doesn''t make a save; it simply withers and dies.","level":4,"higher_level":"The damage increases by 1d8 for each spell slot level above 4.","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action",