  ('srd-2024_blindnessdeafness', 'Blindness/Deafness', 'Transmutation', 2, false, false, '{"key":"srd-2024_blindnessdeafness","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_3","damage_roll":null,"target_count":2,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":null,"target_count":4,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":5,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":6,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":7,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":8,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Blindness/Deafness","desc":"One creature that you can see within range must succeed on a Constitution saving throw, or it has the Blinded or Deafened condition (your choice) for the duration. At the end of each of its turns, the target repeats the save, ending the spell on itself on a success.","level":2,"higher_level":"You can target one additional creature for each spell slot level above 2.","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_blink', 'Blink', 'Transmutation', 3, false, false, '{"key":"srd-2024_blink","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Blink","desc":"Roll 1d6 at the end of each of your turns for the duration. On a roll of 4–6, you vanish from your current plane of existence and appear in the Ethereal Plane (the spell ends instantly if you are already on that plane). While on the Ethereal Plane, you can perceive the plane you left, which is cast in shades of gray, but you can''t see anything there more than 60 feet away. You can affect and be affected only by other creatures on the Ethereal Plane, and creatures on the other plane can''t perceive you unless they have a special ability that lets them perceive things on the Ethereal Plane. You return to the other plane at the start of your next turn and when the spell ends if you are on the Ethereal Plane. You return to an unoccupied space of your choice that you can see within 10 feet of the space you left. If no unoccupied space is available within that range, you appear in the nearest unoccupied space.","level":3,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"1d6","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_blur', 'Blur', 'Illusion', 2, true, false, '{"key":"srd-2024_blur","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Illusion","key":"illusion"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Blur","desc":"Your body becomes blurred. For the duration, any creature has Disadvantage on attack rolls against you. An attacker is immune to this effect if it perceives you with Blindsight or Truesight.","level":2,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_burning-hands', 'Burning Hands', 'Evocation', 1, false, false, '{"key":"srd-2024_burning-hands","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":"4d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_3","damage_roll":"5d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":"6d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"7d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"8d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"9d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"10d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"11d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Burning Hands","desc":"A thin sheet of flames shoots forth from you. Each creature in a 15-foot Cone makes a Dexterity saving throw, taking 3d6 Fire damage on a failed save or half as much damage on a successful one. Flammable objects in the Cone that aren''t being worn or carried start burning.","level":1,"higher_level":"The damage increases by 1d6 for each spell slot level above 1.","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"3d6","damage_types":["fire"],"duration":"instantaneous","shape_type":"cone","shape_size":15,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_call-lightning', 'Call Lightning', 'Conjuration', 3, true, false, '{"key":"srd-2024_call-lightning","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_4","damage_roll":"4d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"5d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"6d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"7d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"8d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"9d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Call Lightning","desc":"A storm cloud appears at a point within range that you can see above yourself. It takes the shape of a Cylinder that is 10 feet tall with a 60-foot radius. When you cast the spell, choose a point you can see under the cloud. A lightning bolt shoots from the cloud to that point. Each creature within 5 feet of that point makes a Dexterity saving throw, taking 3d10 Lightning damage on a failed save or half as much damage on a successful one. Until the spell ends, you can take a Magic action to call down lightning in that way again, targeting the same point or a different one. If you''re outdoors in a storm when you cast this spell, the spell gives you control over that storm instead of creating a new one. Under such conditions, the spell''s damage increases by 1d10.","level":3,"higher_level":"The damage increases by 1d10 for each spell slot level above 3.","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"3d10","damage_types":["lightning"],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_calm-emotions', 'Calm Emotions', 'Enchantment', 2, true, false, '{"key":"srd-2024_calm-emotions","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Calm Emotions","desc":"Each Humanoid in a 20-foot-radius Sphere centered on a point you choose within range must succeed on a Charisma saving throw or be affected by one of the following effects (choose for each creature): - The creature has Immunity to the Charmed and Frightened conditions until the spell ends. If the creature was already Charmed or Frightened, those conditions are suppressed for the duration. - The creature becomes Indifferent about creatures of your choice that it''s Hostile toward. This indifference ends if the target takes damage or witnesses its allies taking damage. When the spell ends, the creature''s attitude returns to normal.","level":2,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"charisma","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":"sphere","shape_size":20,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_chain-lightning', 'Chain Lightning', 'Evocation', 6, false, false, '{"key":"srd-2024_chain-lightning","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Chain Lightning","desc":"You launch a lightning bolt toward a target you can see within range. Three bolts then leap from that target to as many as three other targets of your choice, each of which must be within 30 feet of the first target. A target can be a creature or an object and can be targeted by only one of the bolts. Each target makes a Dexterity saving throw, taking 10d8 Lightning damage on a failed save or half as much damage on a successful one.","level":6,"higher_level":"","target_type":"creature","range_text":"150 feet","range":150,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"three silver pins","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"10d8","damage_types":["lightning"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_charm-monster', 'Charm Monster', 'Enchantment', 4, false, false, '{"key":"srd-2024_charm-monster","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_5","damage_roll":null,"target_count":2,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":4,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":5,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":6,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Charm Monster","desc":"One creature you can see within range makes a Wisdom saving throw. It does so with Advantage if you or your allies are fighting it. On a failed save, the target has the Charmed condition until the spell ends or until you or your allies damage it. The Charmed creature is Friendly to you. When the spell ends, the target knows it was Charmed by you.","level":4,"higher_level":"You can target one additional creature for each spell slot level above 4.","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_charm-person', 'Charm Person', 'Enchantment', 1, false, false, '{"key":"srd-2024_charm-person","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":null,"target_count":2,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_3","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":null,"target_count":4,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":null,"target_count":5,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":6,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":7,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":8,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":9,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Charm Person","desc":"One Humanoid you can see within range makes a Wisdom saving throw. It does so with Advantage if you or your allies are fighting it. On a failed save, the target has the Charmed condition until the spell ends or until you or your allies damage it. The Charmed creature is Friendly to you. When the spell ends, the target knows it was Charmed by you.","level":1,"higher_level":"You can target one additional creature for each spell slot level above 1.","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_chill-touch', 'Chill Touch', 'Necromancy', 0, false, false, '{"key":"srd-2024_chill-touch","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"player_level_5","damage_roll":"2d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"player_level_11","damage_roll":"3d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"player_level_17","damage_roll":"4d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Chill Touch","desc":"Channeling the chill of the grave, make a melee spell attack against a target within reach. On a hit, the target takes 1d10 Necrotic damage, and it can''t regain Hit Points until the end of your next turn.","level":0,"higher_level":"The damage increases by 1d10 when you reach levels 5 (2d10), 11 (3d10), and 17 (4d10).","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"1d10","damage_types":["necrotic"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_chromatic-orb', 'Chromatic Orb', 'Evocation', 1, false, false, '{"key":"srd-2024_chromatic-orb","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":"4d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_3","damage_roll":"5d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":"6d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"7d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"8d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"9d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"10d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"11d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Chromatic Orb","desc":"You hurl an orb of energy at a target within range. Choose Acid, Cold, Fire, Lightning, Poison, or Thunder for the type of orb you create, and then make a ranged spell attack against the target. On a hit, the target takes 3d8 damage of the chosen type. If you roll the same number on two or more of the d8s, the orb leaps to a different target of your choice within 30 feet of the target. Make an attack roll against the new target, and make a new damage roll. The orb can''t leap again unless you cast the spell with a level 2+ spell slot.","level":1,"higher_level":"The damage increases by 1d8 for each spell slot level above 1. The orb can leap a maximum number of times equal to the level of the slot expended, and a creature can be targeted only once by each casting of this spell.","target_type":"creature","range_text":"90 feet","range":90,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a diamond worth 50+ GP","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"3d8","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_circle-of-death', 'Circle of Death', 'Necromancy', 6, false, false, '{"key":"srd-2024_circle-of-death","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_7","damage_roll":"10d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"12d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"14d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Circle of Death","desc":"Negative energy ripples out in a 60-foot-radius Sphere from a point you choose within range. Each creature in that area makes a Constitution saving throw, taking 8d8 Necrotic damage on a failed save or half as much damage on a successful one.","level":6,"higher_level":"The damage increases by 2d8 for each spell slot level above 6.","target_type":"creature","range_text":"150 feet","range":150,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"the powder of a crushed black pearl worth 500+ GP","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"8d8","damage_types":["necrotic"],"duration":"instantaneous","shape_type":"sphere","shape_size":60,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_clairvoyance', 'Clairvoyance', 'Divination', 3, true, false, '{"key":"srd-2024_clairvoyance","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Clairvoyance","desc":"You create an Invisible sensor within range in a location familiar to you (a place you have visited or seen before) or in an obvious location that is unfamiliar to you (such as behind a door, around a corner, or in a grove of trees). The intangible, invulnerable sensor remains in place for the duration. When you cast the spell, choose seeing or hearing. You can use the chosen sense through the sensor as if you were in its space. As a Bonus Action, you can switch between seeing and hearing. A creature that sees the sensor (such as a creature benefiting from See Invisibility or Truesight) sees a luminous orb about the size of your fist.","level":3,"higher_level":"","target_type":"creature","range_text":"1 mile","range":5280,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a focus worth 100+ GP, either a jeweled horn for hearing or a glass eye for seeing","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_clone', 'Clone', 'Necromancy', 8, false, false, '{"key":"srd-2024_clone","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Clone","desc":"You touch a creature or at least 1 cubic inch of its flesh. An inert duplicate of that creature forms inside the vessel used in the spell''s casting and finishes growing after 120 days; you choose whether the finished clone is the same age as the creature or younger. The clone remains inert and endures indefinitely while its vessel remains undisturbed. If the original creature dies after the clone finishes forming, the creature''s soul transfers to the clone if the soul is free and willing to return. The clone is physically identical to the original and has the same personality, memories, and abilities, but none of the original''s equipment. The creature''s original remains, if any, become inert and can''t be revived, since the creature''s soul is elsewhere.","level":8,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"1hour","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a diamond worth 1,000+ GP, which the spell consumes, and a sealable vessel worth 2,000+ GP that is large enough to hold the creature being cloned","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_cloudkill', 'Cloudkill', 'Conjuration', 5, true, false, '{"key":"srd-2024_cloudkill","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_6","damage_roll":"6d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"7d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"8d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"9d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Cloudkill","desc":"You create a 20-foot-radius Sphere of yellow-green fog centered on a point within range. The fog lasts for the duration or until strong wind (such as the one created by Gust of Wind) disperses it, ending the spell. Its area is Heavily Obscured. Each creature in the Sphere makes a Constitution saving throw, taking 5d8 Poison damage on a failed save or half as much damage on a successful one. A creature must also make this save when the Sphere moves into its space and when it enters the Sphere or ends its turn there. A creature makes this save only once per turn. The Sphere moves 10 feet away from you at the start of each of your turns.","level":5,"higher_level":"The damage increases by 1d8 for each spell slot level above 5.","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"5d8","damage_types":["poison"],"duration":"10 minutes","shape_type":"sphere","shape_size":20,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_color-spray', 'Color Spray', 'Illusion', 1, false, false, '{"key":"srd-2024_color-spray","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Illusion","key":"illusion"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Color Spray","desc":"You launch a dazzling array of flashing, colorful light. Each creature in a 15-foot Cone originating from you must succeed on a Constitution saving throw or have the Blinded condition until the end of your next turn.","level":1,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a pinch of colorful sand","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":"cone","shape_size":15,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_command', 'Command', 'Enchantment', 1, false, false, '{"key":"srd-2024_command","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":null,"target_count":2,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_3","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":null,"target_count":4,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":null,"target_count":5,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":6,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":7,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":8,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":9,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Paladin","key":"srd-2024_paladin"}],"range_unit":"feet","shape_size_unit":"feet","name":"Command","desc":"You speak a one-word command to a creature you can see within range. The target must succeed on a Wisdom saving throw or follow the command on its next turn. Choose the command from these options:\n\n- **Drop.** The target drops whatever it is holding and then ends its turn.\n- **Flee.** The target spends its turn moving away from you by the fastest available means.\n- **Grovel.** The target has the Prone condition and then ends its turn.\n- **Halt.** On its turn, the target doesn''t move and takes no action or Bonus Action.","level":1,"higher_level":"You can affect one additional creature for each spell slot level above 1.","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_commune', 'Commune', 'Divination', 5, false, true, '{"key":"srd-2024_commune","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Commune","desc":"You contact a deity or a divine proxy and ask up to three questions that can be answered with yes or no. You must ask your questions before the spell ends. You receive a correct answer for each question. Divine beings aren''t necessarily omniscient, so you might receive \"unclear\" as an answer if a question pertains to information that lies beyond the deity''s knowledge. In a case where a one-word answer could be misleading or contrary to the deity''s interests, the GM might offer a short phrase as an answer instead. If you cast the spell more than once before finishing a Long Rest, there is a cumulative 25 percent chance for each casting after the first that you get no answer.","level":5,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":true,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"incense","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_commune-with-nature', 'Commune with Nature', 'Divination', 5, false, true, '{"key":"srd-2024_commune-with-nature","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Commune with Nature","desc":"You commune with nature spirits and gain knowledge of the surrounding area. In the outdoors, the spell gives you knowledge of the area within 3 miles of you. In caves and other natural underground settings, the radius is limited to 300 feet. The spell doesn''t function where nature has been replaced by construction, such as in castles and settlements. Choose three of the following facts; you learn those facts as they pertain to the spell''s area: - Locations of settlements - Locations of portals to other planes of existence - Location of one Challenge Rating 10+ creature (GM''s choice) that is a Celestial, an Elemental, a Fey, a Fiend, or an Undead - The most prevalent kind of plant, mineral, or Beast (you choose which to learn) - Locations of bodies of water For example, you could determine the location of a powerful monster in the area, the locations of bodies of water, and the locations of any towns.","level":5,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":true,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_comprehend-languages', 'Comprehend Languages', 'Divination', 1, false, true, '{"key":"srd-2024_comprehend-languages","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Comprehend Languages","desc":"For the duration, you understand the literal meaning of any language that you hear or see signed. You also understand any written language that you see, but you must be touching the surface on which the words are written. It takes about 1 minute to read one page of text. This spell doesn''t decode symbols or secret messages.","level":1,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":true,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a pinch of soot and salt","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_compulsion', 'Compulsion', 'Enchantment', 4, true, false, '{"key":"srd-2024_compulsion","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Compulsion","desc":"Each creature of your choice that you can see within range must succeed on a Wisdom saving throw or have the Charmed condition until the spell ends. For the duration, you can take a Bonus Action to designate a direction that is horizontal to you. Each Charmed target must use as much of its movement as possible to move in that direction on its next turn, taking the safest route. After moving in this way, a target repeats the save, ending the spell on itself on a success.","level":4,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_cone-of-cold', 'Cone of Cold', 'Evocation', 5, false, false, '{"key":"srd-2024_cone-of-cold","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_6","damage_roll":"9d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"10d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"11d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"12d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Cone of Cold","desc":"You unleash a blast of cold air. Each creature in a 60-foot Cone originating from you makes a Constitution saving throw, taking 8d8 Cold damage on a failed save or half as much damage on a successful one. A creature killed by this spell becomes a frozen statue until it thaws.","level":5,"higher_level":"The damage increases by 1d8 for each spell slot level above 5.","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a small crystal or glass cone","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"8d8","damage_types":["cold"],"duration":"instantaneous","shape_type":"cone","shape_size":60,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_confusion', 'Confusion', 'Enchantment', 4, true, false, '{"key":"srd-2024_confusion","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_5","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":15,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":20,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":25,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":30,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":35,"desc":null}],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Confusion","desc":"Each creature in a 10-foot-radius Sphere centered on a point you choose within range must succeed on a Wisdom saving throw, or that target can''t take Bonus Actions or Reactions and must roll 1d10 at the start of each of its turns to determine its behavior for that turn, consulting the table below. Table: 1d10 Behavior for the Turn | d10 | Behavior for the Turn | |------|----------------------------------------------------------------------------------------------------------------------------------------------| | 1 | The target doesn''t take an action, and it uses all its movement to move. Roll 1d4 for the direction: 1, north; 2, east; 3, south; or 4, west.| | 2–6 | The target doesn''t move or take actions. | | 7–8 | The target doesn''t move, and it takes the Attack action to make one melee attack against a random creature within reach. If none are within reach, the target takes no action. | | 9–10 | The target chooses its behavior. | At the end of each of its turns, an affected target repeats the save, ending the spell on itself on a success.","level":4,"higher_level":"The Sphere''s radius increases by 5 feet for each spell slot level above 4.","target_type":"creature","range_text":"90 feet","range":90,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"three nut shells","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"1d10","damage_types":[],"duration":"1 minute","shape_type":"sphere","shape_size":10,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_conjure-animals', 'Conjure Animals', 'Conjuration', 3, true, false, '{"key":"srd-2024_conjure-animals","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_4","damage_roll":"4d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"5d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"6d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"7d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"8d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"9d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Conjure Animals","desc":"You conjure nature spirits that appear as a Large pack of spectral, intangible animals in an unoccupied space you can see within range. The pack lasts for the duration, and you choose the spirits'' animal form, such as wolves, serpents, or birds. You have Advantage on Strength saving throws while you''re within 5 feet of the pack, and when you move on your turn, you can also move the pack up to 30 feet to an unoccupied space you can see. Whenever the pack moves within 10 feet of a creature you can see and whenever a creature you can see enters a space within 10 feet of the pack or ends its turn there, you can force that creature to make a Dexterity saving throw. On a failed save, the creature takes 3d10 Slashing damage. A creature makes this save only once per turn.","level":3,"higher_level":"The damage increases by 1d10 for each spell slot level above 3.","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"strength","attack_roll":false,"damage_roll":"3d10","damage_types":["slashing"],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_conjure-celestial', 'Conjure Celestial', 'Conjuration', 7, true, false, '{"key":"srd-2024_conjure-celestial","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_8","damage_roll":"2d12","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Healing and damage increase by 1d12."},{"type":"slot_level_9","damage_roll":"3d12","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Healing and damage increase by 2d12."}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Conjure Celestial","desc":"You conjure a spirit from the Upper Planes, which manifests as a pillar of light in a 10-foot-radius, 40-foot-high Cylinder centered on a point within range. For each creature you can see in the Cylinder, choose which of these lights shines on it: Until the spell ends, Bright Light fills the Cylinder, and when you move on your turn, you can also move the Cylinder up to 30 feet. Whenever the Cylinder moves into the space of a creature you can see and whenever a creature you can see enters the Cylinder or ends its turn there, you can bathe it in one of the lights. A creature can be affected by this spell only once per turn.","level":7,"higher_level":"The healing and damage increase by 1d12 for each spell slot level above 7.","target_type":"creature","range_text":"90 feet","range":90,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_conjure-elemental', 'Conjure Elemental', 'Conjuration', 5, true, false, '{"key":"srd-2024_conjure-elemental","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_6","damage_roll":"9d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"10d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"11d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"12d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Conjure Elemental","desc":"You conjure a Large, intangible spirit from the Elemental Planes that appears in an unoccupied space within range. Choose the spirit''s element, which determines its damage type: air (Lightning), earth (Thunder), fire (Fire), or water (Cold). The spirit lasts for the duration. Whenever a creature you can see enters the spirit''s space or starts its turn within 5 feet of the spirit, you can force that creature to make a Dexterity saving throw if the spirit has no creature Restrained. On failed save, the target takes 8d8 damage of the spirit''s type, and the target has the Restrained condition until the spell ends. At the start of each of its turns, the Restrained target repeats the save. On a failed save, the target takes 4d8 damage of the spirit''s type. On a successful save, the target isn''t Restrained by the spirit.","level":5,"higher_level":"The damage increases by 1d8 for each spell slot level above 5.","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"8d8","damage_types":[],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_conjure-fey', 'Conjure Fey', 'Conjuration', 6, true, false, '{"key":"srd-2024_conjure-fey","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_7","damage_roll":"4d12","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"5d12","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"6d12","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Conjure Fey","desc":"You conjure a Medium spirit from the Feywild in an unoccupied space you can see within range. The spirit lasts for the duration, and it looks like a Fey creature of your choice. When the spirit appears, you can make one melee spell attack against a creature within 5 feet of it. On a hit, the target takes Psychic damage equal to 3d12 plus your spellcasting ability modifier, and the target has the Frightened condition until the start of your next turn, with both you and the spirit as the source of the fear. As a Bonus Action on your later turns, you can teleport the spirit to an unoccupied space you can see within 30 feet of the space it left and make the attack against a creature within 5 feet of it.","level":6,"higher_level":"The damage increases by 1d12 for each spell slot level above 6.","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"3d12","damage_types":["psychic"],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_conjure-minor-elementals', 'Conjure Minor Elementals', 'Conjuration', 4, true, false, '{"key":"srd-2024_conjure-minor-elementals","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_5","damage_roll":"3d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"4d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"5d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"6d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"7d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Conjure Minor Elementals","desc":"You conjure spirits from the Elemental Planes that flit around you in a 15-foot Emanation for the duration. Until the spell ends, any attack you make deals an extra 2d8 damage when you hit a creature in the Emanation. This damage is Acid, Cold, Fire, or Lightning (your choice when you make the attack). In addition, the ground in the Emanation is Difficult Terrain for your enemies.","level":4,"higher_level":"The damage increases by 1d8 for each spell slot level above 4.","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"2d8","damage_types":[],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_conjure-woodland-beings', 'Conjure Woodland Beings', 'Conjuration', 4, true, false, '{"key":"srd-2024_conjure-woodland-beings","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_5","damage_roll":"6d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"7d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"8d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"9d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"10d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Conjure Woodland Beings","desc":"You conjure nature spirits that flit around you in a 10-foot Emanation for the duration. Whenever the Emanation enters the space of a creature you can see and whenever a creature you can see enters the Emanation or ends its turn there, you can force that creature to make a Wisdom saving throw. The creature takes 5d8 Force damage on a failed save or half as much damage on a successful one. A creature makes this save only once per turn. In addition, you can take the Disengage action as a Bonus Action for the spell''s duration.","level":4,"higher_level":"The damage increases by 1d8 for each spell slot level above 4.","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"5d8","damage_types":["force"],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_contact-other-plane', 'Contact Other Plane', 'Divination', 5, false, true, '{"key":"srd-2024_contact-other-plane","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Contact Other Plane","desc":"You mentally contact a demigod, the spirit of a longdead sage, or some other knowledgeable entity from another plane. Contacting this otherworldly intelligence can break your mind. When you cast this spell, make a DC 15 Intelligence saving throw. On a successful save, you can ask the entity up to five questions. You must ask your questions before the spell ends. The GM answers each question with one word, such as \"yes,\" \"no,\" \"maybe,\" \"never,\" \"irrelevant,\" or \"unclear\" (if the entity doesn''t know the answer to the question). If a one-word answer would be misleading, the GM might instead offer a short phrase as an answer. On a failed save, you take 6d6 Psychic damage and have the Incapacitated condition until you finish a Long Rest. A Greater Restoration spell cast on you ends this effect.","level":5,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":true,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"intelligence","attack_roll":false,"damage_roll":"6d6","damage_types":["psychic"],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_contagion', 'Contagion', 'Necromancy', 5, false, false, '{"key":"srd-2024_contagion","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Contagion","desc":"Your touch inflicts a magical contagion. The target must succeed on a Constitution saving throw or take 11d8 Necrotic damage and have the Poisoned condition. Also, choose one ability when you cast the spell. While Poisoned, the target has Disadvantage on saving throws made with the chosen ability. The target must repeat the saving throw at the end of each of its turns until it gets three successes or failures. If the target succeeds on three of these saves, the spell ends on the target. If the target fails three of the saves, the spell lasts for 7 days on it. Whenever the Poisoned target receives an effect that would end the Poisoned condition, the target must succeed on a Constitution saving throw, or the Poisoned condition doesn''t end on it.","level":5,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"11d8","damage_types":["necrotic"],"duration":"7 days","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_contingency', 'Contingency', 'Abjuration', 6, false, false, '{"key":"srd-2024_contingency","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Contingency","desc":"Choose a spell of level 5 or lower that you can cast, that has a casting time of an action, and that can target you. You cast that spell—called the contingent spell—as part of casting Contingency, expending spell slots for both, but the contingent spell doesn''t come into effect. Instead, it takes effect when a certain trigger occurs. You describe that trigger when you cast the two spells. For example, a Contingency cast with Water Breathing might stipulate that Water Breathing comes into effect when you are engulfed in water or a similar liquid. The contingent spell takes effect immediately after the trigger occurs for the first time, whether or not you want it to, and then Contingency ends. The contingent spell takes effect only on you, even if it can normally target others. You can use only one Contingency spell at a time. If you cast this spell again, the effect of another Contingency spell on you ends. Also, Contingency ends on you if its material component is ever not on your person.","level":6,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a gem-encrusted statuette of yourself worth 1,500+ GP","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 days","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_continual-flame', 'Continual Flame', 'Evocation', 2, false, false, '{"key":"srd-2024_continual-flame","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Continual Flame","desc":"A flame springs from an object that you touch. The effect casts Bright Light in a 20-foot radius and Dim Light for an additional 20 feet. It looks like a regular flame, but it creates no heat and consumes no fuel. The flame can be covered or hidden but not smothered or quenched.","level":2,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"ruby dust worth 50+ GP, which the spell consumes","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"until dispelled","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_control-water', 'Control Water', 'Transmutation', 4, true, false, '{"key":"srd-2024_control-water","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Control Water","desc":"Until the spell ends, you control any water inside an area you choose that is a Cube up to 100 feet on a side, using one of the following effects. As a Magic action on your later turns, you can repeat the same effect or choose a different one.\n\n**Flood.** You cause the water level of all standing water in the area to rise by as much as 20 feet. If you choose an area in a large body of water, you instead create a 20-foot tall wave that travels from one side of the area to the other and then crashes. Any Huge or smaller vehicles in the wave''s path are carried with it to the other side. Any Huge or smaller vehicles struck by the wave have a 25 percent chance of capsizing.\n\nThe water level remains elevated until the spell ends or you choose a different effect. If this effect produced a wave, the wave repeats on the start of your next turn while the flood effect lasts.\n\n**Part Water.** You part water in the area and create a trench. The trench extends across the spell''s area, and the separated water forms a wall to either side. The trench remains until the spell ends or you choose a different effect. The water then slowly fills in the trench over the course of the next round until the normal water level is restored.\n\n**Redirect Flow.** You cause flowing water in the area to move in a direction you choose, even if the water has to flow over obstacles, up walls, or in other unlikely directions. The water in the area moves as you direct it, but once it moves beyond the spell''s area, it resumes its flow based on the terrain. The water continues to move in the direction you chose until the spell ends or you choose a different effect.\n\n**Whirlpool.** You cause a whirlpool to form in the center of the area, which must be at least 50 feet square and 25 feet deep. The whirlpool lasts until you choose a different effect or the spell ends. The whirlpool is 5 feet wide at the base, up to 50 feet wide at the top, and 25 feet tall. Any creature in the water and within 25 feet of the whirlpool is pulled 10 feet toward it. When a creature enters the whirlpool for the first time on a turn or ends its turn there, it makes a Strength saving throw. On a failed save, the creature takes 2d8 Bludgeoning damage. On a successful save, the creature takes half as much damage. A creature can swim away from the whirlpool only if it first takes an action to pull away and succeeds on a Strength (Athletics) check against your spell save DC.","level":4,"higher_level":"","target_type":"creature","range_text":"300 feet","range":300,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a mixture of water and dust","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_control-weather', 'Control Weather', 'Transmutation', 8, true, false, '{"key":"srd-2024_control-weather","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Control Weather","desc":"You take control of the weather within 5 miles of you for the duration. You must be outdoors to cast this spell, and it ends early if you go indoors. When you cast the spell, you change the current weather conditions, which are determined by the GM. You can change precipitation, temperature, and wind. It takes 1d4 × 10 minutes for the new conditions to take effect. Once they do so, you can change the conditions again. When the spell ends, the weather gradually returns to normal. When you change the weather conditions, find a current condition on the following tables and change its stage by one, up or down. When changing the wind, you can change its direction. Table: Precipitation | Stage | Condition | |-------|--------------------------------------------| | 1 | Clear | | 2 | Light clouds | | 3 | Overcast or ground fog | | 4 | Rain, hail, or snow | | 5 | Torrential rain, driving hail, or blizzard | Table: Temperature | Stage | Condition | |-------------|-----------| | 1 | Heat wave | | 2 | Hot | | 3 | Warm | | 4 | Cool | | 5 | Cold | | 6 | Freezing | Table: Wind | Stage | Condition | |-------|---------------| | 1 | Calm | | 2 | Moderate wind | | 3 | Strong wind | | 4 | Gale | | 5 | Storm |","level":8,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"burning incense","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"1d4","damage_types":[],"duration":"8 hours","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_counterspell', 'Counterspell', 'Abjuration', 3, false, false, '{"key":"srd-2024_counterspell","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Counterspell","desc":"You attempt to interrupt a creature in the process of casting a spell. The creature makes a Constitution saving throw. On a failed save, the spell dissipates with no effect, and the action, Bonus Action, or Reaction used to cast it is wasted. If that spell was cast with a spell slot, the slot isn''t expended.","level":3,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"reaction","reaction_condition":"which you take when you see a creature within 60 feet of yourself casting a spell with Verbal, Somatic, or Material components","verbal":false,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_create-food-and-water', 'Create Food and Water', 'Conjuration', 3, false, false, '{"key":"srd-2024_create-food-and-water","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Paladin","key":"srd-2024_paladin"}],"range_unit":"feet","shape_size_unit":"feet","name":"Create Food and Water","desc":"You create 45 pounds of food and 30 gallons of fresh water on the ground or in containers within range—both useful in fending off the hazards of malnutrition and dehydration. The food is bland but nourishing and looks like a food of your choice, and the water is clean. The food spoils after 24 hours if uneaten.","level":3,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_create-or-destroy-water', 'Create or Destroy Water', 'Transmutation', 1, false, false, '{"key":"srd-2024_create-or-destroy-water","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":35,"desc":"create or destroy 20 gallons of water, or affect 35-foot cube"},{"type":"slot_level_3","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":40,"desc":"create or destroy 30 gallons of water, or affect 40-foot cube"},{"type":"slot_level_4","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":45,"desc":"create or destroy 40 gallons of water, or affect 45-foot cube"},{"type":"slot_level_5","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":50,"desc":"create or destroy 50 gallons of water, or affect 50-foot cube"},{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":55,"desc":"create or destroy 60 gallons of water, or affect 55-foot cube"},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":60,"desc":"create or destroy 70 gallons of water, or affect 60-foot cube"},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":65,"desc":"create or destroy 80 gallons of water, or affect 65-foot cube"},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":70,"desc":"create or destroy 90 gallons of water, or affect 70-foot cube"}],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Create or Destroy Water","desc":"You do one of the following:\n\n**Create Water.** You create up to 10 gallons of clean water within range in an open container. Alternatively, the water falls as rain in a 30-foot Cube within range, extinguishing exposed flames there.\n\n**Destroy Water.** You destroy up to 10 gallons of water in an open container within range. Alternatively, you destroy fog in a 30-foot Cube within range.","level":1,"higher_level":"You create or destroy 10 additional gallons of water, or the size of the Cube increases by 5 feet, for each spell slot level above 1.","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a mix of water and sand","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_create-undead', 'Create Undead', 'Necromancy', 6, false, false, '{"key":"srd-2024_create-undead","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"animate or reassert control over four Ghouls"},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"animate or reassert control over five Ghouls or two Ghasts or Wights"},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"animate or reassert control over six Ghouls, three Ghasts or Wights, or two Mummies"}],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Create Undead","desc":"You can cast this spell only at night. Choose up to three corpses of Medium or Small Humanoids within range. Each one becomes a Ghoul under your control (see \"Monsters\" for its stat block). As a Bonus Action on each of your turns, you can mentally command any creature you animated with this spell if the creature is within 120 feet of you (if you control multiple creatures, you can command any of them at the same time, issuing the same command to them). You decide what action the creature will take and where it will move on its next turn, or you can issue a general command, such as to guard a particular place. If you issue no commands, the creature takes the Dodge action and moves only to avoid harm. Once given an order, the creature continues to follow the order until its task is complete. The creature is under your control for 24 hours, after which it stops obeying any command you''ve given it. To maintain control of the creature for another 24 hours, you must cast this spell on the creature before the current 24-hour period ends. This use of the spell reasserts your control over up to three creatures you have animated with this spell rather than animating new ones.","level":6,"higher_level":"If you use a level 7 spell slot, you can animate or reassert control over four Ghouls. If you use a level 8 spell slot, you can animate or reassert control over five Ghouls or two Ghasts or Wights. If you use a level 9 spell slot, you can animate or reassert control over six Ghouls, three Ghasts or Wights, or two Mummies. See \"Monsters\" for these stat blocks.","target_type":"creature","range_text":"10 feet","range":10,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"one 150+ GP black onyx stone for each corpse","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_creation', 'Creation', 'Illusion', 5, false, false, '{"key":"srd-2024_creation","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":10,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":15,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":20,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":25,"desc":null}],"school":{"name":"Illusion","key":"illusion"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Creation","desc":"You pull wisps of shadow material from the Shadowfell to create an object within range. It is either an object of vegetable matter (soft goods, rope, wood, and the like) or mineral matter (stone, crystal, metal, and the like). The object must be no larger than a 5-foot Cube, and the object must be of a form and material that you have seen. The spell''s duration depends on the object''s material, as shown in the Materials table. If the object is composed of multiple materials, use the shortest duration. Using any object created by this spell as another spell''s Material component causes the other spell to fail. Table: Materials | Material | Duration | |-----------------------|------------| | Vegetable matter | 24 hours | | Stone or crystal | 12 hours | | Precious metals | 1 hour | | Gems | 10 minutes | | Adamantine or mithral | 1 minute |","level":5,"higher_level":"The Cube increases by 5 feet for each spell slot level above 5.","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a paintbrush","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"special","shape_type":"cube","shape_size":5,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_cure-wounds', 'Cure Wounds', 'Abjuration', 1, false, false, '{"key":"srd-2024_cure-wounds","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":"4d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_3","damage_roll":"6d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":"8d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"10d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"12d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"14d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"16d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"18d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Paladin","key":"srd-2024_paladin"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Cure Wounds","desc":"A creature you touch regains a number of Hit Points equal to 2d8 plus your spellcasting ability modifier.","level":1,"higher_level":"The healing increases by 2d8 for each spell slot level above 1.","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"2d8","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_dancing-lights', 'Dancing Lights', 'Illusion', 0, true, false, '{"key":"srd-2024_dancing-lights","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Illusion","key":"illusion"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Dancing Lights","desc":"You create up to four torch-size lights within range, making them appear as torches, lanterns, or glowing orbs that hover for the duration. Alternatively, you combine the four lights into one glowing Medium form that is vaguely humanlike. Whichever form you choose, each light sheds Dim Light in a 10 foot radius. As a Bonus Action, you can move the lights up to 60 feet to a space within range. A light must be within 20 feet of another light created by this spell, and a light vanishes if it exceeds the spell''s range.","level":0,"higher_level":"","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a bit of phosphorus","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_darkness', 'Darkness', 'Evocation', 2, true, false, '{"key":"srd-2024_darkness","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Darkness","desc":"For the duration, magical Darkness spreads from a point within range and fills a 15-foot-radius Sphere. Darkvision can''t see through it, and nonmagical light can''t illuminate it. Alternatively, you cast the spell on an object that isn''t being worn or carried, causing the Darkness to fill a 15-foot Emanation originating from that object. Covering that object with something opaque, such as a bowl or helm, blocks the Darkness. If any of this spell''s area overlaps with an area of Bright Light or Dim Light created by a spell of level 2 or lower, that other spell is dispelled.","level":2,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":false,"material":true,"material_specified":"bat fur and a piece of coal","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 minutes","shape_type":"sphere","shape_size":15,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_darkvision', 'Darkvision', 'Transmutation', 2, false, false, '{"key":"srd-2024_darkvision","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Darkvision","desc":"For the duration, a willing creature you touch has Darkvision with a range of 150 feet.","level":2,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a dried carrot","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"8 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_daylight', 'Daylight', 'Evocation', 3, false, false, '{"key":"srd-2024_daylight","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Paladin","key":"srd-2024_paladin"},{"name":"Ranger","key":"srd-2024_ranger"},{"name":"Sorcerer","key":"srd-2024_sorcerer"}],"range_unit":"feet","shape_size_unit":"feet","name":"Daylight","desc":"For the duration, sunlight spreads from a point within range and fills a 60-foot-radius Sphere. The sunlight''s area is Bright Light and sheds Dim Light for an additional 60 feet. Alternatively, you cast the spell on an object that isn''t being worn or carried, causing the sunlight to fill a 60-foot Emanation originating from that object. Covering that object with something opaque, such as a bowl or helm, blocks the sunlight. If any of this spell''s area overlaps with an area of Darkness created by a spell of level 3 or lower, that other spell is dispelled.","level":3,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":"sphere","shape_size":60,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_death-ward', 'Death Ward', 'Abjuration', 4, false, false, '{"key":"srd-2024_death-ward","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Paladin","key":"srd-2024_paladin"}],"range_unit":"feet","shape_size_unit":"feet","name":"Death Ward","desc":"You touch a creature and grant it a measure of protection from death. The first time the target would drop to 0 Hit Points before the spell ends, the target instead drops to 1 Hit Point, and the spell ends. If the spell is still in effect when the target is subjected to an effect that would kill it instantly without dealing damage, that effect is negated against the target, and the spell ends.","level":4,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"8 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_delayed-blast-fireball', 'Delayed Blast Fireball', 'Evocation', 7, true, false, '{"key":"srd-2024_delayed-blast-fireball","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_8","damage_roll":"13d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"14d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Delayed Blast Fireball","desc":"A beam of yellow light flashes from you, then condenses at a chosen point within range as a glowing bead for the duration. When the spell ends, the bead explodes, and each creature in a 20-foot-radius Sphere centered on that point makes a Dexterity saving throw. A creature takes Fire damage equal to the total accumulated damage on a failed save or half as much damage on a successful one. The spell''s base damage is 12d6, and the damage increases by 1d6 whenever your turn ends and the spell hasn''t ended. If a creature touches the glowing bead before the spell ends, that creature makes a Dexterity saving throw. On a failed save, the spell ends, causing the bead to explode. On a successful save, the creature can throw the bead up to 40 feet. If the thrown bead enters a creature''s space or collides with a solid object, the spell ends, and the bead explodes. When the bead explodes, flammable objects in the explosion that aren''t being worn or carried start burning.","level":7,"higher_level":"The base damage increases by 1d6 for each spell slot level above 7.","target_type":"creature","range_text":"150 feet","range":150,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a ball of bat guano and sulfur","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"12d6","damage_types":["fire"],"duration":"1 minute","shape_type":"sphere","shape_size":20,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_demiplane', 'Demiplane', 'Conjuration', 8, false, false, '{"key":"srd-2024_demiplane","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Demiplane","desc":"You create a shadowy Medium door on a flat solid surface that you can see within range. This door can be opened and closed, and it leads to a demiplane that is an empty room 30 feet in each dimension, made of wood or stone (your choice). When the spell ends, the door vanishes, and any objects inside the demiplane remain there. Any creatures inside also remain unless they opt to be shunted through the door as it vanishes, landing with the Prone condition in the unoccupied spaces closest to the door''s former space. Each time you cast this spell, you can create a new demiplane or connect the shadowy door to a demiplane you created with a previous casting of this spell. Additionally, if you know the nature and contents of a demiplane created by a casting of this spell by another creature, you can connect the shadowy door to that demiplane instead.","level":8,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":false,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_detect-evil-and-good', 'Detect Evil and Good', 'Divination', 1, true, false, '{"key":"srd-2024_detect-evil-and-good","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Paladin","key":"srd-2024_paladin"}],"range_unit":"feet","shape_size_unit":"feet","name":"Detect Evil and Good","desc":"For the duration, you sense the location of any Aberration, Celestial, Elemental, Fey, Fiend, or Undead within 30 feet of yourself. You also sense whether the Hallow spell is active there and, if so, where. The spell is blocked by 1 foot of stone, dirt, or wood; 1 inch of metal; or a thin sheet of lead.","level":1,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_detect-magic', 'Detect Magic', 'Divination', 1, true, true, '{"key":"srd-2024_detect-magic","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Paladin","key":"srd-2024_paladin"},{"name":"Ranger","key":"srd-2024_ranger"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Detect Magic","desc":"For the duration, you sense the presence of magical effects within 30 feet of yourself. If you sense such effects, you can take the Magic action to see a faint aura around any visible creature or object in the area that bears the magic, and if an effect was created by a spell, you learn the spell''s school of magic. The spell is blocked by 1 foot of stone, dirt, or wood; 1 inch of metal; or a thin sheet of lead.","level":1,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":true,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_detect-poison-and-disease', 'Detect Poison and Disease', 'Divination', 1, true, true, '{"key":"srd-2024_detect-poison-and-disease","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Paladin","key":"srd-2024_paladin"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Detect Poison and Disease","desc":"For the duration, you sense the location of poisons, poisonous or venomous creatures, and magical contagions within 30 feet of yourself. You sense the kind of poison, creature, or contagion in each case. The spell is blocked by 1 foot of stone, dirt, or wood; 1 inch of metal; or a thin sheet of lead.","level":1,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":true,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a yew leaf","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_detect-thoughts', 'Detect Thoughts', 'Divination', 2, true, false, '{"key":"srd-2024_detect-thoughts","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Detect Thoughts","desc":"You activate one of the effects below. Until the spell ends, you can activate either effect as a Magic action on your later turns.\n\n***Sense Thoughts.*** You sense the presence of thoughts within 30 feet of yourself that belong to creatures that know languages or are telepathic. You don''t read the thoughts, but you know that a thinking creature is present. The spell is blocked by 1 foot of stone, dirt, or wood; 1 inch of metal; or a thin sheet of lead.\n\n**Read Thoughts.** Target one creature you can see within 30 feet of yourself or one creature within 30 feet of yourself that you detected with the Sense Thoughts option. You learn what is most on the target''s mind right now. If the target doesn''t know any languages and isn''t telepathic, you learn nothing.\n\nAs a Magic action on your next turn, you can try to probe deeper into the target''s mind. If you probe deeper, the target makes a Wisdom saving throw. On a failed save, you discern the target''s reasoning, emotions, and something that looms large in its mind (such as a worry, love, or hate). On a successful save, the spell ends. Either way, the target knows that you are probing into its mind, and until you shift your attention away from the target''s mind, the target can take an action on its turn to make an Intelligence (Arcana) check against your spell save DC, ending the spell on a success.","level":2,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"1 Copper Piece","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_dimension-door', 'Dimension Door', 'Conjuration', 4, false, false, '{"key":"srd-2024_dimension-door","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Dimension Door","desc":"You teleport to a location within range. You arrive at exactly the spot desired. It can be a place you can see, one you can visualize, or one you can describe by stating distance and direction, such as \"200 feet straight downward\" or \"300 feet upward to the northwest at a 45-degree angle.\" You can also teleport one willing creature. The creature must be within 5 feet of you when you teleport, and it teleports to a space within 5 feet of your destination space. If you, the other creature, or both would arrive in a space occupied by a creature or completely filled by one or more objects, you and any creature traveling with you each take 4d6 Force damage, and the teleportation fails.","level":4,"higher_level":"","target_type":"creature","range_text":"500 feet","range":500,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"4d6","damage_types":["force"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_disguise-self', 'Disguise Self', 'Illusion', 1, false, false, '{"key":"srd-2024_disguise-self","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Illusion","key":"illusion"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Disguise Self","desc":"You make yourself—including your clothing, armor, weapons, and other belongings on your person look different until the spell ends. You can seem 1 foot shorter or taller and can appear heavier or lighter. You must adopt a form that has the same basic arrangement of limbs as you have. Otherwise, the extent of the illusion is up to you. The changes wrought by this spell fail to hold up to physical inspection. For example, if you use this spell to add a hat to your outfit, objects pass through the hat, and anyone who touches it would feel nothing. To discern that you are disguised, a creature must take the Study action to inspect your appearance and succeed on an Intelligence (Investigation) check against your spell save DC.","level":1,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_disintegrate', 'Disintegrate', 'Transmutation', 6, false, false, '{"key":"srd-2024_disintegrate","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_7","damage_roll":"13d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"16d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"19d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Disintegrate","desc":"You launch a green ray at a target you can see within range. The target can be a creature, a nonmagical object, or a creation of magical force, such as the wall created by Wall of Force. A creature targeted by this spell makes a Dexterity saving throw. On a failed save, the target takes 10d6 + 40 Force damage. If this damage reduces it to 0 Hit Points, it and everything nonmagical it is wearing and carrying are disintegrated into gray dust. The target can be revived only by a True Resurrection or a Wish spell. This spell automatically disintegrates a Large or smaller nonmagical object or a creation of magical force. If such a target is Huge or larger, this spell disintegrates a 10-foot-Cube portion of it.","level":6,"higher_level":"The damage increases by 3d6 for each spell slot level above 6.","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a lodestone and dust","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"10d6 + 40","damage_types":["force"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_dispel-evil-and-good', 'Dispel Evil and Good', 'Abjuration', 5, true, false, '{"key":"srd-2024_dispel-evil-and-good","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Paladin","key":"srd-2024_paladin"}],"range_unit":"feet","shape_size_unit":"feet","name":"Dispel Evil and Good","desc":"For the duration, Celestials, Elementals, Fey, Fiends, and Undead have Disadvantage on attack rolls against you. You can end the spell early by using either of the following special functions.","level":5,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"powdered silver and iron","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_dispel-magic', 'Dispel Magic', 'Abjuration', 3, false, false, '{"key":"srd-2024_dispel-magic","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_3","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"automatically dispels spells of 3rd level or lower"},{"type":"slot_level_4","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"automatically dispels spells of 4th level or lower"},{"type":"slot_level_5","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"automatically dispels spells of 5th level or lower"},{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"automatically dispels spells of 6th level or lower"},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"automatically dispels spells of 7th level or lower"},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"automatically dispels spells of 8th level or lower"},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"automatically dispels spells of 9th level or lower"}],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Paladin","key":"srd-2024_paladin"},{"name":"Ranger","key":"srd-2024_ranger"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Dispel Magic","desc":"Choose one creature, object, or magical effect within range. Any ongoing spell of level 3 or lower on the target ends. For each ongoing spell of level 4 or higher on the target, make an ability check using your spellcasting ability (DC 10 plus that spell''s level). On a successful check, the spell ends.","level":3,"higher_level":"You automatically end a spell on the target if the spell''s level is equal to or less than the level of the spell slot you use.","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_dissonant-whispers', 'Dissonant Whispers', 'Enchantment', 1, false, false, '{"key":"srd-2024_dissonant-whispers","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Dissonant Whispers","desc":"One creature of your choice that you can see within range hears a discordant melody in its mind. The target makes a Wisdom saving throw. On a failed save, it takes 3d6 Psychic damage and must immediately use its Reaction, if available, to move as far away from you as it can, using the safest route. On a successful save, the target takes half as much damage only.","level":1,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"3d6","damage_types":["psychic"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_divination', 'Divination', 'Divination', 4, false, true, '{"key":"srd-2024_divination","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Divination","desc":"This spell puts you in contact with a god or a god''s servants. You ask one question about a specific goal, event, or activity to occur within 7 days. The GM offers a truthful reply, which might be a short phrase or cryptic rhyme. The spell doesn''t account for circumstances that might change the answer, such as the casting of other spells. If you cast the spell more than once before finishing a Long Rest, there is a cumulative 25 percent chance for each casting after the first that you get no answer.","level":4,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":true,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"incense worth 25+ GP, which the spell consumes","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_divine-favor', 'Divine Favor', 'Transmutation', 1, false, false, '{"key":"srd-2024_divine-favor","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Paladin","key":"srd-2024_paladin"}],"range_unit":"feet","shape_size_unit":"feet","name":"Divine Favor","desc":"Until the spell ends, your attacks with weapons deal an extra 1d4 Radiant damage on a hit.","level":1,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"bonus-action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"1d4","damage_types":["radiant"],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_divine-smite', 'Divine Smite', 'Evocation', 1, false, false, '{"key":"srd-2024_divine-smite","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":"3d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_3","damage_roll":"4d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":"5d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"6d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"7d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"8d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"9d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"10d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Paladin","key":"srd-2024_paladin"}],"range_unit":"feet","shape_size_unit":"feet","name":"Divine Smite","desc":"The target takes an extra 2d8 Radiant damage from the attack. The damage increases by 1d8 if the target is a Fiend or an Undead.","level":1,"higher_level":"The damage increases by 1d8 for each spell slot level above 1.","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"bonus-action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"2d8","damage_types":["radiant"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_divine-word', 'Divine Word', 'Evocation', 7, false, false, '{"key":"srd-2024_divine-word","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Divine Word","desc":"You utter a word imbued with power from the Upper Planes. Each creature of your choice in range makes a Charisma saving throw. On a failed save, a target that has 50 Hit Points or fewer suffers an effect based on its current Hit Points, as shown in the Divine Word Effects table. Regardless of its Hit Points, a Celestial, an Elemental, a Fey, or a Fiend target that fails its save is forced back to its plane of origin (if it isn''t there already) and can''t return to the current plane for 24 hours by any means short of a Wish spell.\n\n| Hit Points | Effect |\n|---|---|\n| 0–20 | The target dies. |\n| 21–30 | The target has the Blinded, Deafened, and Stunned conditions for 1 hour. |\n| 31–40 | The target has the Blinded and Deafened conditions for 10 minutes. |\n| 41–50 | The target has the Deafened condition for 1 minute. |","level":7,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"bonus-action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"charisma","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_dominate-beast', 'Dominate Beast', 'Enchantment', 4, true, false, '{"key":"srd-2024_dominate-beast","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_5","damage_roll":null,"target_count":null,"duration":"10 minutes","range":null,"concentration":true,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":"1 hour","range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":"8 hours","range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":"8 hours","range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":"8 hours","range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"},{"name":"Sorcerer","key":"srd-2024_sorcerer"}],"range_unit":"feet","shape_size_unit":"feet","name":"Dominate Beast","desc":"One Beast you can see within range must succeed on a Wisdom saving throw or have the Charmed condition for the duration. The target has Advantage on the save if you or your allies are fighting it. Whenever the target takes damage, it repeats the save, ending the spell on itself on a success. You have a telepathic link with the Charmed target while the two of you are on the same plane of existence. On your turn, you can use this link to issue commands to the target (no action required), such as \"Attack that creature,\" \"Move over there,\" or \"Fetch that object.\" The target does its best to obey on its turn. If it completes an order and doesn''t receive further direction from you, it acts and moves as it likes, focusing on protecting itself. You can command the target to take a Reaction but must take your own Reaction to do so.","level":4,"higher_level":"Your Concentration can last longer with a spell slot of level 5 (up to 10 minutes), 6 (up to 1 hour), or 7+ (up to 8 hours).","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_dominate-monster', 'Dominate Monster', 'Enchantment', 8, true, false, '{"key":"srd-2024_dominate-monster","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":"8 hours","range":null,"concentration":true,"shape_size":null,"desc":null}],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Dominate Monster","desc":"One creature you can see within range must succeed on a Wisdom saving throw or have the Charmed condition for the duration. The target has Advantage on the save if you or your allies are fighting it. Whenever the target takes damage, it repeats the save, ending the spell on itself on a success. You have a telepathic link with the Charmed target while the two of you are on the same plane of existence. On your turn, you can use this link to issue commands to the target (no action required), such as \"Attack that creature,\" \"Move over there,\" or \"Fetch that object.\" The target does its best to obey on its turn. If it completes an order and doesn''t receive further direction from you, it acts and moves as it likes, focusing on protecting itself. You can command the target to take a Reaction but must take your own Reaction to do so.","level":8,"higher_level":"Your Concentration can last longer with a level 9 spell slot (up to 8 hours).","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_dominate-person', 'Dominate Person', 'Enchantment', 5, true, false, '{"key":"srd-2024_dominate-person","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":"10 minutes","range":null,"concentration":true,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":"1 hour","range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":"8 hours","range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":"8 hours","range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Dominate Person","desc":"One Humanoid you can see within range must succeed on a Wisdom saving throw or have the Charmed condition for the duration. The target has Advantage on the save if you or your allies are fighting it. Whenever the target takes damage, it repeats the save, ending the spell on itself on a success. You have a telepathic link with the Charmed target while the two of you are on the same plane of existence. On your turn, you can use this link to issue commands to the target (no action required), such as \"Attack that creature,\" \"Move over there,\" or \"Fetch that object.\" The target does its best to obey on its turn. If it completes an order and doesn''t receive further direction from you, it acts and moves as it likes, focusing on protecting itself. You can command the target to take a Reaction but must take your own Reaction to do so.","level":5,"higher_level":"Your Concentration can last longer with a spell slot of level 6 (up to 10 minutes), 7 (up to 1 hour), or 8+ (up to 8 hours).","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_dragons-breath', 'Dragon''s Breath', 'Transmutation', 2, true, false, '{"key":"srd-2024_dragons-breath","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_3","damage_roll":"4d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":"5d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"6d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"7d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"8d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"9d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"10d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Dragon''s Breath","desc":"You touch one willing creature, and choose Acid, Cold, Fire, Lightning, or Poison. Until the spell ends, the target can take a Magic action to exhale a 15-foot Cone. Each creature in that area makes a Dexterity saving throw, taking 3d6 damage of the chosen type on a failed save or half as much damage on a successful one.","level":2,"higher_level":"The damage increases by 1d6 for each spell slot level above 2.","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"bonus-action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a hot pepper","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"3d6","damage_types":[],"duration":"1 minute","shape_type":"cone","shape_size":15,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_dream', 'Dream', 'Illusion', 5, false, false, '{"key":"srd-2024_dream","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Illusion","key":"illusion"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Dream","desc":"You target a creature you know on the same plane of existence. You or a willing creature you touch enters a trance state to act as a dream messenger. While in the trance, the messenger is Incapacitated and has a Speed of 0. If the target is asleep, the messenger appears in the target''s dreams and can converse with the target as long as it remains asleep, through the spell''s duration. The messenger can also shape the dream''s environment, creating landscapes, objects, and other images. The messenger can emerge from the trance at any time, ending the spell. The target recalls the dream perfectly upon waking. If the target is awake when you cast the spell, the messenger knows it and can either end the trance (and the spell) or wait for the target to sleep, at which point the messenger enters its dreams. You can make the messenger terrifying to the target. If you do so, the messenger can deliver a message of no more than ten words, and then the target makes a Wisdom saving throw. On a failed save, the target gains no benefit from its rest, and it takes 3d6 Psychic damage when it wakes up.","level":5,"higher_level":"","target_type":"creature","range_text":"Special","range":0,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a handful of sand","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"3d6","damage_types":["psychic"],"duration":"8 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_druidcraft', 'Druidcraft', 'Transmutation', 0, false, false, '{"key":"srd-2024_druidcraft","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Druidcraft","desc":"Whispering to the spirits of nature, you create one of the following effects within range.\n\n- ***Weather Sensor.*** You create a Tiny, harmless sensory effect that predicts what the weather will be at your location for the next 24 hours. The effect might manifest as a golden orb for clear skies, a cloud for rain, falling snowflakes for snow, and so on. This effect persists for 1 round.\n- ***Bloom.*** You instantly make a flower blossom, a seed pod open, or a leaf bud bloom.\n- ***Sensory Effect.*** You create a harmless sensory effect, such as falling leaves, spectral dancing fairies, a gentle breeze, the sound of an animal, or the faint odor of skunk. The effect must fit in a 5-foot Cube.\n- ***Fire Play.*** You light or snuff out a candle, a torch, or a campfire.","level":0,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_earthquake', 'Earthquake', 'Transmutation', 8, true, false, '{"key":"srd-2024_earthquake","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"}],"range_unit":"feet","shape_size_unit":"feet","name":"Earthquake","desc":"Choose a point on the ground that you can see within range. For the duration, an intense tremor rips through the ground in a 100-foot-radius circle centered on that point. The ground there is Difficult Terrain.\n\nWhen you cast this spell and at the end of each of your turns for the duration, each creature on the ground in the area makes a Dexterity saving throw. On a failed save, a creature has the Prone condition, and its Concentration is broken.\n\nYou can also cause the effects below.\n\n***Fissures.*** A total of 1d6 fissures open in the spell''s area at the end of the turn you cast it. You choose the fissures'' locations, which can''t be under structures. Each fissure is 1d10 × 10 feet deep and 10 feet wide, and it extends from one edge of the spell''s area to another edge. A creature in the same space as a fissure must succeed on a Dexterity saving throw or fall in. A creature that successfully saves moves with the fissure''s edge as it opens.\n\n***Structures.*** The tremor deals 50 Bludgeoning damage to any structure in contact with the ground in the area when you cast the spell and at the end of each of your turns until the spell ends. If a structure drops to 0 Hit Points, it collapses.\n\nA creature within a distance from a collapsing structure equal to half the structure''s height makes a Dexterity saving throw. On a failed save, the creature takes 12d6 Bludgeoning damage, has the Prone condition, and is buried in the rubble, requiring a DC 20 Strength (Athletics) check as an action to escape. On a successful save, the creature takes half as much damage only.","level":8,"higher_level":"","target_type":"creature","range_text":"500 feet","range":500,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a fractured rock","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"12d6","damage_types":["bludgeoning"],"duration":"1 minute","shape_type":"sphere","shape_size":100,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_eldritch-blast', 'Eldritch Blast', 'Evocation', 0, false, false, '{"key":"srd-2024_eldritch-blast","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"player_level_5","damage_roll":null,"target_count":2,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"player_level_11","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"player_level_17","damage_roll":null,"target_count":4,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Warlock","key":"srd-2024_warlock"}],"range_unit":"feet","shape_size_unit":"feet","name":"Eldritch Blast","desc":"You hurl a beam of crackling energy. Make a ranged spell attack against one creature or object in range. On a hit, the target takes 1d10 Force damage.","level":0,"higher_level":"The spell creates two beams at level 5, three beams at level 11, and four beams at level 17. You can direct the beams at the same target or at different ones. Make a separate attack roll for each beam.","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"1d10","damage_types":["force"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_elementalism', 'Elementalism', 'Transmutation', 0, false, false, '{"key":"srd-2024_elementalism","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Elementalism","desc":"You exert control over the elements, creating one of the following effects within range.\n\n***Beckon Air.*** You create a breeze strong enough to ripple cloth, stir dust, rustle leaves, and close open doors and shutters, all in a 5-foot Cube. Doors and shutters being held open by someone or something aren''t affected.\n\n***Beckon Earth.*** You create a thin shroud of dust or sand that covers surfaces in a 5-foot-square area, or you cause a single word to appear in your handwriting in a patch of dirt or sand.\n\n***Beckon Fire.*** You create a thin cloud of harmless embers and colored, scented smoke in a 5-foot Cube. You choose the color and scent, and the embers can light candles, torches, or lamps in that area. The smoke''s scent lingers for 1 minute.\n\n***Beckon Water.*** You create a spray of cool mist that lightly dampens creatures and objects in a 5-foot Cube. Alternatively, you create 1 cup of clean water either in an open container or on a surface, and the water evaporates in 1 minute.\n\n***Sculpt Element.*** You cause dirt, sand, fire, smoke, mist, or water that can fit in a 1-foot Cube to assume a crude shape (such as that of a creature) for 1 hour.","level":0,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_enhance-ability', 'Enhance Ability', 'Transmutation', 2, true, false, '{"key":"srd-2024_enhance-ability","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_3","damage_roll":null,"target_count":2,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":null,"target_count":4,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":5,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":6,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":7,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":8,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Enhance Ability","desc":"You touch a creature and choose Strength, Dexterity, Intelligence, Wisdom, or Charisma. For the duration, the target has Advantage on ability checks using the chosen ability.","level":2,"higher_level":"You can target one additional creature for each spell slot level above 2. You can choose a different ability for each target.","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"fur or a feather","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_enlargereduce', 'Enlarge/Reduce', 'Transmutation', 2, true, false, '{"key":"srd-2024_enlargereduce","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Enlarge/Reduce","desc":"For the duration, the spell enlarges or reduces a creature or an object you can see within range (see the chosen effect below). A targeted object must be neither worn nor carried. If the target is an unwilling creature, it can make a Constitution saving throw. On a successful save, the spell has no effect. Everything that a targeted creature is wearing and carrying changes size with it. Any item it drops returns to normal size at once. A thrown weapon or piece of ammunition returns to normal size immediately after it hits or misses a target.\n\n**_Enlarge._** The target''s size increases by one category—from Medium to Large, for example. The target also has Advantage on Strength checks and Strength saving throws. The target''s attacks with its enlarged weapons or Unarmed Strikes deal an extra 1d4 damage on a hit.\n\n**_Reduce._** The target''s size decreases by one category—from Medium to Small, for example. The target also has Disadvantage on Strength checks and Strength saving throws. The target''s attacks with its reduced weapons or Unarmed Strikes deal 1d4 less damage on a hit (this can''t reduce the damage below 1).","level":2,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a pinch of powdered iron","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_ensnaring-strike', 'Ensnaring Strike', 'Conjuration', 1, true, false, '{"key":"srd-2024_ensnaring-strike","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":"2d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_3","damage_roll":"3d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":"4d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"5d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"6d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"7d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"8d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"9d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Ensnaring Strike","desc":"As you hit the target, grasping vines appear on it, and it makes a Strength saving throw. A Large or larger creature has Advantage on this save. On a failed save, the target has the Restrained condition until the spell ends. On a successful save, the vines shrivel away, and the spell ends. While Restrained, the target takes 1d6 Piercing damage at the start of each of its turns. The target or a creature within reach of it can take an action to make a Strength (Athletics) check against your spell save DC. On a success, the spell ends.","level":1,"higher_level":"The damage increases by 1d6 for each spell slot level above 1.","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"bonus-action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"strength","attack_roll":false,"damage_roll":"1d6","damage_types":["piercing"],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_entangle', 'Entangle', 'Conjuration', 1, true, false, '{"key":"srd-2024_entangle","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Entangle","desc":"Grasping plants sprout from the ground in a 20-foot square within range. For the duration, these plants turn the ground in the area into Difficult Terrain. They disappear when the spell ends. Each creature (other than you) in the area when you cast the spell must succeed on a Strength saving throw or have the Restrained condition until the spell ends. A Restrained creature can take an action to make a Strength (Athletics) check against your spell save DC. On a success, it frees itself from the grasping plants and is no longer Restrained by them.","level":1,"higher_level":"","target_type":"creature","range_text":"90 feet","range":90,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"strength","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_enthrall', 'Enthrall', 'Enchantment', 2, true, false, '{"key":"srd-2024_enthrall","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Warlock","key":"srd-2024_warlock"}],"range_unit":"feet","shape_size_unit":"feet","name":"Enthrall","desc":"You weave a distracting string of words, causing creatures of your choice that you can see within range to make a Wisdom saving throw. Any creature you or your companions are fighting automatically succeeds on this save. On a failed save, a target has a −10 penalty to Wisdom (Perception) checks and Passive Perception until the spell ends.","level":2,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_etherealness', 'Etherealness', 'Conjuration', 7, false, false, '{"key":"srd-2024_etherealness","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_8","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":6,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Etherealness","desc":"You step into the border regions of the Ethereal Plane, where it overlaps with your current plane. You remain in the Border Ethereal for the duration. During this time, you can move in any direction. If you move up or down, every foot of movement costs an extra foot. You can perceive the plane you left, which looks gray, and you can''t see anything there more than 60 feet away. While on the Ethereal Plane, you can affect and be affected only by creatures, objects, and effects on that plane. Creatures that aren''t on the Ethereal Plane can''t perceive or interact with you unless a feature gives them the ability to do so. When the spell ends, you return to the plane you left in the spot that corresponds to your space in the Border Ethereal. If you appear in an occupied space, you are shunted to the nearest unoccupied space and take Force damage equal to twice the number of feet you are moved. This spell ends instantly if you cast it while you are on the Ethereal Plane or a plane that doesn''t border it, such as one of the Outer Planes.","level":7,"higher_level":"You can target up to three willing creatures (including yourself) for each spell slot level above 7. The creatures must be within 10 feet of you when you cast the spell.","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":["force"],"duration":"8 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_expeditious-retreat', 'Expeditious Retreat', 'Transmutation', 1, true, false, '{"key":"srd-2024_expeditious-retreat","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Expeditious Retreat","desc":"You take the Dash action, and until the spell ends, you can take that action again as a Bonus Action.","level":1,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"bonus-action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_eyebite', 'Eyebite', 'Necromancy', 6, true, false, '{"key":"srd-2024_eyebite","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Eyebite","desc":"For the duration, your eyes become an inky void. One creature of your choice within 60 feet of you that you can see must succeed on a Wisdom saving throw or be affected by one of the following effects of your choice for the duration. On each of your turns until the spell ends, you can take a Magic action to target another creature but can''t target a creature again if it has succeeded on a save against this casting of the spell.\n\n**_Asleep._** The target has the Unconscious condition. It wakes up if it takes any damage or if another creature takes an action to shake it awake.\n\n**_Panicked._** The target has the Frightened condition. On each of its turns, the Frightened target must take the Dash action and move away from you by the safest and shortest route available. If the target moves to a space at least 60 feet away from you where it can''t see you, this effect ends.\n\n**_Sickened._** The target has the Poisoned condition.","level":6,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_fabricate', 'Fabricate', 'Transmutation', 4, false, false, '{"key":"srd-2024_fabricate","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Fabricate","desc":"You convert raw materials into products of the same material. For example, you can fabricate a wooden bridge from a clump of trees, a rope from a patch of hemp, or clothes from flax or wool. Choose raw materials that you can see within range. You can fabricate a Large or smaller object (contained within a 10-foot Cube or eight connected 5-foot Cubes) given a sufficient quantity of material. If you''re working with metal, stone, or another mineral substance, however, the fabricated object can be no larger than Medium (contained within a 5-foot Cube). The quality of any fabricated objects is based on the quality of the raw materials. Creatures and magic items can''t be created by this spell. You also can''t use it to create items that require a high degree of skill—such as weapons and armor—unless you have proficiency with the type of Artisan''s Tools used to craft such objects.","level":4,"higher_level":"","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":"cube","shape_size":10,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_faerie-fire', 'Faerie Fire', 'Evocation', 1, true, false, '{"key":"srd-2024_faerie-fire","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Faerie Fire","desc":"Objects in a 20-foot Cube within range are outlined in blue, green, or violet light (your choice). Each creature in the Cube is also outlined if it fails a Dexterity saving throw. For the duration, objects and affected creatures shed Dim Light in a 10-foot radius and can''t benefit from the Invisible condition. Attack rolls against an affected creature or object have Advantage if the attacker can see it.","level":1,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":true,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":"cube","shape_size":20,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_faithful-hound', 'Faithful Hound', 'Conjuration', 4, false, false, '{"key":"srd-2024_faithful-hound","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Faithful Hound","desc":"You conjure a phantom watchdog in an unoccupied space that you can see within range. The hound remains for the duration or until the two of you are more than 300 feet apart from each other. No one but you can see the hound, and it is intangible and invulnerable. When a Small or larger creature comes within 30 feet of it without first speaking the password that you specify when you cast this spell, the hound starts barking loudly. The hound has Truesight with a range of 30 feet. At the start of each of your turns, the hound attempts to bite one enemy within 5 feet of it. That enemy must succeed on a Dexterity saving throw or take 4d8 Force damage. On your later turns, you can take a Magic action to move the hound up to 30 feet.","level":4,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a silver whistle","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"4d8","damage_types":["force"],"duration":"8 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_false-life', 'False Life', 'Necromancy', 1, false, false, '{"key":"srd-2024_false-life","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"grants 5 additional temporary hit points"},{"type":"slot_level_3","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"grants 10 additional temporary hit points"},{"type":"slot_level_4","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"grants 15 additional temporary hit points"},{"type":"slot_level_5","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"grants 20 additional temporary hit points"},{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"grants 25 additional temporary hit points"},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"grants 30 additional temporary hit points"},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"grants 35 additional temporary hit points"},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"grants 40 additional temporary hit points"}],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"False Life","desc":"You gain 2d4 + 4 Temporary Hit Points.","level":1,"higher_level":"You gain 5 additional Temporary Hit Points for each spell slot level above 1.","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a drop of alcohol","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"2d4 + 4","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_fear', 'Fear', 'Illusion', 3, true, false, '{"key":"srd-2024_fear","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Illusion","key":"illusion"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Fear","desc":"Each creature in a 30-foot Cone must succeed on a Wisdom saving throw or drop whatever it is holding and have the Frightened condition for the duration. A Frightened creature takes the Dash action and moves away from you by the safest route on each of its turns unless there is nowhere to move. If the creature ends its turn in a space where it doesn''t have line of sight to you, the creature makes a Wisdom saving throw. On a successful save, the spell ends on that creature.","level":3,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a white feather","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":"cone","shape_size":30,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_feather-fall', 'Feather Fall', 'Transmutation', 1, false, false, '{"key":"srd-2024_feather-fall","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Feather Fall","desc":"Choose up to five falling creatures within range. A falling creature''s rate of descent slows to 60 feet per round until the spell ends. If a creature lands before the spell ends, the creature takes no damage from the fall, and the spell ends for that creature.","level":1,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"reaction","reaction_condition":"which you take when you or a creature you can see within 60 feet of you falls","verbal":true,"somatic":false,"material":true,"material_specified":"a small feather or piece of down","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_find-familiar', 'Find Familiar', 'Conjuration', 1, false, true, '{"key":"srd-2024_find-familiar","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Find Familiar","desc":"You gain the service of a familiar, a spirit that takes an animal form you choose: Bat, Cat, Frog, Hawk, Lizard, Octopus, Owl, Rat, Raven, Spider, Weasel, or another Beast that has a Challenge Rating of 0. Appearing in an unoccupied space within range, the familiar has the statistics of the chosen form (see \"Monsters\"), though it is a Celestial, Fey, or Fiend (your choice) instead of a Beast. Your familiar acts independently of you, but it obeys your commands.\n\n**_Telepathic Connection._** While your familiar is within 100 feet of you, you can communicate with it telepathically. Additionally, as a Bonus Action, you can see through the familiar''s eyes and hear what it hears until the start of your next turn, gaining the benefits of any special senses it has.\n\nFinally, when you cast a spell with a range of touch, your familiar can deliver the touch. Your familiar must be within 100 feet of you, and it must take a Reaction to deliver the touch when you cast the spell.\n\n**_Combat._** The familiar is an ally to you and your allies. It rolls its own Initiative and acts on its own turn. A familiar can''t attack, but it can take other actions as normal.\n\n**_Disappearance of the Familiar._** When the familiar drops to 0 Hit Points, it disappears. It reappears after you cast this spell again. As a Magic action, you can temporarily dismiss the familiar to a pocket dimension. Alternatively, you can dismiss it forever. As a Magic action while it is temporarily dismissed, you can cause it to reappear in an unoccupied space within 30 feet of you. Whenever the familiar drops to 0 Hit Points or disappears into the pocket dimension, it leaves behind in its space anything it was wearing or carrying.\n\n**_One Familiar Only._** You can''t have more than one familiar at a time. If you cast this spell while you have a familiar, you instead cause it to adopt a new eligible form.","level":1,"higher_level":"","target_type":"creature","range_text":"10 feet","range":10,"ritual":true,"casting_time":"1hour","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"burning incense worth 10+ GP, which the spell consumes","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_find-steed', 'Find Steed', 'Conjuration', 2, false, false, '{"key":"srd-2024_find-steed","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_3","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"summoned creature uses level 3 stat block"},{"type":"slot_level_4","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"summoned creature uses level 4 stat block"},{"type":"slot_level_5","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"summoned creature uses level 5 stat block"},{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"summoned creature uses level 6 stat block"},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"summoned creature uses level 7 stat block"},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"summoned creature uses level 8 stat block"},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"summoned creature uses level 9 stat block"}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Paladin","key":"srd-2024_paladin"}],"range_unit":"feet","shape_size_unit":"feet","name":"Find Steed","desc":"You summon an otherworldly being that appears as a loyal steed in an unoccupied space of your choice within range. This creature uses the Otherworldly Steed stat block. If you already have a steed from this spell, the steed is replaced by the new one.\n\nThe steed resembles a Large, rideable animal of your choice, such as a horse, a camel, a dire wolf, or an elk. Whenever you cast the spell, choose the steed''s creature type—Celestial, Fey, or Fiend which determines certain traits in the stat block.\n\n**_Combat._** The steed is an ally to you and your allies. In combat, it shares your Initiative count, and it functions as a controlled mount while you ride it (as defined in the rules on mounted combat). If you have the Incapacitated condition, the steed takes its turn immediately after yours and acts independently, focusing on protecting you.\n\n**_Disappearance of the Steed._** The steed disappears if it drops to 0 Hit Points or if you die. When it disappears, it leaves behind anything it was wearing or carrying. If you cast this spell again, you decide whether you summon the steed that disappeared or a different one.","level":2,"higher_level":"Use the spell slot''s level for the spell''s level in the stat block.","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_find-the-path', 'Find the Path', 'Divination', 6, true, false, '{"key":"srd-2024_find-the-path","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Find the Path","desc":"You magically sense the most direct physical route to a location you name. You must be familiar with the location, and the spell fails if you name a destination on another plane of existence, a moving destination (such as a mobile fortress), or an unspecific destination (such as \"a green dragon''s lair\"). For the duration, as long as you are on the same plane of existence as the destination, you know how far it is and in what direction it lies. Whenever you face a choice of paths along the way there, you know which path is the most direct.","level":6,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a set of divination tools—such as cards or runes—worth 100+ GP","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 day","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_find-traps', 'Find Traps', 'Divination', 2, false, false, '{"key":"srd-2024_find-traps","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Find Traps","desc":"You sense any trap within range that is within line of sight. A trap, for the purpose of this spell, includes any object or mechanism that was created to cause damage or other danger. Thus, the spell would sense the Alarm or Glyph of Warding spell or a mechanical pit trap, but it wouldn''t reveal a natural weakness in the floor, an unstable ceiling, or a hidden sinkhole. This spell reveals that a trap is present but not its location. You do learn the general nature of the danger posed by a trap you sense.","level":2,"higher_level":"","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_finger-of-death', 'Finger of Death', 'Necromancy', 7, false, false, '{"key":"srd-2024_finger-of-death","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Finger of Death","desc":"You unleash negative energy toward a creature you can see within range. The target makes a Constitution saving throw, taking 7d8 + 30 Necrotic damage on a failed save or half as much damage on a successful one. A Humanoid killed by this spell rises at the start of your next turn as a Zombie (see \"Monsters\") that follows your verbal orders.","level":7,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"7d8 + 30","damage_types":["necrotic"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_fire-bolt', 'Fire Bolt', 'Evocation', 0, false, false, '{"key":"srd-2024_fire-bolt","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"player_level_5","damage_roll":"2d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"player_level_11","damage_roll":"3d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"player_level_17","damage_roll":"4d10","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Fire Bolt","desc":"You hurl a mote of fire at a creature or an object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 Fire damage. A flammable object hit by this spell starts burning if it isn''t being worn or carried.","level":0,"higher_level":"The damage increases by 1d10 when you reach levels 5 (2d10), 11 (3d10), and 17 (4d10).","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"1d10","damage_types":["fire"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_fire-shield', 'Fire Shield', 'Evocation', 4, false, false, '{"key":"srd-2024_fire-shield","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Fire Shield","desc":"Wispy flames wreathe your body for the duration, shedding Bright Light in a 10-foot radius and Dim Light for an additional 10 feet. The flames provide you with a warm shield or a chill shield, as you choose. The warm shield grants you Resistance to Cold damage, and the chill shield grants you Resistance to Fire damage. In addition, whenever a creature within 5 feet of you hits you with a melee attack roll, the shield erupts with flame. The attacker takes 2d8 Fire damage from a warm shield or 2d8 Cold damage from a chill shield.","level":4,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a bit of phosphorus or a firefly","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"2d8","damage_types":["fire","cold"],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_fire-storm', 'Fire Storm', 'Evocation', 7, false, false, '{"key":"srd-2024_fire-storm","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"}],"range_unit":"feet","shape_size_unit":"feet","name":"Fire Storm","desc":"A storm of fire appears within range. The area of the storm consists of up to ten 10-foot Cubes, which you arrange as you like. Each Cube must be contiguous with at least one other Cube. Each creature in the area makes a Dexterity saving throw, taking 7d10 Fire damage on a failed save or half as much damage on a successful one. Flammable objects in the area that aren''t being worn or carried start burning.","level":7,"higher_level":"","target_type":"creature","range_text":"150 feet","range":150,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"7d10","damage_types":["fire"],"duration":"instantaneous","shape_type":"cube","shape_size":10,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_fireball', 'Fireball', 'Evocation', 3, false, false, '{"key":"srd-2024_fireball","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_4","damage_roll":"9d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"10d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"11d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"12d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"13d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"14d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Fireball","desc":"A bright streak flashes from you to a point you choose within range and then blossoms with a low roar into a fiery explosion. Each creature in a 20-foot-radius Sphere centered on that point makes a Dexterity saving throw, taking 8d6 Fire damage on a failed save or half as much damage on a successful one. Flammable objects in the area that aren''t being worn or carried start burning.","level":3,"higher_level":"The damage increases by 1d6 for each spell slot level above 3.","target_type":"creature","range_text":"150 feet","range":150,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a ball of bat guano and sulfur","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"8d6","damage_types":["fire"],"duration":"instantaneous","shape_type":"sphere","shape_size":20,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_flame-blade', 'Flame Blade', 'Evocation', 2, true, false, '{"key":"srd-2024_flame-blade","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_3","damage_roll":"4d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":"5d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"6d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"7d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"8d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"9d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"10d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"}],"range_unit":"feet","shape_size_unit":"feet","name":"Flame Blade","desc":"You evoke a fiery blade in your free hand. The blade is similar in size and shape to a scimitar, and it lasts for the duration. If you let go of the blade, it disappears, but you can evoke it again as a Bonus Action. As a Magic action, you can make a melee spell attack with the fiery blade. On a hit, the target takes Fire damage equal to 3d6 plus your spellcasting ability modifier. The flaming blade sheds Bright Light in a 10-foot radius and Dim Light for an additional 10 feet.","level":2,"higher_level":"The damage increases by 1d6 for each spell slot level above 2.","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"bonus-action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a sumac leaf","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"3d6","damage_types":["fire"],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_flame-strike', 'Flame Strike', 'Evocation', 5, false, false, '{"key":"srd-2024_flame-strike","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_6","damage_roll":"6d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"7d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"8d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"9d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Flame Strike","desc":"A vertical column of brilliant fire roars down from above. Each creature in a 10-foot-radius, 40-foothigh Cylinder centered on a point within range makes a Dexterity saving throw, taking 5d6 Fire damage and 5d6 Radiant damage on a failed save or half as much damage on a successful one.","level":5,"higher_level":"The Fire damage and the Radiant damage increase by 1d6 for each spell slot level above 5.","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a pinch of sulfur","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"5d6","damage_types":["fire","radiant"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_flaming-sphere', 'Flaming Sphere', 'Conjuration', 2, true, false, '{"key":"srd-2024_flaming-sphere","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_3","damage_roll":"3d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":"4d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"5d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"6d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"7d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"8d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"9d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Flaming Sphere","desc":"You create a 5-foot-diameter sphere of fire in an unoccupied space on the ground within range. It lasts for the duration. Any creature that ends its turn within 5 feet of the sphere makes a Dexterity saving throw, taking 2d6 Fire damage on a failed save or half as much damage on a successful one. As a Bonus Action, you can move the sphere up to 30 feet, rolling it along the ground. If you move the sphere into a creature''s space, that creature makes the save against the sphere, and the sphere stops moving for the turn. When you move the sphere, you can direct it over barriers up to 5 feet tall and jump it across pits up to 10 feet wide. Flammable objects that aren''t being worn or carried start burning if touched by the sphere, and it sheds Bright Light in a 20-foot radius and Dim Light for an additional 20 feet.","level":2,"higher_level":"The damage increases by 1d6 for each spell slot level above 2.","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a ball of wax","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"2d6","damage_types":["fire"],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_flesh-to-stone', 'Flesh to Stone', 'Transmutation', 6, true, false, '{"key":"srd-2024_flesh-to-stone","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Flesh to Stone","desc":"You attempt to turn one creature that you can see within range into stone. The target makes a Constitution saving throw. On a failed save, it has the Restrained condition for the duration. On a successful save, its Speed is 0 until the start of your next turn. Constructs automatically succeed on the save. A Restrained target makes another Constitution saving throw at the end of each of its turns. If it successfully saves against this spell three times, the spell ends. If it fails its saves three times, it is turned to stone and has the Petrified condition for the duration. The successes and failures needn''t be consecutive; keep track of both until the target collects three of a kind. If you maintain your Concentration on this spell for the entire possible duration, the target is Petrified until the condition is ended by Greater Restoration or similar magic.","level":6,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a cockatrice feather","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_floating-disk', 'Floating Disk', 'Conjuration', 1, false, true, '{"key":"srd-2024_floating-disk","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Floating Disk","desc":"This spell creates a circular, horizontal plane of force, 3 feet in diameter and 1 inch thick, that floats 3 feet above the ground in an unoccupied space of your choice that you can see within range. The disk remains for the duration and can hold up to 500 pounds. If more weight is placed on it, the spell ends, and everything on the disk falls to the ground. The disk is immobile while you are within 20 feet of it. If you move more than 20 feet away from it, the disk follows you so that it remains within 20 feet of you. It can move across uneven terrain, up or down stairs, slopes and the like, but it can''t cross an elevation change of 10 feet or more. For example, the disk can''t move across a 10-foot-deep pit, nor could it leave such a pit if it was created at the bottom. If you move more than 100 feet from the disk (typically because it can''t move around an obstacle to follow you), the spell ends.","level":1,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":true,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a drop of mercury","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_fly', 'Fly', 'Transmutation', 3, true, false, '{"key":"srd-2024_fly","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_4","damage_roll":null,"target_count":2,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":4,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":5,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":6,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":7,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Fly","desc":"You touch a willing creature. For the duration, the target gains a Fly Speed of 60 feet and can hover. When the spell ends, the target falls if it is still aloft unless it can stop the fall.","level":3,"higher_level":"You can target one additional creature for each spell slot level above 3.","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a feather","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_fog-cloud', 'Fog Cloud', 'Conjuration', 1, true, false, '{"key":"srd-2024_fog-cloud","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":40,"desc":null},{"type":"slot_level_3","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":60,"desc":null},{"type":"slot_level_4","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":80,"desc":null},{"type":"slot_level_5","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":100,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":120,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":140,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":160,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":180,"desc":null}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Fog Cloud","desc":"You create a 20-foot-radius Sphere of fog centered on a point within range. The Sphere is Heavily Obscured. It lasts for the duration or until a strong wind (such as one created by Gust of Wind) disperses it.","level":1,"higher_level":"The fog''s radius increases by 20 feet for each spell slot level above 1.","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":"sphere","shape_size":20,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_forbiddance', 'Forbiddance', 'Abjuration', 6, false, true, '{"key":"srd-2024_forbiddance","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Forbiddance","desc":"You create a ward against magical travel that protects up to 40,000 square feet of floor space to a height of 30 feet above the floor. For the duration, creatures can''t teleport into the area or use portals, such as those created by the Gate spell, to enter the area. The spell proofs the area against planar travel, and therefore prevents creatures from accessing the area by way of the Astral Plane, the Ethereal Plane, the Feywild, the Shadowfell, or the Plane Shift spell. In addition, the spell damages types of creatures that you choose when you cast it. Choose one or more of the following: Aberrations, Celestials, Elementals, Fey, Fiends, and Undead. When a creature of a chosen type enters the spell''s area for the first time on a turn or ends its turn there, the creature takes 5d10 Radiant or Necrotic damage (your choice when you cast this spell). You can designate a password when you cast the spell. A creature that speaks the password as it enters the area takes no damage from the spell. The spell''s area can''t overlap with the area of another Forbiddance spell. If you cast Forbiddance every day for 30 days in the same location, the spell lasts until it is dispelled, and the Material components are consumed on the last casting.","level":6,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":true,"casting_time":"10minutes","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"ruby dust worth 1,000+ GP","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"5d10","damage_types":["necrotic"],"duration":"1 day","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_forcecage', 'Forcecage', 'Evocation', 7, true, false, '{"key":"srd-2024_forcecage","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Forcecage","desc":"An immobile, Invisible, Cube-shaped prison composed of magical force springs into existence around an area you choose within range. The prison can be a cage or a solid box, as you choose.\n\nA prison in the shape of a cage can be up to 20 feet on a side and is made from 1/2-inch diameter bars spaced 1/2 inch apart. A prison in the shape of a box can be up to 10 feet on a side, creating a solid barrier that prevents any matter from passing through it and blocking any spells cast into or out from the area.\n\nWhen you cast the spell, any creature that is completely inside the cage''s area is trapped. Creatures only partially within the area, or those too large to fit inside it, are pushed away from the center of the area until they are completely outside it.\n\nA creature inside the cage can''t leave it by nonmagical means. If the creature tries to use teleportation or interplanar travel to leave, it must first make a Charisma saving throw. On a successful save, the creature can use that magic to exit the cage. On a failed save, the creature doesn''t exit the cage and wastes the spell or effect. The cage also extends into the Ethereal Plane, blocking ethereal travel.\n\nThis spell can''t be dispelled by Dispel Magic.","level":7,"higher_level":"","target_type":"creature","range_text":"100 feet","range":100,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"ruby dust worth 1,500+ GP, which the spell consumes","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"charisma","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_foresight', 'Foresight', 'Divination', 9, false, false, '{"key":"srd-2024_foresight","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Foresight","desc":"You touch a willing creature and bestow a limited ability to see into the immediate future. For the duration, the target has Advantage on D20 Tests, and other creatures have Disadvantage on attack rolls against it. The spell ends early if you cast it again.","level":9,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a hummingbird feather","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"","damage_types":[],"duration":"8 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_freedom-of-movement', 'Freedom of Movement', 'Abjuration', 4, false, false, '{"key":"srd-2024_freedom-of-movement","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_5","damage_roll":null,"target_count":2,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":4,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":5,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":6,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Freedom of Movement","desc":"You touch a willing creature. For the duration, the target''s movement is unaffected by Difficult Terrain, and spells and other magical effects can neither reduce the target''s Speed nor cause the target to have the Paralyzed or Restrained conditions. The target also has a Swim Speed equal to its Speed.\n\nIn addition, the target can spend 5 feet of movement to automatically escape from nonmagical restraints, such as manacles or a creature imposing the Grappled condition on it.","level":4,"higher_level":"You can target one additional creature for each spell slot level above 4.","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a leather strap","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"10d6","damage_types":["cold"],"duration":"1 hour","shape_type":"sphere","shape_size":60,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_freezing-sphere', 'Freezing Sphere', 'Evocation', 6, false, false, '{"key":"srd-2024_freezing-sphere","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_7","damage_roll":"11d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"The damage increases to 11d6."},{"type":"slot_level_8","damage_roll":"12d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"The damage increases to 12d6."},{"type":"slot_level_9","damage_roll":"13d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"The damage increases to 13d6."}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Freezing Sphere","desc":"A frigid globe streaks from you to a point of your choice within range, where it explodes in a 60-foot-radius Sphere. Each creature in that area makes a Constitution saving throw, taking 10d6 Cold damage on failed save or half as much damage on a successful one.\n\nIf the globe strikes a body of water, it freezes the water to a depth of 6 inches over an area 30 feet square. This ice lasts for 1 minute. Creatures that were swimming on the surface of frozen water are trapped in the ice and have the Restrained condition. A trapped creature can take an action to make a Strength (Athletics) check against your spell save DC to break free.\n\nYou can refrain from firing the globe after completing the spell''s casting. If you do so, a globe about the size of a sling bullet, cool to the touch, appears in your hand. At any time, you or a creature you give the globe to can throw the globe (to a range of 40 feet) or hurl it with a sling (to the sling''s normal range). It shatters on impact, with the same effect as a normal casting of the spell. You can also set the globe down without shattering it. After 1 minute, if the globe hasn''t already shattered, it explodes.","level":6,"higher_level":"The damage increases by 1d6 for each spell slot level above 6.","target_type":"point","range_text":"300 feet","range":300,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a miniature crystal sphere","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"10d6","damage_types":["cold"],"duration":"instantaneous","shape_type":"sphere","shape_size":60,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_gaseous-form', 'Gaseous Form', 'Transmutation', 3, true, false, '{"key":"srd-2024_gaseous-form","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_4","damage_roll":null,"target_count":2,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":null,"target_count":3,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":null,"target_count":4,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":null,"target_count":5,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":6,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":null,"target_count":7,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Gaseous Form","desc":"A willing creature you touch shape-shifts, along with everything it''s wearing and carrying, into a misty cloud for the duration. The spell ends on the target if it drops to 0 Hit Points or if it takes a Magic action to end the spell on itself. While in this form, the target''s only method of movement is a Fly Speed of 10 feet, and it can hover. The target can enter and occupy the space of another creature. The target has Resistance to Bludgeoning, Piercing, and Slashing damage; it has Immunity to the Prone condition; and it has Advantage on Strength, Dexterity, and Constitution saving throws. The target can pass through narrow openings, but it treats liquids as though they were solid surfaces. The target can''t talk or manipulate objects, and any objects it was carrying or holding can''t be dropped, used, or otherwise interacted with. Finally, the target can''t attack or cast spells.","level":3,"higher_level":"You can target one additional creature for each spell slot level above 3.","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a bit of gauze","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"","damage_types":["slashing"],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_gate', 'Gate', 'Conjuration', 9, true, false, '{"key":"srd-2024_gate","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Gate","desc":"You conjure a portal linking an unoccupied space you can see within range to a precise location on a different plane of existence. The portal is a circular opening, which you can make 5 to 20 feet in diameter. You can orient the portal in any direction you choose. The portal lasts for the duration, and the portal''s destination is visible through it. The portal has a front and a back on each plane where it appears. Travel through the portal is possible only by moving through its front. Anything that does so is instantly transported to the other plane, appearing in the unoccupied space nearest to the portal. Deities and other planar rulers can prevent portals created by this spell from opening in their presence or anywhere within their domains. When you cast this spell, you can speak the name of a specific creature (a pseudonym, title, or nickname doesn''t work). If that creature is on a plane other than the one you are on, the portal opens next to the named creature and transports it to the nearest unoccupied space on your side of the portal. You gain no special power over the creature, and it is free to act as the GM deems appropriate. It might leave, attack you, or help you.","level":9,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a diamond worth 5,000+ GP","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_geas', 'Geas', 'Enchantment', 5, false, false, '{"key":"srd-2024_geas","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":"365 days","range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":"365 days","range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Paladin","key":"srd-2024_paladin"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Geas","desc":"You give a verbal command to a creature that you can see within range, ordering it to carry out some service or refrain from an action or a course of activity as you decide. The target must succeed on a Wisdom saving throw or have the Charmed condition for the duration. The target automatically succeeds if it can''t understand your command. While Charmed, the creature takes 5d10 Psychic damage if it acts in a manner directly counter to your command. It takes this damage no more than once each day. You can issue any command you choose, short of an activity that would result in certain death. Should you issue a suicidal command, the spell ends. A Remove Curse, Greater Restoration, or Wish spell ends this spell.","level":5,"higher_level":"If you use a level 7 or 8 spell slot, the duration is 365 days. If you use a level 9 spell slot, the spell lasts until it is ended by one of the spells mentioned above.","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"wisdom","attack_roll":false,"damage_roll":"5d10","damage_types":["psychic"],"duration":"30 days","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_gentle-repose', 'Gentle Repose', 'Necromancy', 2, false, true, '{"key":"srd-2024_gentle-repose","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Paladin","key":"srd-2024_paladin"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Gentle Repose","desc":"You touch a corpse or other remains. For the duration, the target is protected from decay and can''t become Undead. The spell also effectively extends the time limit on raising the target from the dead, since days spent under the influence of this spell don''t count against the time limit of spells such as Raise Dead.","level":2,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":true,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"2 Copper Pieces, which the spell consumes","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 days","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_giant-insect', 'Giant Insect', 'Conjuration', 4, true, false, '{"key":"srd-2024_giant-insect","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_5","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"summoned creature uses level 5 stat block"},{"type":"slot_level_6","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"summoned creature uses level 6 stat block"},{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"summoned creature uses level 7 stat block"},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"summoned creature uses level 8 stat block"},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"summoned creature uses level 9 stat block"}],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Giant Insect","desc":"You summon a giant centipede, spider, or wasp (chosen when you cast the spell). It manifests in an unoccupied space you can see within range and uses the Giant Insect stat block. The form you choose determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends. The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don''t issue any, it takes the Dodge action and uses its movement to avoid danger.","level":4,"higher_level":"Use the spell slot''s level for the spell''s level in the stat block.","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"10 minutes","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_glibness', 'Glibness', 'Enchantment', 8, false, false, '{"key":"srd-2024_glibness","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Enchantment","key":"enchantment"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Warlock","key":"srd-2024_warlock"}],"range_unit":"feet","shape_size_unit":"feet","name":"Glibness","desc":"Until the spell ends, when you make a Charisma check, you can replace the number you roll with a 15. Additionally, no matter what you say, magic that would determine if you are telling the truth indicates that you are being truthful.","level":8,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 hour","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_globe-of-invulnerability', 'Globe of Invulnerability', 'Abjuration', 6, true, false, '{"key":"srd-2024_globe-of-invulnerability","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"blocks spells of 5th level or lower"},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"blocks spells of 6th level or lower"},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"blocks spells of 7th level or lower"}],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Globe of Invulnerability","desc":"An immobile, shimmering barrier appears in a 10 foot Emanation around you and remains for the duration. Any spell of level 5 or lower cast from outside the barrier can''t affect anything within it. Such a spell can target creatures and objects within the barrier, but the spell has no effect on them. Similarly, the area within the barrier is excluded from areas of effect created by such spells.","level":6,"higher_level":"The barrier blocks spells of 1 level higher for each spell slot level above 6.","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a glass bead","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_glyph-of-warding', 'Glyph of Warding', 'Abjuration', 3, false, false, '{"key":"srd-2024_glyph-of-warding","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_4","damage_roll":"6d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Explosive rune deals 6d8 damage. Spell glyph can store up to level 4 spell."},{"type":"slot_level_5","damage_roll":"7d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Explosive rune deals 7d8 damage. Spell glyph can store up to level 5 spell."},{"type":"slot_level_6","damage_roll":"8d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Explosive rune deals 8d8 damage. Spell glyph can store up to level 6 spell."},{"type":"slot_level_7","damage_roll":"9d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Explosive rune deals 9d8 damage. Spell glyph can store up to level 7 spell."},{"type":"slot_level_8","damage_roll":"10d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Explosive rune deals 10d8 damage. Spell glyph can store up to level 8 spell."},{"type":"slot_level_9","damage_roll":"11d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"Explosive rune deals 11d8 damage. Spell glyph can store up to level 9 spell."}],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Glyph of Warding","desc":"You inscribe a glyph that later unleashes a magical effect. You inscribe it either on a surface (such as a table or a section of floor) or within an object that can be closed (such as a book or chest) to conceal the glyph. The glyph can cover an area no larger than 10 feet in diameter. If the surface or object is moved more than 10 feet from where you cast this spell, the glyph is broken, and the spell ends without being triggered.\n\nThe glyph is nearly imperceptible and requires a successful Wisdom (Perception) check against your spell save DC to notice.\n\nWhen you inscribe the glyph, you set its trigger and choose whether it''s an explosive rune or a spell glyph, as explained below.\n\n**_Set the Trigger._** You decide what triggers the glyph when you cast the spell. For glyphs inscribed on a surface, common triggers include touching or stepping on the glyph, removing another object covering it, or approaching within a certain distance of it. For glyphs inscribed within an object, common triggers include opening that object or seeing the glyph. Once a glyph is triggered, this spell ends.\n\nYou can refine the trigger so that only creatures of certain types activate it (for example, the glyph could be set to affect Aberrations). You can also set conditions for creatures that don''t trigger the glyph, such as those who say a certain password.\n\n**_Explosive Rune._** When triggered, the glyph erupts with magical energy in a 20-foot-radius Sphere centered on the glyph. Each creature in the area makes a Dexterity saving throw. A creature takes 5d8 Acid, Cold, Fire, Lightning, or Thunder damage (your choice when you create the glyph) on a failed save or half as much damage on a successful one.\n\n**_Spell Glyph._** You can store a prepared spell of level 3 or lower in the glyph by casting it as part of creating the glyph. The spell must target a single creature or an area. The spell being stored has no immediate effect when cast in this way.\n\nWhen the glyph is triggered, the stored spell takes effect. If the spell has a target, it targets the creature that triggered the glyph. If the spell affects an area, the area is centered on that creature. If the spell summons Hostile creatures or creates harmful objects or traps, they appear as close as possible to the intruder and attack it. If the spell requires Concentration, it lasts until the end of its full duration.","level":3,"higher_level":"The damage of an explosive rune increases by 1d8 for each spell slot level above 3. If you create a spell glyph, you can store any spell of up to the same level as the spell slot you use for the Glyph of Warding.","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"1hour","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"powdered diamond worth 200+ GP, which the spell consumes","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"until dispelled or triggered","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_goodberry', 'Goodberry', 'Conjuration', 1, false, false, '{"key":"srd-2024_goodberry","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Goodberry","desc":"Ten berries appear in your hand and are infused with magic for the duration. A creature can take a Bonus Action to eat one berry. Eating a berry restores 1 Hit Point, and the berry provides enough nourishment to sustain a creature for one day. Uneaten berries disappear when the spell ends.","level":1,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a sprig of mistletoe","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"24 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_grease', 'Grease', 'Conjuration', 1, false, false, '{"key":"srd-2024_grease","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Grease","desc":"Nonflammable grease covers the ground in a 10 foot square centered on a point within range and turns it into Difficult Terrain for the duration. When the grease appears, each creature standing in its area must succeed on a Dexterity saving throw or have the Prone condition. A creature that enters the area or ends its turn there must also succeed on that save or fall Prone.","level":1,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a bit of pork rind or butter","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_greater-invisibility', 'Greater Invisibility', 'Illusion', 4, true, false, '{"key":"srd-2024_greater-invisibility","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Illusion","key":"illusion"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Greater Invisibility","desc":"","level":4,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_greater-restoration', 'Greater Restoration', 'Abjuration', 5, false, false, '{"key":"srd-2024_greater-restoration","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Paladin","key":"srd-2024_paladin"},{"name":"Ranger","key":"srd-2024_ranger"}],"range_unit":"feet","shape_size_unit":"feet","name":"Greater Restoration","desc":"You touch a creature and magically remove one of the following effects from it:\n\n- 1 Exhaustion level\n- The Charmed or Petrified condition\n- A curse, including the target''s Attunement to a cursed magic item\n- Any reduction to one of the target''s ability scores\n- Any reduction to the target''s Hit Point maximum","level":5,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"diamond dust worth 100+ GP, which the spell consumes","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_guardian-of-faith', 'Guardian of Faith', 'Conjuration', 4, false, false, '{"key":"srd-2024_guardian-of-faith","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Guardian of Faith","desc":"A Large spectral guardian appears and hovers for the duration in an unoccupied space that you can see within range. The guardian occupies that space and is invulnerable, and it appears in a form appropriate for your deity or pantheon. Any enemy that moves to a space within 10 feet of the guardian for the first time on a turn or starts its turn there makes a Dexterity saving throw, taking 20 Radiant damage on a failed save or half as much damage on a successful one. The guardian vanishes when it has dealt a total of 60 damage.","level":4,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"","damage_types":["radiant"],"duration":"8 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_guards-and-wards', 'Guards and Wards', 'Abjuration', 6, false, false, '{"key":"srd-2024_guards-and-wards","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Guards and Wards","desc":"You create a ward that protects up to 2,500 square feet of floor space. The warded area can be up to 20 feet tall, and you shape it as one 50-foot square, one hundred 5-foot squares that are contiguous, or twenty-five 10-foot squares that are contiguous.\n\nWhen you cast this spell, you can specify individuals that are unaffected by the spell''s effects. You can also specify a password that, when spoken aloud within 5 feet of the warded area, makes the speaker immune to its effects.\n\nThe spell creates the effects below within the warded area. Dispel Magic has no effect on Guards and Wards itself, but each of the following effects can be dispelled. If all four are dispelled, Guards and Wards ends. If you cast the spell every day for 365 days on the same area, the spell thereafter lasts until all its effects are dispelled.\n\n**_Corridors._** Fog fills all the warded corridors, making them Heavily Obscured. In addition, at each intersection or branching passage offering a choice of direction, there is a 50 percent chance that a creature other than you believes it is going in the opposite direction from the one it chooses.\n\n**_Doors._** All doors in the warded area are magically locked, as if sealed by the *Arcane Lock* spell. In addition, you can cover up to ten doors with an illusion to make them appear as plain sections of wall.\n\n**_Stairs._** Webs fill all stairs in the warded area from top to bottom, as in the *Web* spell. These strands regrow in 10 minutes if they are destroyed while *Guards and Wards* lasts.\n\n**_Other Spell Effect._** Place one of the following magical effects within the warded area:\n\n- *Dancing Lights* in four corridors, with a simple program that the lights repeat as long as Guards and Wards lasts\n- *Magic Mouth* in two locations\n- *Stinking Cloud* in two locations (the vapors return within 10 minutes if dispersed while Guards and Wards lasts) - Gust of Wind in one corridor or room (the wind blows continuously while the spell lasts)\n- *Suggestion* in one 5-foot square; any creature that enters that square receives the suggestion mentally","level":6,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"1hour","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a silver rod worth 10+ GP","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"24 hours","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_guidance', 'Guidance', 'Divination', 0, true, false, '{"key":"srd-2024_guidance","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Divination","key":"divination"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Guidance","desc":"You touch a willing creature and choose a skill. Until the spell ends, the creature adds 1d4 to any ability check using the chosen skill.","level":0,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"1d4","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_guiding-bolt', 'Guiding Bolt', 'Evocation', 1, false, false, '{"key":"srd-2024_guiding-bolt","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":"5d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_3","damage_roll":"6d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":"7d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"8d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"9d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"10d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"11d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"12d6","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Guiding Bolt","desc":"You hurl a bolt of light toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 4d6 Radiant damage, and the next attack roll made against it before the end of your next turn has Advantage.","level":1,"higher_level":"The damage increases by 1d6 for each spell slot level above 1.","target_type":"creature","range_text":"120 feet","range":120,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"4d6","damage_types":["radiant"],"duration":"1 round","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_gust-of-wind', 'Gust of Wind', 'Evocation', 2, true, false, '{"key":"srd-2024_gust-of-wind","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Evocation","key":"evocation"},"classes":[{"name":"Druid","key":"srd-2024_druid"},{"name":"Ranger","key":"srd-2024_ranger"},{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Gust of Wind","desc":"A Line of strong wind 60 feet long and 10 feet wide blasts from you in a direction you choose for the duration. Each creature in the Line must succeed on a Strength saving throw or be pushed 15 feet away from you in a direction following the Line. A creature that ends its turn in the Line must make the same save. Any creature in the Line must spend 2 feet of movement for every 1 foot it moves when moving closer to you. The gust disperses gas or vapor, and it extinguishes candles and similar unprotected flames in the area. It causes protected flames, such as those of lanterns, to dance wildly and has a 50 percent chance to extinguish them. As a Bonus Action on your later turns, you can change the direction in which the Line blasts from you.","level":2,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a legume seed","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"strength","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_hallow', 'Hallow', 'Abjuration', 5, false, false, '{"key":"srd-2024_hallow","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Hallow","desc":"You touch a point and infuse an area around it with holy or unholy power. The area can have a radius up to 60 feet, and the spell fails if the radius includes an area already under the effect of Hallow. The affected area has the following effects.\n\n**_Hallowed Ward._** Choose any of these creature types: Aberration, Celestial, Elemental, Fey, Fiend, or Undead. Creatures of the chosen types can''t willingly enter the area, and any creature that is possessed by or that has the Charmed or Frightened condition from such creatures isn''t possessed, Charmed, or Frightened by them while in the area.\n\n**_Extra Effect._** You bind an extra effect to the area from the list below:\n\n- **_Courage._** Creatures of any types you choose can''t gain the Frightened condition while in the area.\n- **_Darkness._** Darkness fills the area. Normal light, as well as magical light created by spells of a level lower than this spell, can''t illuminate the area.\n - **_Daylight._** Bright light fills the area. Magical Darkness created by spells of a level lower than this spell can''t extinguish the light.\n- **_Peaceful Rest._** Dead bodies interred in the area can''t be turned into Undead.\n- **_Extradimensional Interference._** Creatures of any types you choose can''t enter or exit the area using teleportation or interplanar travel.\n- **_Fear._** Creatures of any types you choose have the Frightened condition while in the area.\n- **_Silence._** No sound can emanate from within the area, and no sound can reach into it.\n- **_Tongues._** Creatures of any types you choose can communicate with any other creature in the area even if they don''t share a common language.\n- **_Vulnerability._** Creatures of any types you choose have Vulnerability to one damage type of your choice while in the area.","level":5,"higher_level":"","target_type":"creature","range_text":"Touch","range":0,"ritual":false,"casting_time":"1hour","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"incense worth 1,000+ GP, which the spell consumes","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"until dispelled","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_hallucinatory-terrain', 'Hallucinatory Terrain', 'Illusion', 4, false, false, '{"key":"srd-2024_hallucinatory-terrain","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Illusion","key":"illusion"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"},{"name":"Warlock","key":"srd-2024_warlock"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Hallucinatory Terrain","desc":"You make natural terrain in a 150-foot Cube in range look, sound, and smell like another sort of natural terrain. Thus, open fields or a road can be made to resemble a swamp, hill, crevasse, or some other difficult or impassable terrain. A pond can be made to seem like a grassy meadow, a precipice like a gentle slope, or a rock-strewn gully like a wide and smooth road. Manufactured structures, equipment, and creatures within the area aren''t changed. The tactile characteristics of the terrain are unchanged, so creatures entering the area are likely to notice the illusion. If the difference isn''t obvious by touch, a creature examining the illusion can take the Study action to make an Intelligence (Investigation) check against your spell save DC to disbelieve it. If a creature discerns that the terrain is illusory, the creature sees a vague image superimposed on the real terrain.","level":4,"higher_level":"","target_type":"creature","range_text":"300 feet","range":300,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a mushroom","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"24 hours","shape_type":"cube","shape_size":150,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_harm', 'Harm', 'Necromancy', 6, false, false, '{"key":"srd-2024_harm","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Necromancy","key":"necromancy"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Harm","desc":"You unleash virulent magic on a creature you can see within range. The target makes a Constitution saving throw. On a failed save, it takes 14d6 Necrotic damage, and its Hit Point maximum is reduced by an amount equal to the Necrotic damage it took. On a successful save, it takes half as much damage only. This spell can''t reduce a target''s Hit Point maximum below 1.","level":6,"higher_level":"","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":false,"damage_roll":"14d6","damage_types":["necrotic"],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_haste', 'Haste', 'Transmutation', 3, true, false, '{"key":"srd-2024_haste","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Sorcerer","key":"srd-2024_sorcerer"},{"name":"Wizard","key":"srd-2024_wizard"}],"range_unit":"feet","shape_size_unit":"feet","name":"Haste","desc":"Choose a willing creature that you can see within range. Until the spell ends, the target''s Speed is doubled, it gains a +2 bonus to Armor Class, it has Advantage on Dexterity saving throws, and it gains an additional action on each of its turns. That action can be used to take only the Attack (one attack only), Dash, Disengage, Hide, or Utilize action. When the spell ends, the target is Incapacitated and has a Speed of 0 until the end of its next turn, as a wave of lethargy washes over it.","level":3,"higher_level":"","target_type":"creature","range_text":"30 feet","range":30,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a shaving of licorice root","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"dexterity","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_heal', 'Heal', 'Abjuration', 6, false, false, '{"key":"srd-2024_heal","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_7","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"The target regains 80 Hit Points."},{"type":"slot_level_8","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"The target regains 90 Hit Points."},{"type":"slot_level_9","damage_roll":null,"target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":"The target regains 100 Hit Points."}],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Heal","desc":"Choose a creature that you can see within range. Positive energy washes through the target, restoring 70 Hit Points. This spell also ends the Blinded, Deafened, and Poisoned conditions on the target.","level":6,"higher_level":"The healing increases by 10 for each spell slot level above 6.","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_healing-word', 'Healing Word', 'Abjuration', 1, false, false, '{"key":"srd-2024_healing-word","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_2","damage_roll":"4d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_3","damage_roll":"6d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":"8d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"10d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"12d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"14d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"16d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"18d4","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Healing Word","desc":"A creature of your choice that you can see within range regains Hit Points equal to 2d4 plus your spellcasting ability modifier.","level":1,"higher_level":"The healing increases by 2d4 for each spell slot level above 1.","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"bonus-action","reaction_condition":null,"verbal":true,"somatic":false,"material":false,"material_specified":"","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"2d4","damage_types":[],"duration":"instantaneous","shape_type":null,"shape_size":null,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_heat-metal', 'Heat Metal', 'Transmutation', 2, true, false, '{"key":"srd-2024_heat-metal","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[{"type":"slot_level_3","damage_roll":"3d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_4","damage_roll":"4d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_5","damage_roll":"5d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_6","damage_roll":"6d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_7","damage_roll":"7d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_8","damage_roll":"8d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null},{"type":"slot_level_9","damage_roll":"9d8","target_count":null,"duration":null,"range":null,"concentration":null,"shape_size":null,"desc":null}],"school":{"name":"Transmutation","key":"transmutation"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Heat Metal","desc":"Choose a manufactured metal object, such as a metal weapon or a suit of Heavy or Medium metal armor, that you can see within range. You cause the object to glow red-hot. Any creature in physical contact with the object takes 2d8 Fire damage when you cast the spell. Until the spell ends, you can take a Bonus Action on each of your later turns to deal this damage again if the object is within range. If a creature is holding or wearing the object and takes the damage from it, the creature must succeed on a Constitution saving throw or drop the object if it can. If it doesn''t drop the object, it has Disadvantage on attack rolls and ability checks until the start of your next turn.","level":2,"higher_level":"The damage increases by 1d8 for each spell slot level above 2.","target_type":"creature","range_text":"60 feet","range":60,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a piece of iron and a flame","material_cost":null,"material_consumed":false,"target_count":1,"saving_throw_ability":"constitution","attack_roll":true,"damage_roll":"2d8","damage_types":["fire"],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
