  ('srd-2024_heroes-feast', 'Heroes'' Feast', 'Conjuration', 6, false, false, '{"key":"srd-2024_heroes-feast","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Conjuration","key":"conjuration"},"classes":[{"name":"Bard","key":"srd-2024_bard"},{"name":"Cleric","key":"srd-2024_cleric"},{"name":"Druid","key":"srd-2024_druid"}],"range_unit":"feet","shape_size_unit":"feet","name":"Heroes'' Feast","desc":"You conjure a feast that appears on a surface in an unoccupied 10-foot Cube next to you. The feast takes 1 hour to consume and disappears at the end of that time, and the beneficial effects don''t set in until this hour is over. Up to twelve creatures can partake of the feast. A creature that partakes gains several benefits, which last for 24 hours. The creature has Resistance to Poison damage, and it has Immunity to the Frightened and Poisoned conditions. Its Hit Point maximum also increases by 2d10, and it gains the same number of Hit Points.","level":6,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"1minute","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a gem-encrusted bowl worth 1,000+ GP, which the spell consumes","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":false,"damage_roll":"2d10","damage_types":["poison"],"duration":"instantaneous","shape_type":"cube","shape_size":10,"concentration":false,"crossreferences":{"to":[]}}'::jsonb),
