  ('srd-2024_holy-aura', 'Holy Aura', 'Abjuration', 8, true, false, '{"key":"srd-2024_holy-aura","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"casting_options":[],"school":{"name":"Abjuration","key":"abjuration"},"classes":[{"name":"Cleric","key":"srd-2024_cleric"}],"range_unit":"feet","shape_size_unit":"feet","name":"Holy Aura","desc":"For the duration, you emit an aura in a 30-foot Emanation. While in the aura, creatures of your choice have Advantage on all saving throws, and other creatures have Disadvantage on attack rolls against them. In addition, when a Fiend or an Undead hits an affected creature with a melee attack roll, the attacker must succeed on a Constitution saving throw or have the Blinded condition until the end of its next turn.","level":8,"higher_level":"","target_type":"creature","range_text":"Self","range":0,"ritual":false,"casting_time":"action","reaction_condition":null,"verbal":true,"somatic":true,"material":true,"material_specified":"a reliquary worth 1,000+ GP","material_cost":null,"material_consumed":true,"target_count":1,"saving_throw_ability":"","attack_roll":true,"damage_roll":"","damage_types":[],"duration":"1 minute","shape_type":null,"shape_size":null,"concentration":true,"crossreferences":{"to":[]}}'::jsonb),
