  ('srd-2024_bard_slots-9th', 'srd-2024_bard', '9th', 'SPELL_SLOTS', '[]'::jsonb, '[{"level":17,"column_value":"1"},{"level":18,"column_value":"1"},{"level":19,"column_value":"1"},{"level":20,"column_value":"1"}]'::jsonb, '{"key":"srd-2024_bard_slots-9th","name":"9th","desc":"[Column data]","feature_type":"SPELL_SLOTS","gained_at":[],"data_for_class_table":[{"level":17,"column_value":"1"},{"level":18,"column_value":"1"},{"level":19,"column_value":"1"},{"level":20,"column_value":"1"}]}'::jsonb),
  ('srd-2024_bard_spellcasting', 'srd-2024_bard', 'Spellcasting', 'CLASS_LEVEL_FEATURE', '[{"level":1,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_bard_spellcasting","name":"Spellcasting","desc":"You have learned to cast spells through your bardic arts. See \"Spells\" for the rules on spellcasting. The information below details how you use those rules with Bard spells, which appear in the Bard spell list later in the class''s description.\n\n**Cantrips.** You know two cantrips of your choice from the Bard spell list. *Dancing Lights* and *Vicious Mockery* are recommended.\n\nWhenever you gain a Bard level, you can replace one of your cantrips with another cantrip of your choice from the Bard spell list.\n\nWhen you reach Bard levels 4 and 10, you learn another cantrip of your choice from the Bard spell list, as shown in the Cantrips column of the Bard Features table.\n\n**Spell Slots.** The Bard Features table shows how many spell slots you have to cast your level 1+ spells. You regain all expended slots when you finish a Long Rest.\n\n**Prepared Spells of Level 1+.** You prepare the list of level 1+ spells that are available for you to cast with this feature. To start, choose four level 1 spells from the Bard spell list. *Charm Person*, *Color Spray*, *Dissonant Whispers*, and *Healing Word* are recommended.\n\nThe number of spells on your list increases as you gain Bard levels, as shown in the Prepared Spells column of the Bard Features table. Whenever that number increases, choose additional spells from the Bard spell list until the number of spells on your list matches the number on the table. The chosen spells must be of a level for which you have spell slots. For example, if you''re a level 3 Bard, your list of prepared spells can include six spells of levels 1 and 2 in any combination.\n\nIf another Bard feature gives you spells that you always have prepared, those spells don''t count against the number of spells you can prepare with this feature, but those spells otherwise count as Bard spells for you.\n\n**Changing Your Prepared Spells.** Whenever you gain a Bard level, you can replace one spell on your list with another Bard spell for which you have spell slots.\n\n**Spellcasting Ability.** Charisma is your spellcasting ability for your Bard spells.\n\n**Spellcasting Focus.** You can use a Musical Instrument as a Spellcasting Focus for your Bard spells.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":1,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_bard_superior-inspiration', 'srd-2024_bard', 'Superior Inspiration', 'CLASS_LEVEL_FEATURE', '[{"level":18,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_bard_superior-inspiration","name":"Superior Inspiration","desc":"When you roll Initiative, you regain expended uses of Bardic Inspiration until you have two if you have fewer than that.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":18,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_bard_words-of-creation', 'srd-2024_bard', 'Words of Creation', 'CLASS_LEVEL_FEATURE', '[{"level":20,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_bard_words-of-creation","name":"Words of Creation","desc":"You have mastered two of the Words of Creation: the words of life and death. You therefore always have the *Power Word Heal* and *Power Word Kill* spells prepared. When you cast either spell, you can target a second creature with it if that creature is within 10 feet of the first target.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":20,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_fighter_champion_additional-fighting-style', 'srd-2024_champion', 'Additional Fighting Style', 'CLASS_LEVEL_FEATURE', '[{"level":7,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_fighter_champion_additional-fighting-style","name":"Additional Fighting Style","desc":"You gain another Fighting Style feat of your choice.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":7,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_fighter_champion_heroic-warrior', 'srd-2024_champion', 'Heroic Warrior', 'CLASS_LEVEL_FEATURE', '[{"level":10,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_fighter_champion_heroic-warrior","name":"Heroic Warrior","desc":"The thrill of battle drives you toward victory. During combat, you can give yourself Heroic Inspiration whenever you start your turn without it.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":10,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_fighter_champion_improved-critical', 'srd-2024_champion', 'Improved Critical', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_fighter_champion_improved-critical","name":"Improved Critical","desc":"Your attack rolls with weapons and Unarmed Strikes can score a Critical Hit on a roll of 19 or 20 on the d20.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_fighter_champion_remarkable-athlete', 'srd-2024_champion', 'Remarkable Athlete', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_fighter_champion_remarkable-athlete","name":"Remarkable Athlete","desc":"Thanks to your athleticism, you have Advantage on Initiative rolls and Strength (Athletics) checks.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_fighter_champion_superior-critical', 'srd-2024_champion', 'Superior Critical', 'CLASS_LEVEL_FEATURE', '[{"level":15,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_fighter_champion_superior-critical","name":"Superior Critical","desc":"Your attack rolls with weapons and Unarmed Strikes can now score a Critical Hit on a roll of 18–20 on the d20.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":15,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_fighter_champion_survivor', 'srd-2024_champion', 'Survivor', 'CLASS_LEVEL_FEATURE', '[{"level":18,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_fighter_champion_survivor","name":"Survivor","desc":"You attain the pinnacle of resilience in battle, giving you these benefits.\n\n**Defy Death**. You have Advantage on Death Saving Throws. Moreover, when you roll 18–20 on a Death Saving Throw, you gain the benefit of rolling a 20 on it.\n\n**Heroic Rally**. At the start of each of your turns, you regain Hit Points equal to 5 plus your Constitution modifier if you are Bloodied and have at least 1 Hit Point.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":18,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_circle-of-the-land_spell-list', 'srd-2024_circle-of-the-land', 'Circle of the Land Spells', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_circle-of-the-land_spell-list","name":"Circle of the Land Spells","desc":"Whenever you finish a Long Rest, choose one type of land: arid, polar, temperate, or tropical. Consult the table below that corresponds to the chosen type; you have the spells listed for your Druid level and lower prepared.\n\nTable: Arid Land\n\n|Druid Level|Circle Spells|\n|---|---|\n|3|Blur, Burning Hands, Fire Bolt|\n|5|Fireball|\n|7|Blight|\n|9|Wall of Stone|\n\nTable: Polar Land\n|Druid Level|Circle Spells|\n|---|---|\n|3|Fog Cloud, Hold Person, Ray of Frost|\n|5|Sleet Storm|\n|7|Ice Storm|\n|9|Cone of Cold|\n\nTable: Temperate Land\n|Druid Level|Circle Spells|\n|---|---|\n|3|Misty Step, Shocking Grasp, Sleep|\n|5|Lightning Bolt|\n|7|Freedom of Movement|\n|9|Tree Stride|\n\nTable: Tropical Land\n|Druid Level|Circle Spells|\n|---|---|\n|3|Acid Splash, Ray of Sickness, Web|\n|5|Stinking Cloud|\n|7|Polymorph|\n|9|Insect Plague|","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_circle-of-the-land_lands-aid', 'srd-2024_circle-of-the-land', 'Land''s Aid', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_circle-of-the-land_lands-aid","name":"Land''s Aid","desc":"As a Magic action, you can expend a use of your Wild Shape and choose a point within 60 feet of yourself. Vitality-giving flowers and life-draining thorns appear for a moment in a 10-foot-radius Sphere centered on that point. Each creature of your choice in the Sphere must make a Constitution saving throw against your spell save DC, taking 2d6 Necrotic damage on a failed save or half as much damage on a successful one. One creature of your choice in that area regains 2d6 Hit Points.\n\nThe damage and healing increase by 1d6 when you reach Druid levels 10 (3d6) and 14 (4d6).","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_circle-of-the-land_natural-recovery', 'srd-2024_circle-of-the-land', 'Natural Recovery', 'CLASS_LEVEL_FEATURE', '[{"level":6,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_circle-of-the-land_natural-recovery","name":"Natural Recovery","desc":"You can cast one of the level 1+ spells that you have prepared from your Circle Spells feature without expending a spell slot, and you must finish a Long Rest before you do so again.\n\nIn addition, when you finish a Short Rest, you can choose expended spell slots to recover. The spell slots can have a combined level that is equal to or less than half your Druid level (round up), and none of them can be level 6+. For example, if you''re a level 6 Druid, you can recover up to three levels'' worth of spell slots. You can recover a level 3 spell slot, a level 2 and a level 1 spell slot, or three level 1 spell slots. Once you recover spell slots with this feature, you can''t do so again until you finish a Long Rest.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":6,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_circle-of-the-land_natures-sanctuary', 'srd-2024_circle-of-the-land', 'Nature''s Sanctuary', 'CLASS_LEVEL_FEATURE', '[{"level":14,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_circle-of-the-land_natures-sanctuary","name":"Nature''s Sanctuary","desc":"You can cast one of the level 1+ spells that you have prepared from your Circle Spells feature without expending a spell slot, and you must finish a Long Rest before you do so again.\n\nIn addition, when you finish a Short Rest, you can choose expended spell slots to recover. The spell slots can have a combined level that is equal to or less than half your Druid level (round up), and none of them can be level 6+. For example, if you''re a level 6 Druid, you can recover up to three levels'' worth of spell slots. You can recover a level 3 spell slot, a level 2 and a level 1 spell slot, or three level 1 spell slots. Once you recover spell slots with this feature, you can''t do so again until you finish a Long Rest.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":14,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_circle-of-the-land_natures-ward', 'srd-2024_circle-of-the-land', 'Nature''s Ward', 'CLASS_LEVEL_FEATURE', '[{"level":10,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_circle-of-the-land_natures-ward","name":"Nature''s Ward","desc":"As a Magic action, you can expend a use of your Wild Shape and cause spectral trees and vines to appear in a 15-foot Cube on the ground within 120 feet of yourself. They last there for 1 minute or until you have the Incapacitated condition or die. You and your allies have Half Cover while in that area, and your allies gain the current Resistance of your Nature''s Ward while there.\n\nAs a Bonus Action, you can move the Cube up to 60 feet to ground within 120 feet of yourself.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":10,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_cleric_ability-score-improvement', 'srd-2024_cleric', 'Ability Score Improvement', 'CLASS_LEVEL_FEATURE', '[{"level":12,"detail":null},{"level":16,"detail":null},{"level":4,"detail":null},{"level":8,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_ability-score-improvement","name":"Ability Score Improvement","desc":"You gain the Ability Score Improvement feat (see \"Feats\") or another feat of your choice for which you qualify. You gain this feature again at Cleric levels 8, 12, and 16.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":12,"detail":null},{"level":16,"detail":null},{"level":4,"detail":null},{"level":8,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_cleric_blessed-strikes', 'srd-2024_cleric', 'Blessed Strikes', 'CLASS_LEVEL_FEATURE', '[{"level":7,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_blessed-strikes","name":"Blessed Strikes","desc":"Divine power infuses you in battle. You gain one of the following options of your choice (if you get either option from a Cleric subclass in an older book, use only the option you choose for this feature).\n\n**Divine Strike.** Once on each of your turns when you hit a creature with an attack roll using a weapon, you can cause the target to take an extra 1d8 Necrotic or Radiant damage (your choice).\n\n**Potent Spellcasting.** Add your Wisdom modifier to the damage you deal with any Cleric cantrip.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":7,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_cleric_cantrips', 'srd-2024_cleric', 'Cantrips', 'CLASS_TABLE_DATA', '[]'::jsonb, '[{"level":1,"column_value":"3"},{"level":10,"column_value":"5"},{"level":11,"column_value":"5"},{"level":12,"column_value":"5"},{"level":13,"column_value":"5"},{"level":14,"column_value":"5"},{"level":15,"column_value":"5"},{"level":16,"column_value":"5"},{"level":17,"column_value":"5"},{"level":18,"column_value":"5"},{"level":19,"column_value":"5"},{"level":2,"column_value":"3"},{"level":20,"column_value":"5"},{"level":3,"column_value":"3"},{"level":4,"column_value":"4"},{"level":5,"column_value":"4"},{"level":6,"column_value":"4"},{"level":7,"column_value":"4"},{"level":8,"column_value":"4"},{"level":9,"column_value":"4"}]'::jsonb, '{"key":"srd-2024_cleric_cantrips","name":"Cantrips","desc":"[Column data]","feature_type":"CLASS_TABLE_DATA","gained_at":[],"data_for_class_table":[{"level":1,"column_value":"3"},{"level":10,"column_value":"5"},{"level":11,"column_value":"5"},{"level":12,"column_value":"5"},{"level":13,"column_value":"5"},{"level":14,"column_value":"5"},{"level":15,"column_value":"5"},{"level":16,"column_value":"5"},{"level":17,"column_value":"5"},{"level":18,"column_value":"5"},{"level":19,"column_value":"5"},{"level":2,"column_value":"3"},{"level":20,"column_value":"5"},{"level":3,"column_value":"3"},{"level":4,"column_value":"4"},{"level":5,"column_value":"4"},{"level":6,"column_value":"4"},{"level":7,"column_value":"4"},{"level":8,"column_value":"4"},{"level":9,"column_value":"4"}]}'::jsonb),
  ('srd-2024_cleric_channel-divinity', 'srd-2024_cleric', 'Channel Divinity', 'CLASS_LEVEL_FEATURE', '[{"level":2,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_channel-divinity","name":"Channel Divinity","desc":"You can channel divine energy directly from the Outer Planes to fuel magical effects. You start with two such effects: Divine Spark and Turn Undead, each of which is described below. Each time you use this class''s Channel Divinity, choose which Channel Divinity effect from this class to create. You gain additional effect options at higher Cleric levels.\n\nYou can use this class''s Channel Divinity twice. You regain one of its expended uses when you finish a Short Rest, and you regain all expended uses when you finish a Long Rest. You gain additional uses when you reach certain Cleric levels, as shown in the Channel Divinity column of the Cleric Features table.\n\nIf a Channel Divinity effect requires a saving throw, the DC equals the spell save DC from this class''s Spellcasting feature.\n\n**Divine Spark.** As a Magic action, you point your Holy Symbol at another creature you can see within 30 feet of yourself and focus divine energy at it. Roll 1d8 and add your Wisdom modifier. You either restore Hit Points to the creature equal to that total or force the creature to make a Constitution saving throw. On a failed save, the creature takes Necrotic or Radiant damage (your choice) equal to that total. On a successful save, the creature takes half as much damage (round down).\n\nYou roll an additional d8 when you reach Cleric levels 7 (2d8), 13 (3d8), and 18 (4d8).\n\n**Turn Undead.** As a Magic action, you present your Holy Symbol and censure Undead creatures. Each Undead of your choice within 30 feet of you must make a Wisdom saving throw. If the creature fails its save, it has the Frightened and Incapacitated conditions for 1 minute. For that duration, it tries to move as far from you as it can on its turns. This effect ends early on the creature if it takes any damage, if you have the Incapacitated condition, or if you die.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":2,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_cleric_channel-divinity-uses', 'srd-2024_cleric', 'Channel Divinity', 'CLASS_TABLE_DATA', '[]'::jsonb, '[{"level":10,"column_value":"3"},{"level":11,"column_value":"3"},{"level":12,"column_value":"3"},{"level":13,"column_value":"3"},{"level":14,"column_value":"3"},{"level":15,"column_value":"3"},{"level":16,"column_value":"3"},{"level":17,"column_value":"3"},{"level":18,"column_value":"4"},{"level":19,"column_value":"4"},{"level":2,"column_value":"2"},{"level":20,"column_value":"4"},{"level":3,"column_value":"2"},{"level":4,"column_value":"2"},{"level":5,"column_value":"2"},{"level":6,"column_value":"3"},{"level":7,"column_value":"3"},{"level":8,"column_value":"3"},{"level":9,"column_value":"3"}]'::jsonb, '{"key":"srd-2024_cleric_channel-divinity-uses","name":"Channel Divinity","desc":"[Column data]","feature_type":"CLASS_TABLE_DATA","gained_at":[],"data_for_class_table":[{"level":10,"column_value":"3"},{"level":11,"column_value":"3"},{"level":12,"column_value":"3"},{"level":13,"column_value":"3"},{"level":14,"column_value":"3"},{"level":15,"column_value":"3"},{"level":16,"column_value":"3"},{"level":17,"column_value":"3"},{"level":18,"column_value":"4"},{"level":19,"column_value":"4"},{"level":2,"column_value":"2"},{"level":20,"column_value":"4"},{"level":3,"column_value":"2"},{"level":4,"column_value":"2"},{"level":5,"column_value":"2"},{"level":6,"column_value":"3"},{"level":7,"column_value":"3"},{"level":8,"column_value":"3"},{"level":9,"column_value":"3"}]}'::jsonb),
  ('srd-2024_cleric_cleric-spell-list', 'srd-2024_cleric', 'Cleric Spell List', 'CLASS_LEVEL_FEATURE', '[]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_cleric-spell-list","name":"Cleric Spell List","desc":"This section presents the Cleric spell list. The spells are organized by spell level and then alphabetized, and each spell''s school of magic is listed. In the Special column, *C* means the spell requires Concentration, *R* means it''s a Ritual, and *M* means it requires a specific Material component.\n\nTable: Cantrips (Level 0 Cleric Spells)\n\n|Spell|School|Special|\n|---|---|---|\n|Guidance|Divination|C|\n|Light|Evocation|—|\n|Mending|Transmutation|—|\n|Resistance|Abjuration|C|\n|Sacred Flame|Evocation|—|\n|Spare the Dying|Necromancy|—|\n|Thaumaturgy|Transmutation|—|\n\nTable: Level 1 Cleric Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Bane|Enchantment|C|\n|Bless|Enchantment|C, M|\n|Command|Enchantment|—|\n|Create or Destroy Water|Transmutation|—|\n|Cure Wounds|Abjuration|—|\n|Detect Evil and Good|Divination|C|\n|Detect Magic|Divination|C, R|\n|Detect Poison and Disease|Divination|C, R|\n|Guiding Bolt|Evocation|—|\n|Healing Word|Abjuration|—|\n|Inflict Wounds|Necromancy|—|\n|Protection from Evil and Good|Abjuration|C, M|\n|Purify Food and Drink|Transmutation|R|\n|Sanctuary|Abjuration|—|\n|Shield of Faith|Abjuration|C|\n\nTable: Level 2 Cleric Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Aid|Abjuration|—|\n|Augury|Divination|R, M|\n|Blindness/Deafness|Transmutation|—|\n|Calm Emotions|Enchantment|C|\n|Continual Flame|Evocation|M|\n|Enhance Ability|Transmutation|C|\n|Find Traps|Divination|—|\n|Gentle Repose|Necromancy|R, M|\n|Hold Person|Enchantment|C|\n|Lesser Restoration|Abjuration|—|\n|Locate Object|Divination|C|\n|Prayer of Healing|Abjuration|—|\n|Protection from Poison|Abjuration|—|\n|Silence|Illusion|C, R|\n|Spiritual Weapon|Evocation|C|\n|Warding Bond|Abjuration|M|\n|Zone of Truth|Enchantment|—|\n\nTable: Level 3 Cleric Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Animate Dead|Necromancy|—|\n|Beacon of Hope|Abjuration|C|\n|Bestow Curse|Necromancy|C|\n|Clairvoyance|Divination|C, M|\n|Create Food and Water|Conjuration|—|\n|Daylight|Evocation|—|\n|Dispel Magic|Abjuration|—|\n|Glyph of Warding|Abjuration|M|\n|Magic Circle|Abjuration|M|\n|Mass Healing Word|Abjuration|—|\n|Meld into Stone|Transmutation|R|\n|Protection from Energy|Abjuration|C|\n|Remove Curse|Abjuration|—|\n|Revivify|Necromancy|M|\n|Sending|Divination|—|\n|Speak with Dead|Necromancy|—|\n|Spirit Guardians|Conjuration|C|\n|Tongues|Divination|—|\n|Water Walk|Transmutation|R|\n\n#### Level 4 Cleric Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Aura of Life|Abjuration|C|\n|Banishment|Abjuration|C|\n|Control Water|Transmutation|C|\n|Death Ward|Abjuration|—|\n|Divination|Divination|R, M|\n|Freedom of Movement|Abjuration|—|\n|Guardian of Faith|Conjuration|—|\n|Locate Creature|Divination|C|\n|Stone Shape|Transmutation|—|\n\n#### Level 5 Cleric Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Commune|Divination|R|\n|Contagion|Necromancy|—|\n|Dispel Evil and Good|Abjuration|C|\n|Flame Strike|Evocation|—|\n|Geas|Enchantment|—|\n|Greater Restoration|Abjuration|M|\n|Hallow|Abjuration|M|\n|Insect Plague|Conjuration|C|\n|Legend Lore|Divination|M|\n|Mass Cure Wounds|Abjuration|—|\n|Planar Binding|Abjuration|M|\n|Raise Dead|Necromancy|M|\n|Scrying|Divination|C, M|\n\n#### Level 6 Cleric Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Blade Barrier|Evocation|C|\n|Create Undead|Necromancy|M|\n|Find the Path|Divination|C, M|\n|Forbiddance|Abjuration|R, M|\n|Harm|Necromancy|—|\n|Heal|Abjuration|—|\n|Heroes'' Feast|Conjuration|M|\n|Planar Ally|Conjuration|—|\n|Sunbeam|Evocation|C|\n|True Seeing|Divination|M|\n|Word of Recall|Conjuration|—|\n\n#### Level 7 Cleric Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Conjure Celestial|Conjuration|C|\n|Divine Word|Evocation|—|\n|Etherealness|Conjuration|—|\n|Fire Storm|Evocation|—|\n|Plane Shift|Conjuration|M|\n|Regenerate|Transmutation|—|\n|Resurrection|Necromancy|M|\n|Symbol|Abjuration|M|\n\n#### Level 8 Cleric Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Antimagic Field|Abjuration|C|\n|Control Weather|Transmutation|C|\n|Earthquake|Transmutation|C|\n|Holy Aura|Abjuration|C, M|\n|Sunburst|Evocation|—|\n\n#### Level 9 Cleric Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Astral Projection|Necromancy|M|\n|Gate|Conjuration|C, M|\n|Mass Heal|Abjuration|—|\n|Power Word Heal|Enchantment|—|\n|True Resurrection|Necromancy|M|","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_cleric_cleric-subclasses', 'srd-2024_cleric', 'Cleric Subclasses', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_cleric-subclasses","name":"Cleric Subclasses","desc":"You gain a Cleric subclass of your choice. The Life Domain subclass is detailed after this class''s description. A subclass is a specialization that grants you features at certain Cleric levels. For the rest of your career, you gain each of your subclass''s features that are of your Cleric level or lower.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_cleric_core-traits', 'srd-2024_cleric', 'Cleric Subclasses', 'CORE_TRAITS_TABLE', '[]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_core-traits","name":"Cleric Subclasses","desc":"|||\n|---|---|\n|Primary Ability|Wisdom|\n|Hit Point Die|D8 per Cleric level|\n|Saving Throw Proficiencies|Wisdom and Charisma|\n|Skill Proficiencies|Choose 2: History, Insight, Medicine, Persuasion, or Religion|\n|Weapon Proficiencies|Simple weapons|\n|Armor Training|Light and Medium armor and Shields|\n|Starting Equipment|Choose A or B: (A) Chain Shirt, Shield, Mace, Holy Symbol, Priest''s Pack, and 7 GP; or (B) 110 GP|","feature_type":"CORE_TRAITS_TABLE","gained_at":[],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_cleric_divine-intervention', 'srd-2024_cleric', 'Divine Intervention', 'CLASS_LEVEL_FEATURE', '[{"level":10,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_divine-intervention","name":"Divine Intervention","desc":"You can call on your deity or pantheon to intervene on your behalf. As a Magic action, choose any Cleric spell of level 5 or lower that doesn''t require a Reaction to cast. As part of the same action, you cast that spell without expending a spell slot or needing Material components. You can''t use this feature again until you finish a Long Rest.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":10,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_cleric_divine-order', 'srd-2024_cleric', 'Divine Order', 'CLASS_LEVEL_FEATURE', '[{"level":1,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_divine-order","name":"Divine Order","desc":"You have dedicated yourself to one of the following sacred roles of your choice.\n\n**Protector.** Trained for battle, you gain proficiency with Martial weapons and training with Heavy armor.\n\n**Thaumaturge.** You know one extra cantrip from the Cleric spell list. In addition, your mystical connection to the divine gives you a bonus to your Intelligence (Arcana or Religion) checks. The bonus equals your Wisdom modifier (minimum of +1).","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":1,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_cleric_epic-boon', 'srd-2024_cleric', 'Epic Boon', 'CLASS_LEVEL_FEATURE', '[{"level":19,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_epic-boon","name":"Epic Boon","desc":"You gain an Epic Boon feat (see \"Feats\") or another feat of your choice for which you qualify. Boon of Fate is recommended.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":19,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_cleric_greater-divine-intervention', 'srd-2024_cleric', 'Greater Divine Intervention', 'CLASS_LEVEL_FEATURE', '[{"level":20,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_greater-divine-intervention","name":"Greater Divine Intervention","desc":"You can call on even more powerful divine intervention. When you use your Divine Intervention feature, you can choose *Wish* when you select a spell. If you do so, you can''t use Divine Intervention again until you finish 2d4 Long Rests.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":20,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_cleric_improved-blessed-strikes', 'srd-2024_cleric', 'Improved Blessed Strikes', 'CLASS_LEVEL_FEATURE', '[{"level":14,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_improved-blessed-strikes","name":"Improved Blessed Strikes","desc":"The option you chose for Blessed Strikes grows more powerful.\n\n**Divine Strike.** The extra damage of your Divine Strike increases to 2d8.\n\n**Potent Spellcasting.** When you cast a Cleric cantrip and deal damage to a creature with it, you can give vitality to yourself or another creature within 60 feet of yourself, granting a number of Temporary Hit Points equal to twice your Wisdom modifier.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":14,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_cleric_prepared-spells', 'srd-2024_cleric', 'Prepared Spells', 'CLASS_TABLE_DATA', '[]'::jsonb, '[{"level":1,"column_value":"4"},{"level":10,"column_value":"15"},{"level":11,"column_value":"16"},{"level":12,"column_value":"16"},{"level":13,"column_value":"17"},{"level":14,"column_value":"17"},{"level":15,"column_value":"18"},{"level":16,"column_value":"18"},{"level":17,"column_value":"19"},{"level":18,"column_value":"20"},{"level":19,"column_value":"21"},{"level":2,"column_value":"5"},{"level":20,"column_value":"22"},{"level":3,"column_value":"6"},{"level":4,"column_value":"7"},{"level":5,"column_value":"9"},{"level":6,"column_value":"10"},{"level":7,"column_value":"11"},{"level":8,"column_value":"12"},{"level":9,"column_value":"14"}]'::jsonb, '{"key":"srd-2024_cleric_prepared-spells","name":"Prepared Spells","desc":"[Column data]","feature_type":"CLASS_TABLE_DATA","gained_at":[],"data_for_class_table":[{"level":1,"column_value":"4"},{"level":10,"column_value":"15"},{"level":11,"column_value":"16"},{"level":12,"column_value":"16"},{"level":13,"column_value":"17"},{"level":14,"column_value":"17"},{"level":15,"column_value":"18"},{"level":16,"column_value":"18"},{"level":17,"column_value":"19"},{"level":18,"column_value":"20"},{"level":19,"column_value":"21"},{"level":2,"column_value":"5"},{"level":20,"column_value":"22"},{"level":3,"column_value":"6"},{"level":4,"column_value":"7"},{"level":5,"column_value":"9"},{"level":6,"column_value":"10"},{"level":7,"column_value":"11"},{"level":8,"column_value":"12"},{"level":9,"column_value":"14"}]}'::jsonb),
