  ('srd-2024_cleric_sear-undead', 'srd-2024_cleric', 'Sear Undead', 'CLASS_LEVEL_FEATURE', '[{"level":5,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_sear-undead","name":"Sear Undead","desc":"Whenever you use Turn Undead, you can roll a number of d8s equal to your Wisdom modifier (minimum of 1d8) and add the rolls together. Each Undead that fails its saving throw against that use of Turn Undead takes Radiant damage equal to the roll''s total. This damage doesn''t end the turn effect.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":5,"detail":null}],"data_for_class_table":[]}'::jsonb),
