  ('srd-2024_cleric_slots-9th', 'srd-2024_cleric', '9th', 'SPELL_SLOTS', '[]'::jsonb, '[{"level":17,"column_value":"1"},{"level":18,"column_value":"1"},{"level":19,"column_value":"1"},{"level":20,"column_value":"1"}]'::jsonb, '{"key":"srd-2024_cleric_slots-9th","name":"9th","desc":"[Column data]","feature_type":"SPELL_SLOTS","gained_at":[],"data_for_class_table":[{"level":17,"column_value":"1"},{"level":18,"column_value":"1"},{"level":19,"column_value":"1"},{"level":20,"column_value":"1"}]}'::jsonb),
  ('srd-2024_cleric_spellcasting', 'srd-2024_cleric', 'Spellcasting', 'CLASS_LEVEL_FEATURE', '[{"level":1,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_cleric_spellcasting","name":"Spellcasting","desc":"You have learned to cast spells through prayer and meditation. See \"Spells\" for the rules on spellcasting. The information below details how you use those rules with Cleric spells, which appear on the Cleric spell list later in the class''s description.\n\n**Cantrips.** You know three cantrips of your choice from the Cleric spell list. *Guidance*, *Sacred Flame*, and *Thaumaturgy* are recommended.\n\nWhenever you gain a Cleric level, you can replace one of your cantrips with another cantrip of your choice from the Cleric spell list.\n\nWhen you reach Cleric levels 4 and 10, you learn another cantrip of your choice from the Cleric spell list, as shown in the Cantrips column of the Cleric Features table.\n\n**Spell Slots.** The Cleric Features table shows how many spell slots you have to cast your level 1+ spells. You regain all expended slots when you finish a Long Rest.\n\n**Prepared Spells of Level 1+.** You prepare the list of level 1+ spells that are available for you to cast with this feature. To start, choose four level 1 spells from the Cleric spell list. *Bless*, *Cure Wounds*, *Guiding Bolt*, and *Shield of Faith* are recommended.\n\nThe number of spells on your list increases as you gain Cleric levels, as shown in the Prepared Spells column of the Cleric Features table. Whenever that number increases, choose additional spells from the Cleric spell list until the number of spells on your list matches the number on the table. The chosen spells must be of a level for which you have spell slots. For example, if you''re a level 3 Cleric, your list of prepared spells can include six spells of levels 1 and 2 in any combination.\n\nIf another Cleric feature gives you spells that you always have prepared, those spells don''t count against the number of spells you can prepare with this feature, but those spells otherwise count as Cleric spells for you.\n\n**Changing Your Prepared Spells.** Whenever you finish a Long Rest, you can change your list of prepared spells, replacing any of the spells there with other Cleric spells for which you have spell slots.\n\n**Spellcasting Ability.** Wisdom is your spellcasting ability for your Cleric spells.\n\n**Spellcasting Focus.** You can use a Holy Symbol as a Spellcasting Focus for your Cleric spells.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":1,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_college-of-lore_bonus-proficiencies', 'srd-2024_college-of-lore', 'Bonus Proficiencies', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_college-of-lore_bonus-proficiencies","name":"Bonus Proficiencies","desc":"You gain proficiency with three skills of your choice.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_college-of-lore_cutting-words', 'srd-2024_college-of-lore', 'Cutting Words', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_college-of-lore_cutting-words","name":"Cutting Words","desc":"You learn to use your wit to supernaturally distract, confuse, and otherwise sap the confidence and competence of others. When a creature that you can see within 60 feet of yourself makes a damage roll or succeeds on an ability check or attack roll, you can take a Reaction to expend one use of your Bardic Inspiration; roll your Bardic Inspiration die, and subtract the number rolled from the creature''s roll, reducing the damage or potentially turning the success into a failure.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_college-of-lore_magical-discoveries', 'srd-2024_college-of-lore', 'Magical Discoveries', 'CLASS_LEVEL_FEATURE', '[{"level":6,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_college-of-lore_magical-discoveries","name":"Magical Discoveries","desc":"You learn two spells of your choice. These spells can come from the Cleric, Druid, or Wizard spell list or any combination thereof (see a class''s section for its spell list). A spell you choose must be a cantrip or a spell for which you have spell slots, as shown in the Bard Features table.\n\nYou always have the chosen spells prepared, and whenever you gain a Bard level, you can replace one of the spells with another spell that meets these requirements.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":6,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_college-of-lore_peerless-skill', 'srd-2024_college-of-lore', 'Peerless Skill', 'CLASS_LEVEL_FEATURE', '[{"level":14,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_college-of-lore_peerless-skill","name":"Peerless Skill","desc":"When you make an ability check or attack roll and fail, you can expend one use of Bardic Inspiration; roll the Bardic Inspiration die, and add the number rolled to the d20, potentially turning a failure into a success. On a failure, the Bardic Inspiration isn''t expended.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":14,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_sorcerer_draconic-sorcery_draconic-resilience', 'srd-2024_draconic-sorcery', 'Draconic Resilience', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_sorcerer_draconic-sorcery_draconic-resilience","name":"Draconic Resilience","desc":"The magic in your body manifests physical traits of your draconic gift. Your Hit Point maximum increases by 3, and it increases by 1 whenever you gain another Sorcerer level.\n\nParts of you are also covered by dragon-like scales. While you aren''t wearing armor, your base Armor Class equals 10 plus your Dexterity and Charisma modifiers.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_sorcerer_draconic-sorcery_draconic-spells', 'srd-2024_draconic-sorcery', 'Draconic Spells', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_sorcerer_draconic-sorcery_draconic-spells","name":"Draconic Spells","desc":"When you reach a Sorcerer level specified in the Draconic Spells table, you thereafter always have the listed spells prepared.\n\nTable: Draconic Spells\n\n|Sorcerer Level|Spells|\n|---|---|\n|3|Alter Self, Chromatic Orb, Command, Dragon''s Breath|\n|5|Fear, Fly|\n|7|Arcane Eye, Charm Monster|\n|9|Legend Lore, Summon Dragon|","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_sorcerer_draconic-sorcery_dragon-companion', 'srd-2024_draconic-sorcery', 'Dragon Companion', 'CLASS_LEVEL_FEATURE', '[{"level":19,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_sorcerer_draconic-sorcery_dragon-companion","name":"Dragon Companion","desc":"You can cast *Summon Dragon* without a Material component. You can also cast it once without a spell slot, and you regain the ability to cast it in this way when you finish a Long Rest.\n\nWhenever you start casting the spell, you can modify it so that it doesn''t require Concentration. If you do so, the spell''s duration becomes 1 minute for that casting.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":19,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_sorcerer_draconic-sorcery_dragon-wings', 'srd-2024_draconic-sorcery', 'Dragon Wings', 'CLASS_LEVEL_FEATURE', '[{"level":14,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_sorcerer_draconic-sorcery_dragon-wings","name":"Dragon Wings","desc":"As a Bonus Action, you can cause draconic wings to appear on your back. The wings last for 1 hour or until you dismiss them (no action required). For the duration, you have a Fly Speed of 60 feet.\n\nOnce you use this feature, you can''t use it again until you finish a Long Rest unless you spend 3 Sorcery Points (no action required) to restore your use of it.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":14,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_sorcerer_draconic-sorcery_elemental-affinity', 'srd-2024_draconic-sorcery', 'Elemental Affinity', 'CLASS_LEVEL_FEATURE', '[{"level":6,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_sorcerer_draconic-sorcery_elemental-affinity","name":"Elemental Affinity","desc":"Your draconic magic has an affinity with a damage type associated with dragons. Choose one of those types: Acid, Cold, Fire, Lightning, or Poison.\n\nYou have Resistance to that damage type, and when you cast a spell that deals damage of that type, you can add your Charisma modifier to one damage roll of that spell.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":6,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_ability-score-improvement', 'srd-2024_druid', 'Ability Score Improvement', 'CLASS_LEVEL_FEATURE', '[{"level":12,"detail":null},{"level":16,"detail":null},{"level":4,"detail":null},{"level":8,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_ability-score-improvement","name":"Ability Score Improvement","desc":"You gain the Ability Score Improvement feat (see \"Feats\") or another feat of your choice for which you qualify. You gain this feature again at Druid levels 8, 12, and 16.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":12,"detail":null},{"level":16,"detail":null},{"level":4,"detail":null},{"level":8,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_archdruid', 'srd-2024_druid', 'Archdruid', 'CLASS_LEVEL_FEATURE', '[{"level":20,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_archdruid","name":"Archdruid","desc":"The vitality of nature constantly blooms within you, granting you the following benefits.\n\n**Evergreen Wild Shape.** Whenever you roll Initiative and have no uses of Wild Shape left, you regain one expended use of it.\n\n**Nature Magician.** You can convert uses of Wild Shape into a spell slot (no action required). Choose a number of your unexpended uses of Wild Shape and convert them into a single spell slot, with each use contributing 2 spell levels. For example, if you convert two uses of Wild Shape, you produce a level 4 spell slot. Once you use this benefit, you can''t do so again until you finish a Long Rest.\n\n**Longevity.** The primal magic that you wield causes you to age more slowly. For every ten years that pass, your body ages only one year.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":20,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_beast-spells', 'srd-2024_druid', 'Beast Spells', 'CLASS_LEVEL_FEATURE', '[{"level":18,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_beast-spells","name":"Beast Spells","desc":"While using Wild Shape, you can cast spells in Beast form, except for any spell that has a Material component with a cost specified or that consumes its Material component.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":18,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_cantrips', 'srd-2024_druid', 'Cantrips', 'CLASS_TABLE_DATA', '[]'::jsonb, '[{"level":1,"column_value":"2"},{"level":10,"column_value":"4"},{"level":11,"column_value":"4"},{"level":12,"column_value":"4"},{"level":13,"column_value":"4"},{"level":14,"column_value":"4"},{"level":15,"column_value":"4"},{"level":16,"column_value":"4"},{"level":17,"column_value":"4"},{"level":18,"column_value":"4"},{"level":19,"column_value":"4"},{"level":2,"column_value":"2"},{"level":20,"column_value":"4"},{"level":3,"column_value":"2"},{"level":4,"column_value":"3"},{"level":5,"column_value":"3"},{"level":6,"column_value":"3"},{"level":7,"column_value":"3"},{"level":8,"column_value":"3"},{"level":9,"column_value":"3"}]'::jsonb, '{"key":"srd-2024_druid_cantrips","name":"Cantrips","desc":"[Column data]","feature_type":"CLASS_TABLE_DATA","gained_at":[],"data_for_class_table":[{"level":1,"column_value":"2"},{"level":10,"column_value":"4"},{"level":11,"column_value":"4"},{"level":12,"column_value":"4"},{"level":13,"column_value":"4"},{"level":14,"column_value":"4"},{"level":15,"column_value":"4"},{"level":16,"column_value":"4"},{"level":17,"column_value":"4"},{"level":18,"column_value":"4"},{"level":19,"column_value":"4"},{"level":2,"column_value":"2"},{"level":20,"column_value":"4"},{"level":3,"column_value":"2"},{"level":4,"column_value":"3"},{"level":5,"column_value":"3"},{"level":6,"column_value":"3"},{"level":7,"column_value":"3"},{"level":8,"column_value":"3"},{"level":9,"column_value":"3"}]}'::jsonb),
  ('srd-2024_druid_core-traits', 'srd-2024_druid', 'Core Druid Traits', 'CORE_TRAITS_TABLE', '[]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_core-traits","name":"Core Druid Traits","desc":"|||\n|---|---|\n|Primary Ability|Wisdom|\n|Hit Point Die|D8 per Druid level|\n|Saving Throw Proficiencies|Intelligence and Wisdom|\n|Skill Proficiencies|Choose 2: Animal Handling, Arcana, Insight, Medicine, Na ture, Perception, Religion, or Survival|\n|Weapon Proficiencies|Simple weapons|\n|Tool Proficiencies|Herbalism Kit|\n|Armor Training|Light armor and Shields|\n|Starting Equipment|Choose A or B: (A) Leather Ar mor, Shield, Sickle, Druidic Focus (Quarterstaff), Explorer''s Pack, Herbalism Kit, and 9 GP; or (B) 50 GP|","feature_type":"CORE_TRAITS_TABLE","gained_at":[],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_druid-spell-list', 'srd-2024_druid', 'Druid Spell List', 'CLASS_LEVEL_FEATURE', '[]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_druid-spell-list","name":"Druid Spell List","desc":"This section presents the Druid spell list. The spells are organized by spell level and then alphabetized, and each spell''s school of magic is listed. In the Special column, *C* means the spell requires Concentration, *R* means it''s a Ritual, and *M* means it requires a specific Material component.\n\nTable: Cantrips (Level 0 Druid Spells)\n\n|School|Special|\n|---|---|\n|Transmutation|—|\n|Transmutation|—|\n|Divination|C|\n|Transmutation|—|\n|Transmutation|—|\n|Necromancy|—|\n|Conjuration|—|\n|Abjuration|C|\n|Transmutation|—|\n|Necromancy|—|\n|Evocation|—|\n|||\n\nTable: Level 1 Druid Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Animal Friendship|Enchantment|—|\n|Charm Person|Enchantment|—|\n|Create or Destroy Water|Transmutation|—|\n|Cure Wounds|Abjuration|—|\n|Detect Magic|Divination|C, R|\n|Detect Poison and Disease|Divination|C, R|\n|Entangle|Conjuration|C|\n|Faerie Fire|Evocation|C|\n|Fog Cloud|Conjuration|C|\n|Goodberry|Conjuration|—|\n|Healing Word|Abjuration|—|\n|Ice Knife|Conjuration|—|\n|Jump|Transmutation|—|\n|Longstrider|Transmutation|—|\n|Protection from Evil and Good|Abjuration|C, M|\n|Purify Food and Drink|Transmutation|R|\n|Speak with Animals|Divination|R|\n|Thunderwave|Evocation|—|\n\nTable: Level 2 Druid Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Aid|Abjuration|—|\n|Animal Messenger|Enchantment|R|\n|Augury|Divination|R, M|\n|Barkskin|Transmutation|—|\n|Continual Flame|Evocation|M|\n|Darkvision|Transmutation|—|\n|Enhance Ability|Transmutation|C|\n|Enlarge/Reduce|Transmutation|C|\n|Find Traps|Divination|—|\n|Flame Blade|Evocation|C|","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_druid-subclass', 'srd-2024_druid', 'Druid Subclass', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_druid-subclass","name":"Druid Subclass","desc":"You gain a Druid subclass of your choice. The Circle of the Land subclass is detailed after this class''s description. A subclass is a specialization that grants you features at certain Druid levels. For the rest of your career, you gain each of your subclass''s features that are of your Druid level or lower.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_druidic', 'srd-2024_druid', 'Druidic', 'CLASS_LEVEL_FEATURE', '[{"level":1,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_druidic","name":"Druidic","desc":"You know Druidic, the secret language of Druids. While learning this ancient tongue, you also unlocked the magic of communicating with animals; you always have the *Speak with Animals* spell prepared.\n\nYou can use Druidic to leave hidden messages. You and others who know Druidic automatically spot such a message. Others spot the message''s presence with a successful DC 15 Intelligence (Investigation) check but can''t decipher it without magic.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":1,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_elemental-fury', 'srd-2024_druid', 'Elemental Fury', 'CLASS_LEVEL_FEATURE', '[{"level":7,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_elemental-fury","name":"Elemental Fury","desc":"The might of the elements flows through you. You gain one of the following options of your choice.\n\n**Potent Spellcasting.** Add your Wisdom modifier to the damage you deal with any Druid cantrip.\n\n**Primal Strike.** Once on each of your turns when you hit a creature with an attack roll using a weapon or a Beast form''s attack in Wild Shape, you can cause the target to take an extra 1d8 Cold, Fire, Lightning, or Thunder damage (choose when you hit).","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":7,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_epic-boon', 'srd-2024_druid', 'Epic Boon', 'CLASS_LEVEL_FEATURE', '[{"level":19,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_epic-boon","name":"Epic Boon","desc":"You gain an Epic Boon feat (see \"Feats\") or another feat of your choice for which you qualify. Boon of Dimensional Travel is recommended.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":19,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_druid_improved-elemental-fury', 'srd-2024_druid', 'Improved Elemental Fury', 'CLASS_LEVEL_FEATURE', '[{"level":15,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_improved-elemental-fury","name":"Improved Elemental Fury","desc":"The option you chose for Elemental Fury grows more powerful, as detailed below.\n\n**Potent Spellcasting.** When you cast a Druid cantrip with a range of 10 feet or greater, the spell''s range increases by 300 feet.\n\n**Primal Strike.** The extra damage of your Primal Strike increases to 2d8.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":15,"detail":null}],"data_for_class_table":[]}'::jsonb),
