  ('srd-2024_druid_primal-order', 'srd-2024_druid', 'Primal Order', 'CLASS_LEVEL_FEATURE', '[{"level":1,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_druid_primal-order","name":"Primal Order","desc":"You have dedicated yourself to one of the following sacred roles of your choice.\n\n**Magician.** You know one extra cantrip from the Druid spell list. In addition, your mystical connection to nature gives you a bonus to your Intelligence (Arcana or Nature) checks. The bonus equals your Wisdom modifier (minimum bonus of +1).\n\n**Warden.** Trained for battle, you gain proficiency with Martial weapons and training with Medium armor.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":1,"detail":null}],"data_for_class_table":[]}'::jsonb),
