  ('srd-2024_paladin_proficiency-bonus', 'srd-2024_paladin', 'Proficiency Bonus', 'PROFICIENCY_BONUS', '[]'::jsonb, '[{"level":1,"column_value":"+2"},{"level":10,"column_value":"+4"},{"level":11,"column_value":"+4"},{"level":12,"column_value":"+4"},{"level":13,"column_value":"+5"},{"level":14,"column_value":"+5"},{"level":15,"column_value":"+5"},{"level":16,"column_value":"+5"},{"level":17,"column_value":"+6"},{"level":18,"column_value":"+6"},{"level":19,"column_value":"+6"},{"level":2,"column_value":"+2"},{"level":20,"column_value":"+6"},{"level":3,"column_value":"+2"},{"level":4,"column_value":"+2"},{"level":5,"column_value":"+3"},{"level":6,"column_value":"+3"},{"level":7,"column_value":"+3"},{"level":8,"column_value":"+3"},{"level":9,"column_value":"+4"}]'::jsonb, '{"key":"srd-2024_paladin_proficiency-bonus","name":"Proficiency Bonus","desc":"[Column data]","feature_type":"PROFICIENCY_BONUS","gained_at":[],"data_for_class_table":[{"level":1,"column_value":"+2"},{"level":10,"column_value":"+4"},{"level":11,"column_value":"+4"},{"level":12,"column_value":"+4"},{"level":13,"column_value":"+5"},{"level":14,"column_value":"+5"},{"level":15,"column_value":"+5"},{"level":16,"column_value":"+5"},{"level":17,"column_value":"+6"},{"level":18,"column_value":"+6"},{"level":19,"column_value":"+6"},{"level":2,"column_value":"+2"},{"level":20,"column_value":"+6"},{"level":3,"column_value":"+2"},{"level":4,"column_value":"+2"},{"level":5,"column_value":"+3"},{"level":6,"column_value":"+3"},{"level":7,"column_value":"+3"},{"level":8,"column_value":"+3"},{"level":9,"column_value":"+4"}]}'::jsonb),
  ('srd-2024_paladin_radiant-strikes', 'srd-2024_paladin', 'Radiant Strikes', 'CLASS_LEVEL_FEATURE', '[{"level":11,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_paladin_radiant-strikes","name":"Radiant Strikes","desc":"Your strikes now carry supernatural power. When you hit a target with an attack roll using a Melee weapon or an Unarmed Strike, the target takes an extra 1d8 Radiant damage.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":11,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_paladin_restoring-touch', 'srd-2024_paladin', 'Restoring Touch', 'CLASS_LEVEL_FEATURE', '[{"level":14,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_paladin_restoring-touch","name":"Restoring Touch","desc":"When you use Lay On Hands on a creature, you can also remove one or more of the following conditions from the creature: Blinded, Charmed, Deafened, Frightened, Paralyzed, or Stunned. You must expend 5 Hit Points from the healing pool of Lay On Hands for each of these conditions you remove; those points don''t also restore Hit Points to the creature.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":14,"detail":null}],"data_for_class_table":[]}'::jsonb),
