  ('srd-2024_ranger_feral-senses', 'srd-2024_ranger', 'Feral Senses', 'CLASS_LEVEL_FEATURE', '[{"level":18,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_ranger_feral-senses","name":"Feral Senses","desc":"Your connection to the forces of nature grants you Blindsight with a range of 30 feet.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":18,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_ranger_fighting-style', 'srd-2024_ranger', 'Fighting Style', 'CLASS_LEVEL_FEATURE', '[{"level":2,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_ranger_fighting-style","name":"Fighting Style","desc":"You gain a Fighting Style feat of your choice (see \"Feats\"). Instead of choosing one of those feats, you can choose the option below.\n\n**Druidic Warrior.** You learn two Druid cantrips of your choice (see the Druid class''s section for a list of Druid spells). *Guidance* and *Starry Wisp* are recommended. The chosen cantrips count as Ranger spells for you, and Wisdom is your spellcasting ability for them. Whenever you gain a Ranger level, you can replace one of these cantrips with another Druid cantrip.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":2,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_ranger_foe-slayer', 'srd-2024_ranger', 'Foe Slayer', 'CLASS_LEVEL_FEATURE', '[{"level":20,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_ranger_foe-slayer","name":"Foe Slayer","desc":"The damage die of your *Hunter''s Mark* is a d10 rather than a d6.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":20,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_ranger_natures-veil', 'srd-2024_ranger', 'Nature''s Veil', 'CLASS_LEVEL_FEATURE', '[{"level":14,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_ranger_natures-veil","name":"Nature''s Veil","desc":"You invoke spirits of nature to magically hide yourself. As a Bonus Action, you can give yourself the Invisible condition until the end of your next turn.\n\nYou can use this feature a number of times equal to your Wisdom modifier (minimum of once), and you regain all expended uses when you finish a Long Rest.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":14,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_ranger_precise-hunter', 'srd-2024_ranger', 'Precise Hunter', 'CLASS_LEVEL_FEATURE', '[{"level":17,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_ranger_precise-hunter","name":"Precise Hunter","desc":"You have Advantage on attack rolls against the creature currently marked by your *Hunter''s Mark*.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":17,"detail":null}],"data_for_class_table":[]}'::jsonb),
