  ('srd-2024_ranger_ranger-subclass', 'srd-2024_ranger', 'Ranger Subclass', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_ranger_ranger-subclass","name":"Ranger Subclass","desc":"You gain a Ranger subclass of your choice. The Hunter subclass is detailed after this class''s description. A subclass is a specialization that grants you features at certain Ranger levels. For the rest of your career, you gain each of your subclass''s features that are of your Ranger level or lower.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
