  ('srd-2024_sorcerer_sorcerer-spell-list', 'srd-2024_sorcerer', 'Sorcerer Spell List', 'CLASS_LEVEL_FEATURE', '[]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_sorcerer_sorcerer-spell-list","name":"Sorcerer Spell List","desc":"This section presents the Sorcerer spell list. The spells are organized by spell level and then alphabetized, and each spell''s school of magic is listed. In the Special column, *C* means the spell requires Concentration, *R* means it''s a Ritual, and *M* means it requires a specific Material component.\n\nTable: Cantrips (Level 0 Sorcerer Spells)\n\n|Spell|School|Special|\n|---|---|---|\n|Acid Splash|Evocation|—|\n|Chill Touch|Necromancy|—|\n|Dancing Lights|Illusion|C|\n|Elementalism|Transmutation|—|\n|Fire Bolt|Evocation|—|\n|Light|Evocation|—|\n|Mage Hand|Conjuration|—|\n|Mending|Transmutation|—|\n|Message|Transmutation|—|\n|Minor Illusion|Illusion|—|\n|Poison Spray|Necromancy|—|\n|Prestidigitation|Transmutation|—|\n|Ray of Frost|Evocation|—|\n|Shocking Grasp|Evocation|—|\n|Sorcerous Burst|Evocation|—|\n|True Strike|Divination|—|\n\nTable: Level 1 Sorcerer Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Burning Hands|Evocation|—|\n|Charm Person|Enchantment|—|\n|Chromatic Orb|Evocation|M|\n|Color Spray|Illusion|—|\n|Comprehend Languages|Divination|R|\n|Detect Magic|Divination|C, R|\n|Disguise Self|Illusion|—|\n|Expeditious Retreat|Transmutation|C|\n|False Life|Necromancy|–|\n|Feather Fall|Transmutation|—|\n|Fog Cloud|Conjuration|C|\n|Grease|Conjuration|—|\n|Ice Knife|Conjuration|—|\n|Jump|Transmutation|—|\n|Mage Armor|Abjuration|—|\n|Magic Missile|Evocation|—|\n|Ray of Sickness|Necromancy|—|\n|Shield|Abjuration|—|\n|Silent Image|Illusion|C|\n|Sleep|Enchantment|C|\n|Thunderwave|Evocation|—|\n\nTable: Level 2 Sorcerer Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Alter Self|Transmutation|C|\n|Blindness/Deafness|Transmutation|—|\n|Blur|Illusion|C|\n|Darkness|Evocation|C|\n|Darkvision|Transmutation|—|\n|Detect Thoughts|Divination|C|\n|Dragon''s Breath|Transmutation|C|\n|Enhance Ability|Transmutation|C|\n|Enlarge/Reduce|Transmutation|C|\n|Flame Blade|Evocation|C|\n|Flaming Sphere|Evocation|C|\n|Gust of Wind|Evocation|C|\n|Hold Person|Enchantment|C|\n|Invisibility|Illusion|C|\n|Knock|Transmutation|—|\n|Levitate|Transmutation|C|\n|Magic Weapon|Transmutation|—|\n|Mirror Image|Illusion|—|\n|Misty Step|Conjuration|—|\n|Scorching Ray|Evocation|—|\n|See Invisibility|Divination|—|\n|Shatter|Evocation|—|\n|Spider Climb|Transmutation|C|\n|Suggestion|Enchantment|C|\n|Web|Conjuration|C|\n\nTable: Level 3 Sorcerer Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Blink|Transmutation|—|\n|Clairvoyance|Divination|C, M|\n|Counterspell|Abjuration|—|\n|Daylight|Evocation|—|\n|Dispel Magic|Abjuration|—|\n|Fear|Illusion|C|\n|Fireball|Evocation|—|\n|Fly|Transmutation|C|\n|Gaseous Form|Transmutation|C|\n|Haste|Transmutation|C|\n|Hypnotic Pattern|Illusion|C|\n|Lightning Bolt|Evocation|—|\n|Major Image|Illusion|C|\n|Protection from Energy|Abjuration|C|\n|Sleet Storm|Conjuration|C|\n|Slow|Transmutation|C|\n|Stinking Cloud|Conjuration|C|\n|Tongues|Divination|—|\n|Vampiric Touch|Necromancy|C|\n|Water Breathing|Transmutation|R|\n|Water Walk|Transmutation|R|\n\nTable: Level 4 Sorcerer Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Banishment|Abjuration|C|\n|Blight|Necromancy|—|\n|Charm Monster|Enchantment|—|\n|Confusion|Enchantment|C|\n|Dimension Door|Conjuration|—|\n|Dominate Beast|Enchantment|C|\n|Fire Shield|Evocation|—|\n|Greater Invisibility|Illusion|C|\n|Ice Storm|Evocation|—|\n|Polymorph|Transmutation|C|\n|Stoneskin|Transmutation|C, M|\n|Vitriolic Sphere|Evocation|—|\n|Wall of Fire|Evocation|C|\n\nTable: Level 5 Sorcerer Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Animate Objects|Transmutation|C|\n|Arcane Hand|Evocation|C|\n|Cloudkill|Conjuration|C|\n|Cone of Cold|Evocation|—|\n|Creation|Illusion|—|\n|Dominate Person|Enchantment|C|\n|Hold Monster|Enchantment|C|\n|Insect Plague|Conjuration|C|\n|Seeming|Illusion|—|\n|Telekinesis|Transmutation|C|\n|Teleportation Circle|Conjuration|M|\n|Wall of Stone|Evocation|C|\n\nTable: Level 6 Sorcerer Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Chain Lightning|Evocation|—|\n|Circle of Death|Necromancy|M|\n|Disintegrate|Transmutation|—|\n|Eyebite|Necromancy|C|\n|Flesh to Stone|Transmutation|C|\n|Freezing Sphere|Evocation|—|\n|Globe of Invulnerability|Abjuration|C|\n|Mass Suggestion|Enchantment|—|\n|Move Earth|Transmutation|C|\n|Sunbeam|Evocation|C|\n|True Seeing|Divination|M|\n|||\n\nTable: Level 7 Sorcerer Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Delayed Blast Fireball|Evocation|C|\n|Etherealness|Conjuration|—|\n|Finger of Death|Necromancy|—|\n|Fire Storm|Evocation|—|\n|Plane Shift|Conjuration|M|\n|Prismatic Spray|Evocation|—|\n|Reverse Gravity|Transmutation|C|\n|Teleport|Conjuration|—|\n\nTable: Level 8 Sorcerer Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Demiplane|Conjuration|—|\n|Dominate Monster|Enchantment|C|\n|Earthquake|Transmutation|C|\n|Incendiary Cloud|Conjuration|C|\n|Power Word Stun|Enchantment|—|\n|Sunburst|Evocation|—|\n\nTable: Level 9 Sorcerer Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Gate|Conjuration|C, M|\n|Meteor Swarm|Evocation|—|\n|Power Word Kill|Enchantment|—|\n|Time Stop|Transmutation|—|\n|Wish|Conjuration|—|","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_sorcerer_sorcerer-subclass', 'srd-2024_sorcerer', 'Sorcerer Subclass', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_sorcerer_sorcerer-subclass","name":"Sorcerer Subclass","desc":"You gain a Sorcerer subclass of your choice. The Draconic Sorcery subclass is detailed after this class''s description. A subclass is a specialization that grants you features at certain Sorcerer levels. For the rest of your career, you gain each of your subclass''s features that are of your Sorcerer level or lower.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_sorcerer_sorcerous-restoration', 'srd-2024_sorcerer', 'Sorcerous Restoration', 'CLASS_LEVEL_FEATURE', '[{"level":5,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_sorcerer_sorcerous-restoration","name":"Sorcerous Restoration","desc":"When you finish a Short Rest, you can regain expended Sorcery Points, but no more than a number equal to half your Sorcerer level (round down). Once you use this feature, you can''t do so again until you finish a Long Rest.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":5,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_sorcerer_sorcery-incarnate', 'srd-2024_sorcerer', 'Sorcery Incarnate', 'CLASS_LEVEL_FEATURE', '[{"level":7,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_sorcerer_sorcery-incarnate","name":"Sorcery Incarnate","desc":"If you have no uses of Innate Sorcery left, you can use it if you spend 2 Sorcery Points when you take the Bonus Action to activate it.\n\nIn addition, while your Innate Sorcery feature is active, you can use up to two of your Metamagic options on each spell you cast.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":7,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_sorcerer_sorcery-points', 'srd-2024_sorcerer', 'Sorcery Points', 'CLASS_TABLE_DATA', '[]'::jsonb, '[{"level":10,"column_value":"10"},{"level":11,"column_value":"11"},{"level":12,"column_value":"12"},{"level":13,"column_value":"13"},{"level":14,"column_value":"14"},{"level":15,"column_value":"15"},{"level":16,"column_value":"16"},{"level":17,"column_value":"17"},{"level":18,"column_value":"18"},{"level":19,"column_value":"19"},{"level":2,"column_value":"2"},{"level":20,"column_value":"20"},{"level":3,"column_value":"3"},{"level":4,"column_value":"4"},{"level":5,"column_value":"5"},{"level":6,"column_value":"6"},{"level":7,"column_value":"7"},{"level":8,"column_value":"8"},{"level":9,"column_value":"9"}]'::jsonb, '{"key":"srd-2024_sorcerer_sorcery-points","name":"Sorcery Points","desc":"[Column data]","feature_type":"CLASS_TABLE_DATA","gained_at":[],"data_for_class_table":[{"level":10,"column_value":"10"},{"level":11,"column_value":"11"},{"level":12,"column_value":"12"},{"level":13,"column_value":"13"},{"level":14,"column_value":"14"},{"level":15,"column_value":"15"},{"level":16,"column_value":"16"},{"level":17,"column_value":"17"},{"level":18,"column_value":"18"},{"level":19,"column_value":"19"},{"level":2,"column_value":"2"},{"level":20,"column_value":"20"},{"level":3,"column_value":"3"},{"level":4,"column_value":"4"},{"level":5,"column_value":"5"},{"level":6,"column_value":"6"},{"level":7,"column_value":"7"},{"level":8,"column_value":"8"},{"level":9,"column_value":"9"}]}'::jsonb),
  ('srd-2024_sorcerer_spellcasting', 'srd-2024_sorcerer', 'Spellcasting', 'CLASS_LEVEL_FEATURE', '[{"level":1,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_sorcerer_spellcasting","name":"Spellcasting","desc":"Drawing from your innate magic, you can cast spells. See \"Spells\" for the rules on spellcasting. The information below details how you use those rules with Sorcerer spells, which appear in the Sorcerer spell list later in the class''s description.\n\n**Cantrips.** You know four Sorcerer cantrips of your choice. *Light*, *Prestidigitation*, *Shocking Grasp*, and *Sorcerous Burst* are recommended. Whenever you gain a Sorcerer level, you can replace one of your cantrips from this feature with another Sorcerer cantrip of your choice.\n\nWhen you reach Sorcerer levels 4 and 10, you learn another Sorcerer cantrip of your choice, as shown in the Cantrips column of the Sorcerer Features table.\n\n**Spell Slots.** The Sorcerer Features table shows how many spell slots you have to cast your level 1+ spells. You regain all expended slots when you finish a Long Rest.\n\n**Prepared Spells of Level 1+.** You prepare the list of level 1+ spells that are available for you to cast with this feature. To start, choose two level 1 Sorcerer spells. *Burning Hands* and *Detect Magic* are recommended.\n\nThe number of spells on your list increases as you gain Sorcerer levels, as shown in the Prepared Spells column of the Sorcerer Features table. Whenever that number increases, choose additional Sorcerer spells until the number of spells on your list matches the number in the Sorcerer Features table. The chosen spells must be of a level for which you have spell slots. For example, if you''re a level 3 Sorcerer, your list of prepared spells can include six Sorcerer spells of level 1 or 2 in any combination.\n\nIf another Sorcerer feature gives you spells that you always have prepared, those spells don''t count against the number of spells you can prepare with this feature, but those spells otherwise count as Sorcerer spells for you.\n\n**Changing Your Prepared Spells.** Whenever you gain a Sorcerer level, you can replace one spell on your list with another Sorcerer spell for which you have spell slots.\n\n**Spellcasting Ability.** Charisma is your spellcasting ability for your Sorcerer spells.\n\n**Spellcasting Focus.** You can use an Arcane Focus as a Spellcasting Focus for your Sorcerer spells.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":1,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_rogue_thief_fast-hands', 'srd-2024_thief', 'Fast Hands', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_rogue_thief_fast-hands","name":"Fast Hands","desc":"As a Bonus Action, you can do one of the following.\n\n**Sleight of Hand.** Make a Dexterity (Sleight of Hand) check to pick a lock or disarm a trap with Thieves'' Tools or to pick a pocket.\n\n**Use an Object.** Take the Utilize action, or take the Magic action to use a magic item that requires that action.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_rogue_thief_second-story-work', 'srd-2024_thief', 'Second-Story Work', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_rogue_thief_second-story-work","name":"Second-Story Work","desc":"You''ve trained to get into especially hard-to-reach places, granting you these benefits.\n\n**Climber.** You gain a Climb Speed equal to your Speed.\n\n**Jumper.** You can determine your jump distance using your Dexterity rather than your Strength.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_rogue_thief_supreme-sneak', 'srd-2024_thief', 'Supreme Sneak', 'CLASS_LEVEL_FEATURE', '[{"level":9,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_rogue_thief_supreme-sneak","name":"Supreme Sneak","desc":"You gain the following Cunning Strike option. *Stealth Attack (Cost: 1d6).* If you have the Hide action''s Invisible condition, this attack doesn''t end that condition on you if you end the turn behind Three-Quarters Cover or Total Cover.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":9,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_rogue_thief_thiefs-reflexes', 'srd-2024_thief', 'Thief''s Reflexes', 'CLASS_LEVEL_FEATURE', '[{"level":17,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_rogue_thief_thiefs-reflexes","name":"Thief''s Reflexes","desc":"You are adept at laying ambushes and quickly escaping danger. You can take two turns during the first round of any combat. You take your first turn at your normal Initiative and your second turn at your Initiative minus 10.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":17,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_rogue_thief_use-magic-device', 'srd-2024_thief', 'Use Magic Device', 'CLASS_LEVEL_FEATURE', '[{"level":13,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_rogue_thief_use-magic-device","name":"Use Magic Device","desc":"You''ve learned how to maximize use of magic items, granting you the following benefits.\n\n**Attunement.** You can attune to up to four magic items at once.\n\n**Charges.** Whenever you use a magic item property that expends charges, roll 1d6. On a roll of 6, you use the property without expending the charges.\n\n**Scrolls.** You can use any *Spell Scroll*, using Intelligence as your spellcasting ability for the spell. If the spell is a cantrip or a level 1 spell, you can cast it reliably. If the scroll contains a higher-level spell, you must first succeed on an Intelligence (Arcana) check (DC 10 plus the spell''s level). On a successful check, you cast the spell from the scroll. On a failed check, the scroll disintegrates.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":13,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_warlock_ability-score-improvement', 'srd-2024_warlock', 'Ability Score Improvement', 'CLASS_LEVEL_FEATURE', '[{"level":12,"detail":null},{"level":16,"detail":null},{"level":4,"detail":null},{"level":8,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_warlock_ability-score-improvement","name":"Ability Score Improvement","desc":"You gain the Ability Score Improvement feat (see \"Feats\") or another feat of your choice for which you qualify. You gain this feature again at Warlock levels 8, 12, and 16.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":12,"detail":null},{"level":16,"detail":null},{"level":4,"detail":null},{"level":8,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_warlock_cantrips', 'srd-2024_warlock', 'Cantrips', 'CLASS_TABLE_DATA', '[]'::jsonb, '[{"level":1,"column_value":"2"},{"level":10,"column_value":"4"},{"level":11,"column_value":"4"},{"level":12,"column_value":"4"},{"level":13,"column_value":"4"},{"level":14,"column_value":"4"},{"level":15,"column_value":"4"},{"level":16,"column_value":"4"},{"level":17,"column_value":"4"},{"level":18,"column_value":"4"},{"level":19,"column_value":"4"},{"level":2,"column_value":"2"},{"level":20,"column_value":"4"},{"level":3,"column_value":"2"},{"level":4,"column_value":"3"},{"level":5,"column_value":"3"},{"level":6,"column_value":"3"},{"level":7,"column_value":"3"},{"level":8,"column_value":"3"},{"level":9,"column_value":"3"}]'::jsonb, '{"key":"srd-2024_warlock_cantrips","name":"Cantrips","desc":"[Column data]","feature_type":"CLASS_TABLE_DATA","gained_at":[],"data_for_class_table":[{"level":1,"column_value":"2"},{"level":10,"column_value":"4"},{"level":11,"column_value":"4"},{"level":12,"column_value":"4"},{"level":13,"column_value":"4"},{"level":14,"column_value":"4"},{"level":15,"column_value":"4"},{"level":16,"column_value":"4"},{"level":17,"column_value":"4"},{"level":18,"column_value":"4"},{"level":19,"column_value":"4"},{"level":2,"column_value":"2"},{"level":20,"column_value":"4"},{"level":3,"column_value":"2"},{"level":4,"column_value":"3"},{"level":5,"column_value":"3"},{"level":6,"column_value":"3"},{"level":7,"column_value":"3"},{"level":8,"column_value":"3"},{"level":9,"column_value":"3"}]}'::jsonb),
  ('srd-2024_warlock_contact-patron', 'srd-2024_warlock', 'Contact Patron', 'CLASS_LEVEL_FEATURE', '[{"level":9,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_warlock_contact-patron","name":"Contact Patron","desc":"In the past, you usually contacted your patron through intermediaries. Now you can communicate directly; you always have the *Contact Other Plane* spell prepared. With this feature, you can cast the spell without expending a spell slot to contact your patron, and you automatically succeed on the spell''s saving throw.\n\nOnce you cast the spell with this feature, you can''t do so in this way again until you finish a Long Rest.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":9,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_warlock_core-traits', 'srd-2024_warlock', 'Core Warlock Traits', 'CORE_TRAITS_TABLE', '[]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_warlock_core-traits","name":"Core Warlock Traits","desc":"|||\n|---|---|\n|Primary Ability|Charisma|\n|Hit Point Die|D8 per Warlock level|\n|Saving Throw Proficiencies|Wisdom and Charisma|\n|Skill Proficiencies|Choose 2: Arcana, Deception, History, Intimidation, Investigation, Nature, or Religion|\n|Weapon Proficiencies|Simple weapons|\n|Armor Training|Light armor|\n|Starting Equipment|Choose A or B: (A) Leather Armor, Sickle, 2 Daggers, Ar cane Focus (orb), Book (occult lore), Scholar''s Pack, and 15 GP; or (B) 100 GP|","feature_type":"CORE_TRAITS_TABLE","gained_at":[],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_warlock_eldritch-invocation-count', 'srd-2024_warlock', 'Eldritch Invocations', 'CLASS_TABLE_DATA', '[]'::jsonb, '[{"level":1,"column_value":"1"},{"level":10,"column_value":"7"},{"level":11,"column_value":"7"},{"level":12,"column_value":"8"},{"level":13,"column_value":"8"},{"level":14,"column_value":"8"},{"level":15,"column_value":"9"},{"level":16,"column_value":"9"},{"level":17,"column_value":"9"},{"level":18,"column_value":"10"},{"level":19,"column_value":"10"},{"level":2,"column_value":"3"},{"level":20,"column_value":"10"},{"level":3,"column_value":"3"},{"level":4,"column_value":"3"},{"level":5,"column_value":"5"},{"level":6,"column_value":"5"},{"level":7,"column_value":"6"},{"level":8,"column_value":"6"},{"level":9,"column_value":"7"}]'::jsonb, '{"key":"srd-2024_warlock_eldritch-invocation-count","name":"Eldritch Invocations","desc":"[Column data]","feature_type":"CLASS_TABLE_DATA","gained_at":[],"data_for_class_table":[{"level":1,"column_value":"1"},{"level":10,"column_value":"7"},{"level":11,"column_value":"7"},{"level":12,"column_value":"8"},{"level":13,"column_value":"8"},{"level":14,"column_value":"8"},{"level":15,"column_value":"9"},{"level":16,"column_value":"9"},{"level":17,"column_value":"9"},{"level":18,"column_value":"10"},{"level":19,"column_value":"10"},{"level":2,"column_value":"3"},{"level":20,"column_value":"10"},{"level":3,"column_value":"3"},{"level":4,"column_value":"3"},{"level":5,"column_value":"5"},{"level":6,"column_value":"5"},{"level":7,"column_value":"6"},{"level":8,"column_value":"6"},{"level":9,"column_value":"7"}]}'::jsonb),
  ('srd-2024_warlock_eldritch-invocation-options', 'srd-2024_warlock', 'Eldritch Invocation Options', 'CLASS_FEATURE_OPTION_LIST', '[]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_warlock_eldritch-invocation-options","name":"Eldritch Invocation Options","desc":"Eldritch Invocation options appear in alphabetical order.\n\n### Agonizing Blast\n\n*Prerequisite: Level 2+ Warlock, a Warlock Cantrip That Deals Damage*\n\nChoose one of your known Warlock cantrips that deals damage. You can add your Charisma modifier to that spell''s damage rolls.\n\n**Repeatable.** You can gain this invocation more than once. Each time you do so, choose a different eligible cantrip.\n\n### Armor of Shadows\n\nYou can cast *Mage Armor* on yourself without expending a spell slot.\n\n### Ascendant Step\n\n*Prerequisite: Level 5+ Warlock*\n\nYou can cast *Levitate* on yourself without expending a spell slot.\n\n### Devil''s Sight\n\n*Prerequisite: Level 2+ Warlock*\n\nYou can see normally in Dim Light and Darkness both magical and nonmagical—within 120 feet of yourself.\n\n### Devouring Blade\n\n*Prerequisite: Level 12+ Warlock, Thirsting Blade Invocation*\n\nThe Extra Attack of your Thirsting Blade invocation confers two extra attacks rather than one.\n\n### Eldritch Mind\n\nYou have Advantage on Constitution saving throws that you make to maintain Concentration.\n\n### Eldritch Smite\n\n*Prerequisite: Level 5+ Warlock, Pact of the Blade Invocation*\n\nOnce per turn when you hit a creature with your pact weapon, you can expend a Pact Magic spell slot to deal an extra 1d8 Force damage to the target, plus another 1d8 per level of the spell slot, and you can give the target the Prone condition if it is Huge or smaller.\n\n### Eldritch Spear\n\n*Prerequisite: Level 2+ Warlock, a Warlock Cantrip That Deals Damage*\n\nChoose one of your known Warlock cantrips that deals damage and has a range of 10+ feet. When you cast that spell, its range increases by a number of feet equal to 30 times your Warlock level.\n\n**Repeatable.** You can gain this invocation more than once. Each time you do so, choose a different eligible cantrip.\n\n### Fiendish Vigor\n\n*Prerequisite: Level 2+ Warlock*\n\nYou can cast *False Life* on yourself without expending a spell slot. When you cast the spell with this feature, you don''t roll the die for the Temporary Hit Points; you automatically get the highest number on the die.\n\n### Gaze of Two Minds\n\n*Prerequisite: Level 5+ Warlock*\n\nYou can use a Bonus Action to touch a willing creature and perceive through its senses until the end of your next turn. As long as the creature is on the same plane of existence as you, you can take a Bonus Action on subsequent turns to maintain this connection, extending the duration until the end of your next turn. The connection ends if you don''t maintain it in this way.\n\nWhile perceiving through the other creature''s senses, you benefit from any special senses possessed by that creature, and you can cast spells as if you were in your space or the other creature''s space if the two of you are within 60 feet of each other.\n\n### Gift of the Depths\n\n*Prerequisite: Level 5+ Warlock*\n\nYou can breathe underwater, and you gain a Swim Speed equal to your Speed.\n\nYou can also cast *Water Breathing* once without expending a spell slot. You regain the ability to cast it in this way again when you finish a Long Rest.\n\n### Gift of the Protectors\n\n*Prerequisite: Level 9+ Warlock, Pact of the Tome Invocation*\n\nA new page appears in your *Book of Shadows* when you conjure it. With your permission, a creature can take an action to write its name on that page, which can contain a number of names equal to your Charisma modifier (minimum of one name).\n\nWhen any creature whose name is on the page is reduced to 0 Hit Points but not killed outright, the creature magically drops to 1 Hit Point instead. Once this magic is triggered, no creature can benefit from it until you finish a Long Rest.\n\nAs a Magic action, you can erase a name on the page by touching it.\n\n### Investment of the Chain Master\n\n*Prerequisite: Level 5+ Warlock, Pact of the Chain Invocation*\n\nWhen you cast *Find Familiar*, you infuse the summoned familiar with a measure of your eldritch power, granting the creature the following benefits.\n\n**Aerial or Aquatic.** The familiar gains either a Fly Speed or a Swim Speed (your choice) of 40 feet.\n\n**Quick Attack.** As a Bonus Action, you can command the familiar to take the Attack action.\n\n**Necrotic or Radiant Damage.** Whenever the familiar deals Bludgeoning, Piercing, or Slashing damage, you can make it deal Necrotic or Radiant damage instead.\n\n**Your Save DC.** If the familiar forces a creature to make a saving throw, it uses your spell save DC.\n\n**Resistance.** When the familiar takes damage, you can take a Reaction to grant it Resistance against that damage.\n\n### **Lessons of the First Ones**\n\n*Prerequisite: Level 2+ Warlock*\n\nYou have received knowledge from an elder entity of the multiverse, allowing you to gain one Origin feat of your choice (see \"Feats\").\n\n**Repeatable.** You can gain this invocation more than once. Each time you do so, choose a different Origin feat.\n\n### Lifedrinker\n\n*Prerequisite: Level 9+ Warlock, Pact of the Blade Invocation*\n\nOnce per turn when you hit a creature with your pact weapon, you can deal an extra 1d6 Necrotic, Psychic, or Radiant damage (your choice) to the creature, and you can expend one of your Hit Point Dice to roll it and regain a number of Hit Points equal to the roll plus your Constitution modifier (minimum of 1 Hit Point).\n\n### Mask of Many Faces\n\n*Prerequisite: Level 2+ Warlock*\n\nYou can cast *Disguise Self* without expending a spell slot.\n\n### Master of Myriad Forms\n\n*Prerequisite: Level 5+ Warlock*\n\nYou can cast *Alter Self* without expending a spell slot.\n\n### Misty Visions\n\n*Prerequisite: Level 2+ Warlock*\n\nYou can cast *Silent Image* without expending a spell slot.\n\n### One with Shadows\n\n*Prerequisite: Level 5+ Warlock*\n\nWhile you''re in an area of Dim Light or Darkness, you can cast *Invisibility* on yourself without expending a spell slot.\n\n### Otherworldly Leap\n\n*Prerequisite: Level 2+ Warlock*\n\nYou can cast *Jump* on yourself without expending a spell slot.\n\n### Pact of the Blade\n\nAs a Bonus Action, you can conjure a pact weapon in your hand—a Simple or Martial Melee weapon of your choice with which you bond—or create a bond with a magic weapon you touch; you can''t bond with a magic weapon if someone else is attuned to it or another Warlock is bonded with it. Until the bond ends, you have proficiency with the weapon, and you can use it as a Spellcasting Focus.\n\nWhenever you attack with the bonded weapon, you can use your Charisma modifier for the attack and damage rolls instead of using Strength or Dexterity; and you can cause the weapon to deal Necrotic, Psychic, or Radiant damage or its normal damage type.\n\nYour bond with the weapon ends if you use this feature''s Bonus Action again, if the weapon is more than 5 feet away from you for 1 minute or more, or if you die. A conjured weapon disappears when the bond ends.\n\n### Pact of the Chain\n\nYou learn the *Find Familiar* spell and can cast it as a Magic action without expending a spell slot.\n\nWhen you cast the spell, you choose one of the normal forms for your familiar or one of the following special forms: **Imp, Pseudodragon, Quasit, Skeleton, Sphinx of Wonder, Sprite,** or **Venomous Snake** (see \"Monsters\" for the familiar''s stat block).\n\nAdditionally, when you take the Attack action, you can forgo one of your own attacks to allow your familiar to make one attack of its own with its Reaction.\n\n### Pact of the Tome\n\nStitching together strands of shadow, you conjure forth a book in your hand at the end of a Short or Long Rest. This *Book of Shadows* (you determine its appearance) contains eldritch magic that only you can access, granting you the benefits below. The book disappears if you conjure another book with this feature or if you die.\n\n**Cantrips and Rituals.** When the book appears, choose three cantrips, and choose two level 1 spells that have the Ritual tag. The spells can be from any class''s spell list, and they must be spells you don''t already have prepared. While the book is on your person, you have the chosen spells prepared, and they function as Warlock spells for you.\n\n**Spellcasting Focus.** You can use the book as a Spellcasting Focus.\n\n### Repelling Blast\n\n*Prerequisite: Level 2+ Warlock, a Warlock Cantrip That Deals Damage via an Attack Roll*\n\nChoose one of your known Warlock cantrips that requires an attack roll. When you hit a Large or smaller creature with that cantrip, you can push the creature up to 10 feet straight away from you.\n\n**Repeatable.** You can gain this invocation more than once. Each time you do so, choose a different eligible cantrip.\n\n### Thirsting Blade\n\n*Prerequisite: Level 5+ Warlock, Pact of the Blade Invocation*\n\nYou gain the Extra Attack feature for your pact weapon only. With that feature, you can attack twice with the weapon instead of once when you take the Attack action on your turn.\n\n### Visions of Distant Realms\n\n*Prerequisite: Level 9+ Warlock*\n\nYou can cast *Arcane Eye* without expending a spell slot.\n\n### Whispers of the Grave\n\n*Prerequisite: Level 7+ Warlock*\n\nYou can cast *Speak with Dead* without expending a spell slot.\n\n### Witch Sight\n\n*Prerequisite: Level 15+ Warlock*\n\nYou have Truesight with a range of 30 feet.","feature_type":"CLASS_FEATURE_OPTION_LIST","gained_at":[],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_warlock_eldritch-invocations', 'srd-2024_warlock', 'Eldritch Invocations', 'CLASS_LEVEL_FEATURE', '[{"level":1,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_warlock_eldritch-invocations","name":"Eldritch Invocations","desc":"You have unearthed Eldritch Invocations, pieces of forbidden knowledge that imbue you with an abiding magical ability or other lessons. You gain one invocation of your choice, such as Pact of the Tome. Invocations are described in the \"Eldritch Invocation Options\" section later in this class''s description.\n\n**Prerequisites.** If an invocation has a prerequisite, you must meet it to learn that invocation. For example, if an invocation requires you to be a level 5+ Warlock, you can select the invocation once you reach Warlock level 5.\n\n**Replacing and Gaining Invocations.** Whenever you gain a Warlock level, you can replace one of your invocations with another one for which you qualify. You can''t replace an invocation if it''s a prerequisite for another invocation that you have.\n\nWhen you gain certain Warlock levels, you gain more invocations of your choice, as shown in the Invocations column of the Warlock Features table.\n\nYou can''t pick the same invocation more than once unless its description says otherwise.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":1,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_warlock_eldritch-master', 'srd-2024_warlock', 'Eldritch Master', 'CLASS_LEVEL_FEATURE', '[{"level":20,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_warlock_eldritch-master","name":"Eldritch Master","desc":"When you use your Magical Cunning feature, you regain all your expended Pact Magic spell slots.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":20,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_warlock_epic-boon', 'srd-2024_warlock', 'Epic Boon', 'CLASS_LEVEL_FEATURE', '[{"level":19,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_warlock_epic-boon","name":"Epic Boon","desc":"You gain an Epic Boon feat (see \"Feats\") or another feat of your choice for which you qualify. Boon of Fate is recommended.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":19,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_warlock_magical-cunning', 'srd-2024_warlock', 'Magic Cunning', 'CLASS_LEVEL_FEATURE', '[{"level":2,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_warlock_magical-cunning","name":"Magic Cunning","desc":"You can perform an esoteric rite for 1 minute. At the end of it, you regain expended Pact Magic spell slots but no more than a number equal to half your maximum (round up). Once you use this feature, you can''t do so again until you finish a Long Rest.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":2,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_warlock_mystic-arcanum', 'srd-2024_warlock', 'Mystic Arcanum', 'CLASS_LEVEL_FEATURE', '[{"level":11,"detail":"level 6 spell"},{"level":13,"detail":"level 7 spell"},{"level":15,"detail":"level 8 spell"},{"level":17,"detail":"level 9 spell"}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_warlock_mystic-arcanum","name":"Mystic Arcanum","desc":"Your patron grants you a magical secret called an arcanum. Choose one level 6 Warlock spell as this arcanum.\n\nYou can cast your arcanum spell once without expending a spell slot, and you must finish a Long Rest before you can cast it in this way again.\n\nAs shown in the Warlock Features table, you gain another Warlock spell of your choice that can be cast in this way when you reach Warlock levels 13 (level 7 spell), 15 (level 8 spell), and 17 (level 9 spell). You regain all uses of your Mystic Arcanum when you finish a Long Rest.\n\nWhenever you gain a Warlock level, you can replace one of your arcanum spells with another Warlock spell of the same level.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":11,"detail":"level 6 spell"},{"level":13,"detail":"level 7 spell"},{"level":15,"detail":"level 8 spell"},{"level":17,"detail":"level 9 spell"}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_warlock_pact-magic', 'srd-2024_warlock', 'Pact Magic', 'CLASS_LEVEL_FEATURE', '[{"level":1,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_warlock_pact-magic","name":"Pact Magic","desc":"Through occult ceremony, you have formed a pact with a mysterious entity to gain magical powers. The entity is a voice in the shadows—its identity unclear—but its boon to you is concrete: the ability to cast spells. See \"Spells\" for the rules on spellcasting. The information below details how you use those rules with Warlock spells, which appear in the Warlock spell list later in the class''s description.\n\n**Cantrips.** You know two Warlock cantrips of your choice. *Eldritch Blast* and *Prestidigitation* are recommended. Whenever you gain a Warlock level, you can replace one of your cantrips from this feature with another Warlock cantrip of your choice.\n\nWhen you reach Warlock levels 4 and 10, you learn another Warlock cantrip of your choice, as shown in the Cantrips column of the Warlock Features table.\n\n**Spell Slots.** The Warlock Features table shows how many spell slots you have to cast your Warlock spells of levels 1–5. The table also shows the level of those slots, all of which are the same level. You regain all expended Pact Magic spell slots when you finish a Short or Long Rest.\n\nFor example, when you''re a level 5 Warlock, you have two level 3 spell slots. To cast the level 1 spell *Charm Person*, you must spend one of those slots, and you cast it as a level 3 spell.\n\n**Prepared Spells of Level 1+.** You prepare the list of level 1+ spells that are available for you to cast with this feature. To start, choose two level 1 Warlock spells. *Charm Person* and *Hex* are recommended.\n\nThe number of spells on your list increases as you gain Warlock levels, as shown in the Prepared Spells column of the Warlock Features table. Whenever that number increases, choose additional Warlock spells until the number of spells on your list matches the number in the table. The chosen spells must be of a level no higher than what''s shown in the table''s Slot Level column for your level. When you reach level 6, for example, you learn a new Warlock spell, which can be of levels 1–3.\n\nIf another Warlock feature gives you spells that you always have prepared, those spells don''t count against the number of spells you can prepare with this feature, but those spells otherwise count as Warlock spells for you.\n\n**Changing Your Prepared Spells.** Whenever you gain a Warlock level, you can replace one spell on your list with another Warlock spell of an eligible level.\n\n**Spellcasting Ability.** Charisma is the spellcasting ability for your Warlock spells.\n\n**Spellcasting Focus.** You can use an Arcane Focus as a Spellcasting Focus for your Warlock spells.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":1,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_warlock_prepared-spells', 'srd-2024_warlock', 'Prepared Spells', 'CLASS_TABLE_DATA', '[]'::jsonb, '[{"level":1,"column_value":"2"},{"level":10,"column_value":"10"},{"level":11,"column_value":"11"},{"level":12,"column_value":"11"},{"level":13,"column_value":"12"},{"level":14,"column_value":"12"},{"level":15,"column_value":"13"},{"level":16,"column_value":"13"},{"level":17,"column_value":"14"},{"level":18,"column_value":"14"},{"level":19,"column_value":"15"},{"level":2,"column_value":"3"},{"level":20,"column_value":"15"},{"level":3,"column_value":"4"},{"level":4,"column_value":"5"},{"level":5,"column_value":"6"},{"level":6,"column_value":"7"},{"level":7,"column_value":"8"},{"level":8,"column_value":"9"},{"level":9,"column_value":"10"}]'::jsonb, '{"key":"srd-2024_warlock_prepared-spells","name":"Prepared Spells","desc":"[Column data]","feature_type":"CLASS_TABLE_DATA","gained_at":[],"data_for_class_table":[{"level":1,"column_value":"2"},{"level":10,"column_value":"10"},{"level":11,"column_value":"11"},{"level":12,"column_value":"11"},{"level":13,"column_value":"12"},{"level":14,"column_value":"12"},{"level":15,"column_value":"13"},{"level":16,"column_value":"13"},{"level":17,"column_value":"14"},{"level":18,"column_value":"14"},{"level":19,"column_value":"15"},{"level":2,"column_value":"3"},{"level":20,"column_value":"15"},{"level":3,"column_value":"4"},{"level":4,"column_value":"5"},{"level":5,"column_value":"6"},{"level":6,"column_value":"7"},{"level":7,"column_value":"8"},{"level":8,"column_value":"9"},{"level":9,"column_value":"10"}]}'::jsonb),
  ('srd-2024_warlock_proficiency-bonus', 'srd-2024_warlock', 'Proficiency Bonus', 'PROFICIENCY_BONUS', '[]'::jsonb, '[{"level":1,"column_value":"+2"},{"level":10,"column_value":"+4"},{"level":11,"column_value":"+4"},{"level":12,"column_value":"+4"},{"level":13,"column_value":"+5"},{"level":14,"column_value":"+5"},{"level":15,"column_value":"+5"},{"level":16,"column_value":"+5"},{"level":17,"column_value":"+6"},{"level":18,"column_value":"+6"},{"level":19,"column_value":"+6"},{"level":2,"column_value":"+2"},{"level":20,"column_value":"+6"},{"level":3,"column_value":"+2"},{"level":4,"column_value":"+2"},{"level":5,"column_value":"+3"},{"level":6,"column_value":"+3"},{"level":7,"column_value":"+3"},{"level":8,"column_value":"+3"},{"level":9,"column_value":"+4"}]'::jsonb, '{"key":"srd-2024_warlock_proficiency-bonus","name":"Proficiency Bonus","desc":"[Column data]","feature_type":"PROFICIENCY_BONUS","gained_at":[],"data_for_class_table":[{"level":1,"column_value":"+2"},{"level":10,"column_value":"+4"},{"level":11,"column_value":"+4"},{"level":12,"column_value":"+4"},{"level":13,"column_value":"+5"},{"level":14,"column_value":"+5"},{"level":15,"column_value":"+5"},{"level":16,"column_value":"+5"},{"level":17,"column_value":"+6"},{"level":18,"column_value":"+6"},{"level":19,"column_value":"+6"},{"level":2,"column_value":"+2"},{"level":20,"column_value":"+6"},{"level":3,"column_value":"+2"},{"level":4,"column_value":"+2"},{"level":5,"column_value":"+3"},{"level":6,"column_value":"+3"},{"level":7,"column_value":"+3"},{"level":8,"column_value":"+3"},{"level":9,"column_value":"+4"}]}'::jsonb),
  ('srd-2024_warlock_slot-level', 'srd-2024_warlock', 'Slot Level', 'CLASS_TABLE_DATA', '[]'::jsonb, '[{"level":1,"column_value":"1st"},{"level":10,"column_value":"5th"},{"level":11,"column_value":"5th"},{"level":12,"column_value":"5th"},{"level":13,"column_value":"5th"},{"level":14,"column_value":"5th"},{"level":15,"column_value":"5th"},{"level":16,"column_value":"5th"},{"level":17,"column_value":"5th"},{"level":18,"column_value":"5th"},{"level":19,"column_value":"5th"},{"level":2,"column_value":"1st"},{"level":20,"column_value":"5th"},{"level":3,"column_value":"2nd"},{"level":4,"column_value":"2nd"},{"level":5,"column_value":"3rd"},{"level":6,"column_value":"3rd"},{"level":7,"column_value":"4th"},{"level":8,"column_value":"4th"},{"level":9,"column_value":"5th"}]'::jsonb, '{"key":"srd-2024_warlock_slot-level","name":"Slot Level","desc":"[Column data]","feature_type":"CLASS_TABLE_DATA","gained_at":[],"data_for_class_table":[{"level":1,"column_value":"1st"},{"level":10,"column_value":"5th"},{"level":11,"column_value":"5th"},{"level":12,"column_value":"5th"},{"level":13,"column_value":"5th"},{"level":14,"column_value":"5th"},{"level":15,"column_value":"5th"},{"level":16,"column_value":"5th"},{"level":17,"column_value":"5th"},{"level":18,"column_value":"5th"},{"level":19,"column_value":"5th"},{"level":2,"column_value":"1st"},{"level":20,"column_value":"5th"},{"level":3,"column_value":"2nd"},{"level":4,"column_value":"2nd"},{"level":5,"column_value":"3rd"},{"level":6,"column_value":"3rd"},{"level":7,"column_value":"4th"},{"level":8,"column_value":"4th"},{"level":9,"column_value":"5th"}]}'::jsonb),
  ('srd-2024_warlock_spell-slots', 'srd-2024_warlock', 'Spell Slots', 'CLASS_TABLE_DATA', '[]'::jsonb, '[{"level":1,"column_value":"1"},{"level":10,"column_value":"2"},{"level":11,"column_value":"3"},{"level":12,"column_value":"3"},{"level":13,"column_value":"3"},{"level":14,"column_value":"3"},{"level":15,"column_value":"3"},{"level":16,"column_value":"3"},{"level":17,"column_value":"4"},{"level":18,"column_value":"4"},{"level":19,"column_value":"4"},{"level":2,"column_value":"2"},{"level":20,"column_value":"4"},{"level":3,"column_value":"2"},{"level":4,"column_value":"2"},{"level":5,"column_value":"2"},{"level":6,"column_value":"2"},{"level":7,"column_value":"2"},{"level":8,"column_value":"2"},{"level":9,"column_value":"2"}]'::jsonb, '{"key":"srd-2024_warlock_spell-slots","name":"Spell Slots","desc":"[Column data]","feature_type":"CLASS_TABLE_DATA","gained_at":[],"data_for_class_table":[{"level":1,"column_value":"1"},{"level":10,"column_value":"2"},{"level":11,"column_value":"3"},{"level":12,"column_value":"3"},{"level":13,"column_value":"3"},{"level":14,"column_value":"3"},{"level":15,"column_value":"3"},{"level":16,"column_value":"3"},{"level":17,"column_value":"4"},{"level":18,"column_value":"4"},{"level":19,"column_value":"4"},{"level":2,"column_value":"2"},{"level":20,"column_value":"4"},{"level":3,"column_value":"2"},{"level":4,"column_value":"2"},{"level":5,"column_value":"2"},{"level":6,"column_value":"2"},{"level":7,"column_value":"2"},{"level":8,"column_value":"2"},{"level":9,"column_value":"2"}]}'::jsonb),
  ('srd-2024_warlock_warlock-spell-list', 'srd-2024_warlock', 'Warlock Spell List', 'CLASS_LEVEL_FEATURE', '[]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_warlock_warlock-spell-list","name":"Warlock Spell List","desc":"This section presents the Warlock spell list. The spells are organized by spell level and then alphabetized, and each spell''s school of magic is listed. In the Special column, *C* means the spell requires Concentration, *R* means it''s a Ritual, and *M* means it requires a specific Material component.\n\nTable: Cantrips (Level 0 Warlock Spells)\n\n|Spell|School|Special|\n|---|---|---|\n|Chill Touch|Necromancy|—|\n|Eldritch Blast|Evocation|—|\n|Mage Hand|Conjuration|—|\n|Minor Illusion|Illusion|—|\n|Poison Spray|Necromancy|—|\n|Prestidigitation|Transmutation|—|\n|True Strike|Divination|—|\n\nTable: Level 1 Warlock Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Bane|Enchantment|C|\n|Charm Person|Enchantment|—|\n|Comprehend Languages|Divination|R|\n|Detect Magic|Divination|C, R|\n|Expeditious Retreat|Transmutation|C|\n|Hellish Rebuke|Evocation|—|\n|Hex|Enchantment|C|\n|Hideous Laughter|Enchantment|C|\n|Illusory Script|Illusion|R, M|\n|Protection from Evil and Good|Abjuration|C, M|\n|Speak with Animals|Divination|R|\n|Unseen Servant|Conjuration|R|\n\nTable: Level 2 Warlock Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Darkness|Evocation|C|\n|Enthrall|Enchantment|C|\n|Hold Person|Enchantment|C|\n|Invisibility|Illusion|C|\n|Mind Spike|Divination|C|\n|Mirror Image|Illusion|—|\n|Misty Step|Conjuration|—|\n|Ray of Enfeeblement|Necromancy|C|\n|Spider Climb|Transmutation|C|\n|Suggestion|Enchantment|C|\n\nTable: Level 3 Warlock Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Counterspell|Abjuration|—|\n|Dispel Magic|Abjuration|—|\n|Fear|Illusion|C|\n|Fly|Transmutation|C|\n|Gaseous Form|Transmutation|C|\n|Hypnotic Pattern|Illusion|C|\n|Magic Circle|Abjuration|M|\n|Major Image|Illusion|C|\n|Remove Curse|Abjuration|—|\n|Tongues|Divination|—|\n|Vampiric Touch|Necromancy|C|\n\nTable: Level 4 Warlock Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Banishment|Abjuration|C|\n|Blight|Necromancy|—|\n|Charm Monster|Enchantment|—|\n|Dimension Door|Conjuration|—|\n|Hallucinatory Terrain|Illusion|—|\n\nTable: Level 5 Warlock Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Contact Other Plane|Divination|R|\n|Dream|Illusion|—|\n|Hold Monster|Enchantment|C|\n|Mislead|Illusion|C|\n|Planar Binding|Abjuration|M|\n|Scrying|Divination|C, M|\n|Teleportation Circle|Conjuration|M|\n\nTable: Level 6 Warlock Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Circle of Death|Necromancy|M|\n|Create Undead|Necromancy|M|\n|Eyebite|Necromancy|C|\n|True Seeing|Divination|M|\n\nTable: Level 7 Warlock Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Etherealness|Conjuration|—|\n|Finger of Death|Necromancy|—|\n|Forcecage|Evocation|C, M|\n|Plane Shift|Conjuration|M|\n\nTable: Level 8 Warlock Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Befuddlement|Enchantment|—|\n|Demiplane|Conjuration|—|\n|Dominate Monster|Enchantment|C|\n|Glibness|Enchantment|—|\n|Power Word Stun|Enchantment|—|\n\nTable: Level 9 Warlock Spells\n\n|Spell|School|Special|\n|---|---|---|\n|Astral Projection|Necromancy|M|\n|Foresight|Divination|—|\n|Gate|Conjuration|C, M|\n|Imprisonment|Abjuration|M|\n|Power Word Kill|Enchantment|—|\n|True Polymorph|Transmutation|C|\n|Weird|Illusion|C|","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_warlock_warlock-subclass', 'srd-2024_warlock', 'Warlock Subclass', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_warlock_warlock-subclass","name":"Warlock Subclass","desc":"You gain a Warlock subclass of your choice. The Fiend Patron subclass is detailed after this class''s description. A subclass is a specialization that grants you features at certain Warlock levels. For the rest of your career, you gain each of your subclass''s features that are of your Warlock level or lower.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_monk_warrior-of-the-open-hand_fleet-step', 'srd-2024_warrior-of-the-open-hand', 'Fleet Step', 'CLASS_LEVEL_FEATURE', '[{"level":11,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_monk_warrior-of-the-open-hand_fleet-step","name":"Fleet Step","desc":"When you take a Bonus Action other than Step of the Wind, you can also use Step of the Wind immediately after that Bonus Action.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":11,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_monk_warrior-of-the-open-hand_open-hand-technique', 'srd-2024_warrior-of-the-open-hand', 'Open Hand Technique', 'CLASS_LEVEL_FEATURE', '[{"level":3,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_monk_warrior-of-the-open-hand_open-hand-technique","name":"Open Hand Technique","desc":"Whenever you hit a creature with an attack granted by your Flurry of Blows, you can impose one of the following effects on that target.\n\n**Addle.** The target can''t make Opportunity Attacks until the start of its next turn.\n\n**Push.** The target must succeed on a Strength saving throw or be pushed up to 15 feet away from you.\n\n**Topple.** The target must succeed on a Dexterity saving throw or have the Prone condition.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":3,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_monk_warrior-of-the-open-hand_quivering-palm', 'srd-2024_warrior-of-the-open-hand', 'Quivering Palm', 'CLASS_LEVEL_FEATURE', '[{"level":17,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_monk_warrior-of-the-open-hand_quivering-palm","name":"Quivering Palm","desc":"You gain the ability to set up lethal vibrations in someone''s body. When you hit a creature with an Unarmed Strike, you can expend 4 Focus Points to start these imperceptible vibrations, which last for a number of days equal to your Monk level. The vibrations are harmless unless you take an action to end them. Alternatively, when you take the Attack action on your turn, you can forgo one of the attacks to end the vibrations. To end them, you and the target must be on the same plane of existence. When you end them, the target must make a Constitution saving throw, taking 10d12 Force damage on a failed save or half as much damage on a successful one.\n\nYou can have only one creature under the effect of this feature at a time. You can end the vibrations harmlessly (no action required).","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":17,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_monk_warrior-of-the-open-hand_wholeness-of-body', 'srd-2024_warrior-of-the-open-hand', 'Wholeness of Body', 'CLASS_LEVEL_FEATURE', '[{"level":6,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_monk_warrior-of-the-open-hand_wholeness-of-body","name":"Wholeness of Body","desc":"You gain the ability to heal yourself. As a Bonus Action, you can roll your Martial Arts die. You regain a number of Hit Points equal to the number rolled plus your Wisdom modifier (minimum of 1 Hit Point regained).\n\nYou can use this feature a number of times equal to your Wisdom modifier (minimum of once), and you regain all expended uses when you finish a Long Rest.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":6,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_wizard_ability-score-improvement', 'srd-2024_wizard', 'Ability Score Improvement', 'CLASS_LEVEL_FEATURE', '[{"level":12,"detail":null},{"level":16,"detail":null},{"level":4,"detail":null},{"level":8,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_wizard_ability-score-improvement","name":"Ability Score Improvement","desc":"You gain the Ability Score Improvement feat (see \"Feats\") or another feat of your choice for which you qualify. You gain this feature again at Wizard levels 8, 12, and 16.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":12,"detail":null},{"level":16,"detail":null},{"level":4,"detail":null},{"level":8,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_wizard_arcane-recovery', 'srd-2024_wizard', 'Arcane Recovery', 'CLASS_LEVEL_FEATURE', '[{"level":1,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_wizard_arcane-recovery","name":"Arcane Recovery","desc":"You can regain some of your magical energy by studying your spellbook. When you finish a Short Rest, you can choose expended spell slots to recover. The spell slots can have a combined level equal to no more than half your Wizard level (round up), and none of the slots can be level 6 or higher. For example, if you''re a level 4 Wizard, you can recover up to two levels'' worth of spell slots, regaining either one level 2 spell slot or two level 1 spell slots.\n\nOnce you use this feature, you can''t do so again until you finish a Long Rest.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":1,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_wizard_cantrips', 'srd-2024_wizard', 'Cantrips', 'CLASS_TABLE_DATA', '[]'::jsonb, '[{"level":1,"column_value":"3"},{"level":10,"column_value":"5"},{"level":11,"column_value":"5"},{"level":12,"column_value":"5"},{"level":13,"column_value":"5"},{"level":14,"column_value":"5"},{"level":15,"column_value":"5"},{"level":16,"column_value":"5"},{"level":17,"column_value":"5"},{"level":18,"column_value":"5"},{"level":19,"column_value":"5"},{"level":2,"column_value":"3"},{"level":20,"column_value":"5"},{"level":3,"column_value":"3"},{"level":4,"column_value":"4"},{"level":5,"column_value":"4"},{"level":6,"column_value":"4"},{"level":7,"column_value":"4"},{"level":8,"column_value":"4"},{"level":9,"column_value":"4"}]'::jsonb, '{"key":"srd-2024_wizard_cantrips","name":"Cantrips","desc":"[Column data]","feature_type":"CLASS_TABLE_DATA","gained_at":[],"data_for_class_table":[{"level":1,"column_value":"3"},{"level":10,"column_value":"5"},{"level":11,"column_value":"5"},{"level":12,"column_value":"5"},{"level":13,"column_value":"5"},{"level":14,"column_value":"5"},{"level":15,"column_value":"5"},{"level":16,"column_value":"5"},{"level":17,"column_value":"5"},{"level":18,"column_value":"5"},{"level":19,"column_value":"5"},{"level":2,"column_value":"3"},{"level":20,"column_value":"5"},{"level":3,"column_value":"3"},{"level":4,"column_value":"4"},{"level":5,"column_value":"4"},{"level":6,"column_value":"4"},{"level":7,"column_value":"4"},{"level":8,"column_value":"4"},{"level":9,"column_value":"4"}]}'::jsonb),
  ('srd-2024_wizard_core-traits', 'srd-2024_wizard', 'Core Wizard Traits', 'CORE_TRAITS_TABLE', '[]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_wizard_core-traits","name":"Core Wizard Traits","desc":"|||\n|---|---|\n|Primary Ability|Intelligence|\n|Hit Point Die|D6 per Wizard level|\n|Saving Throw Proficiencies|Intelligence and Wisdom|\n|Skill Proficiencies|Choose 2: Arcana, History, In sight, Investigation, Medicine, Nature, or Religion|\n|Weapon Proficiencies|Simple weapons|\n|Armor Training|None|\n|Starting Equipment|Choose A or B: (A) 2 Daggers, Arcane Focus (Quarterstaff), Robe, Spellbook, Scholar''s Pack, and 5 GP; or (B) 55 GP|","feature_type":"CORE_TRAITS_TABLE","gained_at":[],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_wizard_epic-boon', 'srd-2024_wizard', 'Epic Boon', 'CLASS_LEVEL_FEATURE', '[{"level":19,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_wizard_epic-boon","name":"Epic Boon","desc":"You gain an Epic Boon feat (see \"Feats\") or another feat of your choice for which you qualify. Boon of Spell Recall is recommended.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":19,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_wizard_memorize-spell', 'srd-2024_wizard', 'Memorize Spell', 'CLASS_LEVEL_FEATURE', '[{"level":5,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_wizard_memorize-spell","name":"Memorize Spell","desc":"Whenever you finish a Short Rest, you can study your spellbook and replace one of the level 1+ Wizard spells you have prepared for your Spellcasting feature with another level 1+ spell from the book.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":5,"detail":null}],"data_for_class_table":[]}'::jsonb),
