  ('srd-2024_wizard_proficiency-bonus', 'srd-2024_wizard', 'Proficiency Bonus', 'PROFICIENCY_BONUS', '[]'::jsonb, '[{"level":1,"column_value":"+2"},{"level":10,"column_value":"+4"},{"level":11,"column_value":"+4"},{"level":12,"column_value":"+4"},{"level":13,"column_value":"+5"},{"level":14,"column_value":"+5"},{"level":15,"column_value":"+5"},{"level":16,"column_value":"+5"},{"level":17,"column_value":"+6"},{"level":18,"column_value":"+6"},{"level":19,"column_value":"+6"},{"level":2,"column_value":"+2"},{"level":20,"column_value":"+6"},{"level":3,"column_value":"+2"},{"level":4,"column_value":"+2"},{"level":5,"column_value":"+3"},{"level":6,"column_value":"+3"},{"level":7,"column_value":"+3"},{"level":8,"column_value":"+3"},{"level":9,"column_value":"+4"}]'::jsonb, '{"key":"srd-2024_wizard_proficiency-bonus","name":"Proficiency Bonus","desc":"[Column data]","feature_type":"PROFICIENCY_BONUS","gained_at":[],"data_for_class_table":[{"level":1,"column_value":"+2"},{"level":10,"column_value":"+4"},{"level":11,"column_value":"+4"},{"level":12,"column_value":"+4"},{"level":13,"column_value":"+5"},{"level":14,"column_value":"+5"},{"level":15,"column_value":"+5"},{"level":16,"column_value":"+5"},{"level":17,"column_value":"+6"},{"level":18,"column_value":"+6"},{"level":19,"column_value":"+6"},{"level":2,"column_value":"+2"},{"level":20,"column_value":"+6"},{"level":3,"column_value":"+2"},{"level":4,"column_value":"+2"},{"level":5,"column_value":"+3"},{"level":6,"column_value":"+3"},{"level":7,"column_value":"+3"},{"level":8,"column_value":"+3"},{"level":9,"column_value":"+4"}]}'::jsonb),
  ('srd-2024_wizard_ritual-adept', 'srd-2024_wizard', 'Ritual Adept', 'CLASS_LEVEL_FEATURE', '[{"level":1,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_wizard_ritual-adept","name":"Ritual Adept","desc":"You can cast any spell as a Ritual if that spell has the Ritual tag and the spell is in your spellbook. You needn''t have the spell prepared, but you must read from the book to cast a spell in this way.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":1,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_wizard_scholar', 'srd-2024_wizard', 'Scholar', 'CLASS_LEVEL_FEATURE', '[{"level":2,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_wizard_scholar","name":"Scholar","desc":"While studying magic, you also specialized in another field of study. Choose one of the following skills in which you have proficiency: Arcana, History, Investigation, Medicine, Nature, or Religion. You have Expertise in the chosen skill.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":2,"detail":null}],"data_for_class_table":[]}'::jsonb),
  ('srd-2024_wizard_signature-spells', 'srd-2024_wizard', 'Signature Spells', 'CLASS_LEVEL_FEATURE', '[{"level":20,"detail":null}]'::jsonb, '[]'::jsonb, '{"key":"srd-2024_wizard_signature-spells","name":"Signature Spells","desc":"Choose two level 3 spells in your spellbook as your signature spells. You always have these spells prepared, and you can cast each of them once at level 3 without expending a spell slot. When you do so, you can''t cast them in this way again until you finish a Short or Long Rest. To cast either spell at a higher level, you must expend a spell slot.","feature_type":"CLASS_LEVEL_FEATURE","gained_at":[{"level":20,"detail":null}],"data_for_class_table":[]}'::jsonb),
