  ('srd-2024_chain', 'Chain', 'Adventuring Gear', '{"key":"srd-2024_chain","name":"Chain","desc":"As a Utilize action, you can wrap a Chain around an unwilling creature within 5 feet of yourself that has the Grappled, Incapacitated, or Restrained condition if you succeed on a DC 13 Strength (Athletics) check. If the creature''s legs are bound, the creature has the Restrained condition until it escapes. Escaping the Chain requires the creature to make a successful DC 18 Dexterity (Acrobatics) check as an action. Bursting the Chain requires a successful DC 20 Strength (Athletics) check as an action.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"10.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
