  ('srd-2024_climbers-kit', 'Climber''s Kit', 'Tools', '{"key":"srd-2024_climbers-kit","name":"Climber''s Kit","desc":"A Climber''s Kit includes boot tips, gloves, pitons, and a harness. As a Utilize action, you can use the Climber''s Kit to anchor yourself; when you do, you can''t fall more than 25 feet from the anchor point, and you can''t move more than 25 feet from there without undoing the anchor as a Bonus Action.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"12.000","weight_unit":"lb","cost":"25.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
