  ('srd-2024_club', 'Club', 'Weapon', '{"key":"srd-2024_club","name":"Club","desc":"A club.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Club","key":"srd-2024_club","damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"damage_dice":"1d4","properties":[{"property":{"name":"Light","type":null,"desc":"When you take the Attack action on your turn and attack with a Light weapon, you can make one extra attack as a Bonus Action later on the same turn. That extra attack must be made with a different Light weapon, and you don''t add your ability modifier to the extra attack''s damage unless that modifier is negative."},"detail":null},{"property":{"name":"Slow","type":"Mastery","desc":"If you hit a creature with this weapon and deal damage to it, you can reduce its Speed by 10 feet until the start of your next turn. If the creature is hit more than once by weapons that have this property, the Speed reduction doesn''t exceed 10 feet."},"detail":null}],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"0.10","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
