  ('srd-2024_component-pouch', 'Component Pouch', 'Adventuring Gear', '{"key":"srd-2024_component-pouch","name":"Component Pouch","desc":"A Component Pouch is watertight and filled with compartments that hold all the free Material components of your spells.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"25.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
