  ('srd-2024_greatclub', 'Greatclub', 'Weapon', '{"key":"srd-2024_greatclub","name":"Greatclub","desc":"A greatclub.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Greatclub","key":"srd-2024_greatclub","damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"damage_dice":"1d8","properties":[{"property":{"name":"Push","type":"Mastery","desc":"If you hit a creature with this weapon, you can push the creature up to 10 feet straight away from yourself if it is Large or smaller."},"detail":null},{"property":{"name":"Two-Handed","type":null,"desc":"A Two-Handed weapon requires two hands when you attack with it."},"detail":null}],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"10.000","weight_unit":"lb","cost":"0.20","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
