  ('srd-2024_halberd', 'Halberd', 'Weapon', '{"key":"srd-2024_halberd","name":"Halberd","desc":"A halberd.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Halberd","key":"srd-2024_halberd","damage_type":{"name":"Slashing","key":"slashing"},"damage_dice":"1d10","properties":[{"property":{"name":"Cleave","type":"Mastery","desc":"If you hit a creature with a melee attack roll using this weapon, you can make a melee attack roll with the weapon against a second creature within 5 feet of the first that is also within your reach. On a hit, the second creature takes the weapon''s damage, but don''t add your ability modifier to that damage unless that modifier is negative. You can make this extra attack only once per turn."},"detail":null},{"property":{"name":"Heavy","type":null,"desc":"You have Disadvantage on attack rolls with a Heavy weapon if it''s a Melee weapon and your Strength score isn''t at least 13 or if it''s a Ranged weapon and your Dexterity score isn''t at least 13."},"detail":null},{"property":{"name":"Reach","type":null,"desc":"A Reach weapon adds 5 feet to your reach when you attack with it, as well as when determining your reach for Opportunity Attacks with it."},"detail":null},{"property":{"name":"Two-Handed","type":null,"desc":"A Two-Handed weapon requires two hands when you attack with it."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"6.000","weight_unit":"lb","cost":"20.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_half-plate-armor', 'Half Plate Armor', 'Armor', '{"key":"srd-2024_half-plate-armor","name":"Half Plate Armor","desc":"A half plate armor.","category":{"name":"Armor","key":"armor"},"weapon":null,"armor":{"name":"Half Plate Armor","key":"srd-2024_half-plate-armor","category":"medium","ac_base":15,"ac_display":"15 + Dex modifier (max 2)","ac_add_dexmod":true,"ac_cap_dexmod":2,"grants_stealth_disadvantage":true,"strength_score_required":null},"size":{"name":"Tiny","key":"tiny"},"weight":"40.000","weight_unit":"lb","cost":"750.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_hand-crossbow', 'Hand Crossbow', 'Weapon', '{"key":"srd-2024_hand-crossbow","name":"Hand Crossbow","desc":"A hand crossbow.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Hand Crossbow","key":"srd-2024_hand-crossbow","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1d6","properties":[{"property":{"name":"Ammunition","type":null,"desc":"You can use a weapon that has the Ammunition property to make a ranged attack only if you have ammunition to fire from it. The type of ammunition required is specified with the weapon''s range. Each attack expends one piece of ammunition. Drawing the ammunition is part of the attack (you need a free hand to load a one-handed weapon). After a fight, you can spend 1 minute to recover half the ammunition (round down) you used in the fight; the rest is lost."},"detail":"Range 30/120; Bolt"},{"property":{"name":"Light","type":null,"desc":"When you take the Attack action on your turn and attack with a Light weapon, you can make one extra attack as a Bonus Action later on the same turn. That extra attack must be made with a different Light weapon, and you don''t add your ability modifier to the extra attack''s damage unless that modifier is negative."},"detail":null},{"property":{"name":"Loading","type":null,"desc":"You can fire only one piece of ammunition from a Loading weapon when you use an action, a Bonus Action, or a Reaction to fire it, regardless of the number of attacks you can normally make."},"detail":null},{"property":{"name":"Vex","type":"Mastery","desc":"If you hit a creature with this weapon and deal damage to the creature, you have Advantage on your next attack roll against that creature before the end of your next turn."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"3.000","weight_unit":"lb","cost":"75.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_handaxe', 'Handaxe', 'Weapon', '{"key":"srd-2024_handaxe","name":"Handaxe","desc":"A handaxe.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Handaxe","key":"srd-2024_handaxe","damage_type":{"name":"Slashing","key":"slashing"},"damage_dice":"1d6","properties":[{"property":{"name":"Light","type":null,"desc":"When you take the Attack action on your turn and attack with a Light weapon, you can make one extra attack as a Bonus Action later on the same turn. That extra attack must be made with a different Light weapon, and you don''t add your ability modifier to the extra attack''s damage unless that modifier is negative."},"detail":null},{"property":{"name":"Thrown","type":null,"desc":"If a weapon has the Thrown property, you can throw the weapon to make a ranged attack, and you can draw that weapon as part of the attack. If the weapon is a Melee weapon, use the same ability modifier for the attack and damage rolls that you use for a melee attack with that weapon."},"detail":"Range 20/60"},{"property":{"name":"Vex","type":"Mastery","desc":"If you hit a creature with this weapon and deal damage to the creature, you have Advantage on your next attack roll against that creature before the end of your next turn."},"detail":null}],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_healers-kit', 'Healer''s Kit', 'Tools', '{"key":"srd-2024_healers-kit","name":"Healer''s Kit","desc":"A Healer''s Kit has ten uses. As a Utilize action, you can expend one of its uses to stabilize an Unconscious creature that has 0 Hit Points without needing to make a Wisdom (Medicine) check.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"3.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
