  ('srd-2024_herbalism-kit', 'Herbalism Kit', 'Tools', '{"key":"srd-2024_herbalism-kit","name":"Herbalism Kit","desc":"Ability: Intelligence. Utilize: Identify a plant (DC 15). Craft: Antitoxin, Potion of Healing","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"3.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_hide-armor', 'Hide Armor', 'Armor', '{"key":"srd-2024_hide-armor","name":"Hide Armor","desc":"A hide armor.","category":{"name":"Armor","key":"armor"},"weapon":null,"armor":{"name":"Hide Armor","key":"srd-2024_hide-armor","category":"medium","ac_base":12,"ac_display":"12 + Dex modifier (max 2)","ac_add_dexmod":true,"ac_cap_dexmod":2,"grants_stealth_disadvantage":false,"strength_score_required":null},"size":{"name":"Tiny","key":"tiny"},"weight":"12.000","weight_unit":"lb","cost":"10.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_holy-symbol-amulet', 'Holy Symbol, Amulet)', 'Adventuring Gear', '{"key":"srd-2024_holy-symbol-amulet","name":"Holy Symbol, Amulet)","desc":"A Holy Symbol Amulet is bejeweled or painted to channel divine magic. A Cleric or Paladin can use it as a Spellcasting Focus. It can be worn around the neck or held in hand.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"1.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_holy-symbol-emblem', 'Holy Symbol, Emblem)', 'Adventuring Gear', '{"key":"srd-2024_holy-symbol-emblem","name":"Holy Symbol, Emblem)","desc":"A Holy Symbol Emblem is bejeweled or painted to channel divine magic. A Cleric or Paladin can use it as a Spellcasting Focus. It must be borne on fabric (such as a tabard or banner) or a Shield.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_holy-symbol-reliquary', 'Holy Symbol, Reliquary', 'Adventuring Gear', '{"key":"srd-2024_holy-symbol-reliquary","name":"Holy Symbol, Reliquary","desc":"A Holy Symbol Reliquary is bejeweled or painted to channel divine magic. A Cleric or Paladin can use it as a Spellcasting Focus. It must be held in hand.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_holy-water', 'Holy Water', 'Weapon', '{"key":"srd-2024_holy-water","name":"Holy Water","desc":"When you take the Attack action, you can replace one of your attacks with throwing a flask of Holy Water. Target one creature you can see within 20 feet of yourself. The target must succeed on a Dexterity saving throw (DC 8 plus your Dexterity modifier and Proficiency Bonus) or take 2d8 Radiant damage if it is a Fiend or an Undead.","category":{"name":"Weapon","key":"weapon"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"1.000","weight_unit":"lb","cost":"25.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_horse-draft', 'Horse (Draft)', 'Mount', '{"key":"srd-2024_horse-draft","name":"Horse (Draft)","desc":"A strong horse bred for pulling heavy loads.","category":{"name":"Mount","key":"mount"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"50.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_horse-riding', 'Horse (Riding)', 'Mount', '{"key":"srd-2024_horse-riding","name":"Horse (Riding)","desc":"A horse trained for riding and carrying moderate loads.","category":{"name":"Mount","key":"mount"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"75.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_hunting-trap', 'Hunting Trap', 'Adventuring Gear', '{"key":"srd-2024_hunting-trap","name":"Hunting Trap","desc":"As a Utilize action, you can set a Hunting Trap, which is a sawtooth steel ring that snaps shut when a creature steps on a pressure plate in the center. The trap is affixed by a heavy chain to an immobile object, such as a tree or a spike driven into the ground. A creature that steps on the plate must succeed on a DC 13 Dexterity saving throw or take 1d4 Piercing damage and have its Speed reduced to 0 until the start of its next turn. Thereafter, until the creature breaks free of the trap, its movement is limited by the length of the chain (typically 3 feet). A creature can use its action to make a DC 13 Strength (Athletics) check, freeing itself or another creature within its reach on a success. Each failed check deals 1 Piercing damage to the trapped creature.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"25.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_ink', 'Ink', 'Adventuring Gear', '{"key":"srd-2024_ink","name":"Ink","desc":"Ink comes in a 1-ounce bottle, which provides enough ink to write about 500 pages.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"10.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_ink-pen', 'Ink Pen', 'Adventuring Gear', '{"key":"srd-2024_ink-pen","name":"Ink Pen","desc":"Using Ink, an Ink Pen is used to write or draw.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"0.02","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_ioun-stone', 'Ioun Stone', 'Wondrous Item', '{"key":"srd-2024_ioun-stone","name":"Ioun Stone","desc":"Roughly marble sized, Ioun Stones are named after Ioun, a god of knowledge and prophecy revered on some worlds. Many types of Ioun Stones exist, each type a distinct combination of shape and color. When you take a Magic action to toss an Ioun Stone into the air, the stone orbits your head at a distance of 1d3 feet, conferring its benefit to you while doing so. You can have up to three Ioun Stones orbiting your head at the same time. Each Ioun Stone orbiting your head is considered to be an object you are wearing. The orbiting stone avoids contact with other creatures and objects, adjusting its orbit to avoid collisions and thwarting all attempts by other creatures to attack or snatch it. As a Utilize action, you can seize and stow any number of Ioun Stones orbiting your head. If your Attunement to an Ioun Stone ends while it''s orbiting your head, the stone falls as though you had dropped it. The type of stone determines its rarity and effects. Absorption (Very Rare). While this pale lavender ellipsoid orbits your head, you can take a Reaction to cancel a spell of level 4 or lower cast by a creature you can see. A canceled spell has no effect, and any resources used to cast it are wasted. Once the stone has canceled 20 levels of spells, it burns out, turns dull gray, and loses its magic. Agility (Very Rare). Your Dexterity increases by 2, to a maximum of 20, while this deep-red sphere orbits your head. Awareness (Rare). While this dark-blue rhomboid orbits your head, you have Advantage on Initiative rolls and Wisdom (Perception) checks. Fortitude (Very Rare). Your Constitution increases by 2, to a maximum of 20, while this pink rhomboid orbits your head. Greater Absorption (Legendary). While this marbled lavender and green ellipsoid orbits your head, you can take a Reaction to cancel a spell of level 8 or lower cast by a creature you can see. A canceled spell has no effect, and any resources used to cast it are wasted. Once the stone has canceled 20 levels of spells, it burns out, turns dull gray, and loses its magic. Insight (Very Rare). Your Wisdom increases by 2, to a maximum of 20, while this incandescent blue sphere orbits your head. Intellect (Very Rare). Your Intelligence increases by 2, to a maximum of 20, while this marbled scarlet and blue sphere orbits your head. Leadership (Very Rare). Your Charisma increases by 2, to a maximum of 20, while this marbled pink and green sphere orbits your head. Mastery (Legendary). Your Proficiency Bonus increases by 1 while this pale green prism orbits your head. Protection (Rare). You gain a +1 bonus to Armor Class while this dusty-rose prism orbits your head. Regeneration (Legendary). You regain 15 Hit Points at the end of each hour this pearly white spindle orbits your head if you have at least 1 Hit Point. Reserve (Rare). This vibrant purple prism stores spells cast into it, holding them until you use them. The stone can store up to 4 levels of spells at a time. When found, it contains 1d4 levels of stored spells chosen by the GM. Any creature can cast a spell of level 1 through 4 into the stone by touching it as the spell is cast. The spell has no effect, other than to be stored in the stone. If the stone can''t hold the spell, the spell is expended without effect. The level of the slot used to cast the spell determines how much space it uses. While this stone orbits your head, you can cast any spell stored in it. The spell uses the slot level, spell save DC, spell attack bonus, and spellcasting ability of the original caster but is otherwise treated as if you cast the spell. The spell cast from the stone is no longer stored in it, freeing up space. Strength (Very Rare). Your Strength increases by 2, to a maximum of 20, while this pale blue rhomboid orbits your head. Sustenance (Rare). You don''t need to eat or drink while this clear spindle orbits your head.","category":{"name":"Wondrous Item","key":"wondrous-item"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"0.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
