  ('srd-2024_lance', 'Lance', 'Weapon', '{"key":"srd-2024_lance","name":"Lance","desc":"A lance.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Lance","key":"srd-2024_lance","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1d10","properties":[{"property":{"name":"Heavy","type":null,"desc":"You have Disadvantage on attack rolls with a Heavy weapon if it''s a Melee weapon and your Strength score isn''t at least 13 or if it''s a Ranged weapon and your Dexterity score isn''t at least 13."},"detail":null},{"property":{"name":"Reach","type":null,"desc":"A Reach weapon adds 5 feet to your reach when you attack with it, as well as when determining your reach for Opportunity Attacks with it."},"detail":null},{"property":{"name":"Topple","type":"Mastery","desc":"If you hit a creature with this weapon, you can force the creature to make a Constitution saving throw (DC 8 plus the ability modifier used to make the attack roll and your Proficiency Bonus). On a failed save, the creature has the Prone condition."},"detail":null},{"property":{"name":"Two-Handed","type":null,"desc":"A Two-Handed weapon requires two hands when you attack with it."},"detail":"unless mounted"}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"6.000","weight_unit":"lb","cost":"10.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
