  ('srd-2024_leatherworkers-tools', 'Leatherworker''s Tools (5 GP)', 'Tools', '{"key":"srd-2024_leatherworkers-tools","name":"Leatherworker''s Tools (5 GP)","desc":"Ability: Dexterity. Utilize: Add a design to a leather item (DC 10). Craft: Sling, Whip, Hide Armor, Leather Armor, Studded Leather Armor, Backpack, Crossbow Bolt Case, Map or Scroll Case, Parchment, Pouch, Quiver, Waterskin","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"5.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_light-crossbow', 'Light Crossbow', 'Weapon', '{"key":"srd-2024_light-crossbow","name":"Light Crossbow","desc":"A light crossbow.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Light Crossbow","key":"srd-2024_light-crossbow","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1d8","properties":[{"property":{"name":"Ammunition","type":null,"desc":"You can use a weapon that has the Ammunition property to make a ranged attack only if you have ammunition to fire from it. The type of ammunition required is specified with the weapon''s range. Each attack expends one piece of ammunition. Drawing the ammunition is part of the attack (you need a free hand to load a one-handed weapon). After a fight, you can spend 1 minute to recover half the ammunition (round down) you used in the fight; the rest is lost."},"detail":"Range 80/320; Bolt"},{"property":{"name":"Loading","type":null,"desc":"You can fire only one piece of ammunition from a Loading weapon when you use an action, a Bonus Action, or a Reaction to fire it, regardless of the number of attacks you can normally make."},"detail":null},{"property":{"name":"Slow","type":"Mastery","desc":"If you hit a creature with this weapon and deal damage to it, you can reduce its Speed by 10 feet until the start of your next turn. If the creature is hit more than once by weapons that have this property, the Speed reduction doesn''t exceed 10 feet."},"detail":null},{"property":{"name":"Two-Handed","type":null,"desc":"A Two-Handed weapon requires two hands when you attack with it."},"detail":null}],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"5.000","weight_unit":"lb","cost":"25.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_light-hammer', 'Light Hammer', 'Weapon', '{"key":"srd-2024_light-hammer","name":"Light Hammer","desc":"A light hammer.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Light Hammer","key":"srd-2024_light-hammer","damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"damage_dice":"1d4","properties":[{"property":{"name":"Light","type":null,"desc":"When you take the Attack action on your turn and attack with a Light weapon, you can make one extra attack as a Bonus Action later on the same turn. That extra attack must be made with a different Light weapon, and you don''t add your ability modifier to the extra attack''s damage unless that modifier is negative."},"detail":null},{"property":{"name":"Nick","type":"Mastery","desc":"When you make the extra attack of the Light property, you can make it as part of the Attack action instead of as a Bonus Action. You can make this extra attack only once per turn."},"detail":null},{"property":{"name":"Thrown","type":null,"desc":"If a weapon has the Thrown property, you can throw the weapon to make a ranged attack, and you can draw that weapon as part of the attack. If the weapon is a Melee weapon, use the same ability modifier for the attack and damage rolls that you use for a melee attack with that weapon."},"detail":"Range 20/60"}],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"2.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_lock', 'Lock', 'Adventuring Gear', '{"key":"srd-2024_lock","name":"Lock","desc":"A Lock comes with a key. Without the key, a creature can use Thieves'' Tools to pick this Lock with a successful DC 15 Dexterity (Sleight of Hand) check.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"1.000","weight_unit":"lb","cost":"10.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_longbow', 'Longbow', 'Weapon', '{"key":"srd-2024_longbow","name":"Longbow","desc":"A longbow.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Longbow","key":"srd-2024_longbow","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1d8","properties":[{"property":{"name":"Ammunition","type":null,"desc":"You can use a weapon that has the Ammunition property to make a ranged attack only if you have ammunition to fire from it. The type of ammunition required is specified with the weapon''s range. Each attack expends one piece of ammunition. Drawing the ammunition is part of the attack (you need a free hand to load a one-handed weapon). After a fight, you can spend 1 minute to recover half the ammunition (round down) you used in the fight; the rest is lost."},"detail":"Range 150/600; Arrow"},{"property":{"name":"Heavy","type":null,"desc":"You have Disadvantage on attack rolls with a Heavy weapon if it''s a Melee weapon and your Strength score isn''t at least 13 or if it''s a Ranged weapon and your Dexterity score isn''t at least 13."},"detail":null},{"property":{"name":"Slow","type":"Mastery","desc":"If you hit a creature with this weapon and deal damage to it, you can reduce its Speed by 10 feet until the start of your next turn. If the creature is hit more than once by weapons that have this property, the Speed reduction doesn''t exceed 10 feet."},"detail":null},{"property":{"name":"Two-Handed","type":null,"desc":"A Two-Handed weapon requires two hands when you attack with it."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"50.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_longship', 'Longship', 'Waterborne Vehicle', '{"key":"srd-2024_longship","name":"Longship","desc":"A swift ship designed for raiding and exploration.","category":{"name":"Waterborne Vehicle","key":"waterborne-vehicle"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"10000.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_longsword', 'Longsword', 'Weapon', '{"key":"srd-2024_longsword","name":"Longsword","desc":"A longsword.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Longsword","key":"srd-2024_longsword","damage_type":{"name":"Slashing","key":"slashing"},"damage_dice":"1d8","properties":[{"property":{"name":"Sap","type":"Mastery","desc":"If you hit a creature with this weapon, that creature has Disadvantage on its next attack roll before the start of your next turn."},"detail":null},{"property":{"name":"Versatile","type":null,"desc":"A Versatile weapon can be used with one or two hands. A damage value in parentheses appears with the property. The weapon deals that damage when used with two hands to make a melee attack."},"detail":"1d10"}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"3.000","weight_unit":"lb","cost":"15.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
