  ('srd-2024_perfume', 'Perfume', 'Adventuring Gear', '{"key":"srd-2024_perfume","name":"Perfume","desc":"Perfume comes in a 4-ounce vial. For 1 hour after applying Perfume to yourself, you have Advantage on Charisma (Persuasion) checks made to influence an Indifferent Humanoid within 5 feet of yourself.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_pike', 'Pike', 'Weapon', '{"key":"srd-2024_pike","name":"Pike","desc":"A pike.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Pike","key":"srd-2024_pike","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1d10","properties":[{"property":{"name":"Heavy","type":null,"desc":"You have Disadvantage on attack rolls with a Heavy weapon if it''s a Melee weapon and your Strength score isn''t at least 13 or if it''s a Ranged weapon and your Dexterity score isn''t at least 13."},"detail":null},{"property":{"name":"Push","type":"Mastery","desc":"If you hit a creature with this weapon, you can push the creature up to 10 feet straight away from yourself if it is Large or smaller."},"detail":null},{"property":{"name":"Reach","type":null,"desc":"A Reach weapon adds 5 feet to your reach when you attack with it, as well as when determining your reach for Opportunity Attacks with it."},"detail":null},{"property":{"name":"Two-Handed","type":null,"desc":"A Two-Handed weapon requires two hands when you attack with it."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"18.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_pistol', 'Pistol', 'Weapon', '{"key":"srd-2024_pistol","name":"Pistol","desc":"A pistol.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Pistol","key":"srd-2024_pistol","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1d10","properties":[{"property":{"name":"Ammunition","type":null,"desc":"You can use a weapon that has the Ammunition property to make a ranged attack only if you have ammunition to fire from it. The type of ammunition required is specified with the weapon''s range. Each attack expends one piece of ammunition. Drawing the ammunition is part of the attack (you need a free hand to load a one-handed weapon). After a fight, you can spend 1 minute to recover half the ammunition (round down) you used in the fight; the rest is lost."},"detail":"Range 30/90; Bullet"},{"property":{"name":"Loading","type":null,"desc":"You can fire only one piece of ammunition from a Loading weapon when you use an action, a Bonus Action, or a Reaction to fire it, regardless of the number of attacks you can normally make."},"detail":null},{"property":{"name":"Vex","type":"Mastery","desc":"If you hit a creature with this weapon and deal damage to the creature, you have Advantage on your next attack roll against that creature before the end of your next turn."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"3.000","weight_unit":"lb","cost":"250.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_plate-armor', 'Plate Armor', 'Armor', '{"key":"srd-2024_plate-armor","name":"Plate Armor","desc":"A plate armor.","category":{"name":"Armor","key":"armor"},"weapon":null,"armor":{"name":"Plate Armor","key":"srd-2024_plate-armor","category":"heavy","ac_base":18,"ac_display":"18","ac_add_dexmod":false,"ac_cap_dexmod":null,"grants_stealth_disadvantage":true,"strength_score_required":15},"size":{"name":"Tiny","key":"tiny"},"weight":"65.000","weight_unit":"lb","cost":"1500.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_poison-basic', 'Poison, Basic', 'Adventuring Gear', '{"key":"srd-2024_poison-basic","name":"Poison, Basic","desc":"As a Bonus Action, you can use a vial of Basic Poison to coat one weapon or up to three pieces of ammunition. A creature that takes Piercing or Slashing damage from the poisoned weapon or ammunition takes an extra 1d4 Poison damage. Once applied, the poison retains potency for 1 minute or until its damage is dealt, whichever comes first.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"100.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_poisoners-kit', 'Poisoner''s Kit', 'Tools', '{"key":"srd-2024_poisoners-kit","name":"Poisoner''s Kit","desc":"Ability: Intelligence. Utilize: Detect a poisoned object (DC 10). Craft: Basic Poison","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"50.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_pole', 'Pole', 'Adventuring Gear', '{"key":"srd-2024_pole","name":"Pole","desc":"A Pole is 10 feet long. You can use it to touch something up to 10 feet away. If you must make a Strength (Athletics) check as part of a High or Long Jump, you can use the Pole to vault, giving yourself Advantage on the check.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"7.000","weight_unit":"lb","cost":"0.05","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_pony', 'Pony', 'Mount', '{"key":"srd-2024_pony","name":"Pony","desc":"A small horse suitable for smaller riders and lighter loads.","category":{"name":"Mount","key":"mount"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"30.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_pot-iron', 'Pot, Iron', 'Adventuring Gear', '{"key":"srd-2024_pot-iron","name":"Pot, Iron","desc":"An Iron Pot holds up to 1 gallon.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"10.000","weight_unit":"lb","cost":"2.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_potion-of-giant-strength', 'Potion of Giant Strength', 'Potion', '{"key":"srd-2024_potion-of-giant-strength","name":"Potion of Giant Strength","desc":"When you drink this potion, your Strength score changes for 1 hour. The type of giant determines the score (see the table below). The potion has no effect on you if your Strength is equal to or greater than that score.\n\nThis potion''s transparent liquid has floating in it a sliver of light resembling a giant''s fingernail.\n\n| Potion                                    | Str. | Rarity    |\n|-------------------------------------------|------|-----------|\n| Potion of Giant Strength (hill)           | 21   | Uncommon  |\n| Potion of Giant Strength (frost or stone) | 23   | Rare      |\n| Potion of Giant Strength (fire)           | 25   | Rare      |\n| Potion of Giant Strength (cloud)          | 27   | Very Rare |\n| Potion of Giant Strength (storm)          | 29   | Legendary |","category":{"name":"Potion","key":"potion"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"0.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_potion-of-healing', 'Potion of Healing', 'Potion', '{"key":"srd-2024_potion-of-healing","name":"Potion of Healing","desc":"This potion is a magic item. As a Bonus Action, you can drink it or administer it to another creature within 5 feet of yourself. The creature that drinks the magical red fluid in this vial regains 2d4 + 2 Hit Points.","category":{"name":"Potion","key":"potion"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.500","weight_unit":"lb","cost":"50.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_potions-of-healing', 'Potions of Healing', 'Potion', '{"key":"srd-2024_potions-of-healing","name":"Potions of Healing","desc":"You regain Hit Points when you drink this potion. The number of Hit Points depends on the potion''s rarity, as shown in the table below.\n\nWhatever its potency, the potion''s red liquid glimmers when agitated.\n\n| Potion                       | HP Regained | Rarity    |\n|------------------------------|-------------|-----------|\n| Potion of Healing            | 2d4 + 2     | Common    |\n| Potion of Healing (greater)  | 4d4 + 4     | Uncommon  |\n| Potion of Healing (superior) | 8d4 + 8     | Rare      |\n| Potion of Healing (supreme)  | 10d4 + 20   | Very Rare |","category":{"name":"Potion","key":"potion"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"0.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_potters-tools', 'Potter''s Tools (10 GP)', 'Tools', '{"key":"srd-2024_potters-tools","name":"Potter''s Tools (10 GP)","desc":"Ability: Intelligence. Utilize: Discern what a ceramic object held in the past 24 hours (DC 15). Craft: Jug, Lamp","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"3.000","weight_unit":"lb","cost":"10.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
