  ('srd-2024_priests-pack', 'Priest''s Pack', 'Equipment Pack', '{"key":"srd-2024_priests-pack","name":"Priest''s Pack","desc":"A Priest''s Pack contains the following items: Backpack, Blanket, Holy Water, Lamp, 7 days of Rations, Robe, and Tinderbox.","category":{"name":"Equipment Pack","key":"equipment-pack"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"29.000","weight_unit":"lb","cost":"33.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_quarterstaff', 'Quarterstaff', 'Weapon', '{"key":"srd-2024_quarterstaff","name":"Quarterstaff","desc":"A quarterstaff.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Quarterstaff","key":"srd-2024_quarterstaff","damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"damage_dice":"1d6","properties":[{"property":{"name":"Topple","type":"Mastery","desc":"If you hit a creature with this weapon, you can force the creature to make a Constitution saving throw (DC 8 plus the ability modifier used to make the attack roll and your Proficiency Bonus). On a failed save, the creature has the Prone condition."},"detail":null},{"property":{"name":"Versatile","type":null,"desc":"A Versatile weapon can be used with one or two hands. A damage value in parentheses appears with the property. The weapon deals that damage when used with two hands to make a melee attack."},"detail":"1d8"}],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"4.000","weight_unit":"lb","cost":"0.20","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
