  ('srd-2024_spear', 'Spear', 'Weapon', '{"key":"srd-2024_spear","name":"Spear","desc":"A spear.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Spear","key":"srd-2024_spear","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1d6","properties":[{"property":{"name":"Sap","type":"Mastery","desc":"If you hit a creature with this weapon, that creature has Disadvantage on its next attack roll before the start of your next turn."},"detail":null},{"property":{"name":"Thrown","type":null,"desc":"If a weapon has the Thrown property, you can throw the weapon to make a ranged attack, and you can draw that weapon as part of the attack. If the weapon is a Melee weapon, use the same ability modifier for the attack and damage rolls that you use for a melee attack with that weapon."},"detail":"Range 20/60"},{"property":{"name":"Versatile","type":null,"desc":"A Versatile weapon can be used with one or two hands. A damage value in parentheses appears with the property. The weapon deals that damage when used with two hands to make a melee attack."},"detail":"1d8"}],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"3.000","weight_unit":"lb","cost":"1.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_spell-scroll', 'Spell Scroll', 'Scroll', '{"key":"srd-2024_spell-scroll","name":"Spell Scroll","desc":"A Spell Scroll (Cantrip) or Spell Scroll (Level 1) is a magic item that bears the words of a cantrip or level 1 spell, respectively, determined by the scroll''s creator. If the spell is on your class''s spell list, you can read the scroll and cast the spell using its normal casting time and without providing any Material components. If the spell requires a saving throw or an attack roll, the spell save DC is 13, and the attack bonus is +5. The scroll disintegrates when the casting is completed.","category":{"name":"Scroll","key":"scroll"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"30.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd-2024_spikes-iron', 'Spikes, Iron', 'Adventuring Gear', '{"key":"srd-2024_spikes-iron","name":"Spikes, Iron","desc":"Iron Spikes come in bundles of ten. As a Utilize action, you can use a blunt object, such as a Light Hammer, to hammer a spike into wood, earth, or a similar material. You can do so to jam a door shut or to then tie a Rope or Chain to the Spike.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"5.000","weight_unit":"lb","cost":"1.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
