  ('srd-2024_warhammer', 'Warhammer', 'Weapon', '{"key":"srd-2024_warhammer","name":"Warhammer","desc":"A warhammer.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Warhammer","key":"srd-2024_warhammer","damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"damage_dice":"1d8","properties":[{"property":{"name":"Push","type":"Mastery","desc":"If you hit a creature with this weapon, you can push the creature up to 10 feet straight away from yourself if it is Large or smaller."},"detail":null},{"property":{"name":"Versatile","type":null,"desc":"A Versatile weapon can be used with one or two hands. A damage value in parentheses appears with the property. The weapon deals that damage when used with two hands to make a melee attack."},"detail":"1d10"}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"5.000","weight_unit":"lb","cost":"15.00","document":{"name":"System Reference Document 5.2","key":"srd-2024","type":"SOURCE","display_name":"5e 2024 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2024","key":"5e-2024"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
