  ('srd_block-and-tackle', 'Block and Tackle', 'Adventuring Gear', '{"key":"srd_block-and-tackle","name":"Block and Tackle","desc":"A set of pulleys with a cable threaded through them and a hook to attach to objects, a block and tackle allows you to hoist up to four times the weight you can normally lift.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"5.000","weight_unit":"lb","cost":"1.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_blowgun', 'Blowgun', 'Weapon', '{"key":"srd_blowgun","name":"Blowgun","desc":"A blowgun.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Blowgun","key":"srd_blowgun","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1","properties":[{"property":{"name":"Ammunition","type":null,"desc":"You can use a weapon that has the ammunition property to make a ranged attack only if you have ammunition to fire from the weapon. Each time you attack with the weapon, you expend one piece of ammunition. Drawing the ammunition from a quiver, case, or other container is part of the attack (you need a free hand to load a one-­‐‑handed weapon). At the end of the battle, you can recover half your expended ammunition by taking a minute to search the battlefield.\n\nIf you use a weapon that has the ammunition property to make a melee attack, you treat the weapon as an improvised weapon (see “Improvised Weapons” later in the section). A sling must be loaded to deal any damage when used in this way."},"detail":"range 25/100"},{"property":{"name":"Loading","type":null,"desc":"Because of the time required to load this weapon, you can fire only one piece of ammunition from it when you use an action, bonus action, or reaction to fire it, regardless of the number of attacks you can normally make."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"1.000","weight_unit":"lb","cost":"10.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_blowgun-needles', 'Blowgun needles', 'Ammunition', '{"key":"srd_blowgun-needles","name":"Blowgun needles","desc":"Needles to be fired with a blowgun.","category":{"name":"Ammunition","key":"ammunition"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.020","weight_unit":"lb","cost":"0.02","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_book', 'Book', 'Adventuring Gear', '{"key":"srd_book","name":"Book","desc":"A book might contain poetry, historical accounts, information pertaining to a particular field of lore, diagrams and notes on gnomish contraptions, or just about anything else that can be represented using text or pictures. A book of spells is a spellbook (described later in this section).","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"5.000","weight_unit":"lb","cost":"25.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_bottle-glass', 'Bottle, glass', 'Adventuring Gear', '{"key":"srd_bottle-glass","name":"Bottle, glass","desc":"A glass bottle. Capacity: 1.5 pints liquid.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"2.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_breastplate', 'Breastplate', 'Armor', '{"key":"srd_breastplate","name":"Breastplate","desc":"This armor consists of a fitted metal chest piece worn with supple leather. Although it leaves the legs and arms relatively unprotected, this armor provides good protection for the wearer''s vital organs while leaving the wearer relatively unencumbered.","category":{"name":"Armor","key":"armor"},"weapon":null,"armor":{"name":"Breastplate","key":"srd_breastplate","category":"medium","ac_base":14,"ac_display":"14 + Dex modifier (max 2)","ac_add_dexmod":true,"ac_cap_dexmod":2,"grants_stealth_disadvantage":false,"strength_score_required":null},"size":{"name":"Tiny","key":"tiny"},"weight":"20.000","weight_unit":"lb","cost":"400.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_brewers-supplies', 'Brewer''s Supplies', 'Tools', '{"key":"srd_brewers-supplies","name":"Brewer''s Supplies","desc":"These special tools include the items needed to pursue a craft or trade.\\n\\n\r\nProficiency with a set of artisan’s tools lets you add your proficiency bonus to any ability checks you make using the tools in your craft. Each type of artisan’s tools requires a separate proficiency.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"9.000","weight_unit":"lb","cost":"20.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_bucket', 'Bucket', 'Adventuring Gear', '{"key":"srd_bucket","name":"Bucket","desc":"A bucket. Capacity: 3 gallons liquid, 1/2 cubic foot solid.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"0.05","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_burnt-othur-fumes', 'Burnt othur fumes', 'Poison', '{"key":"srd_burnt-othur-fumes","name":"Burnt othur fumes","desc":"A creature subjected to this poison must succeed on a DC 13 Constitution saving throw or take 10 (3d6) poison damage, and must repeat the saving throw at the start of each of its turns. On each successive failed save, the character takes 3 (1d6) poison damage. After three successful saves, the poison ends.\\n\\n**_Inhaled._** These poisons are powders or gases that take effect when inhaled. Blowing the powder or releasing the gas subjects creatures in a 5-foot cube to its effect. The resulting cloud dissipates immediately afterward. Holding one''s breath is ineffective against inhaled poisons, as they affect nasal membranes, tear ducts, and other parts of the body.","category":{"name":"Poison","key":"poison"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"500.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_calligraphers-supplies', 'Calligrapher''s supplies', 'Tools', '{"key":"srd_calligraphers-supplies","name":"Calligrapher''s supplies","desc":"These special tools include the items needed to pursue a craft or trade.\\n\\n\r\nProficiency with a set of artisan’s tools lets you add your proficiency bonus to any ability checks you make using the tools in your craft. Each type of artisan’s tools requires a separate proficiency.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"5.000","weight_unit":"lb","cost":"10.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_caltrops-bag-of-20', 'Caltrops (bag of 20)', 'Adventuring Gear', '{"key":"srd_caltrops-bag-of-20","name":"Caltrops (bag of 20)","desc":"As an action, you can spread a bag of caltrops to cover a square area that is 5 feet on a side. Any creature that enters the area must succeed on a DC 15 Dexterity saving throw or stop moving this turn and take 1 piercing damage. Taking this damage reduces the creature''s walking speed by 10 feet until the creature regains at least 1 hit point. A creature moving through the area at half speed doesn''t need to make the save.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"1.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
