  ('srd_chain-10-feet', 'Chain (10 feet)', 'Adventuring Gear', '{"key":"srd_chain-10-feet","name":"Chain (10 feet)","desc":"A chain has 10 hit points. It can be burst with a successful DC 20 Strength check.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"10.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_chain-mail', 'Chain mail', 'Armor', '{"key":"srd_chain-mail","name":"Chain mail","desc":"Made of interlocking metal rings, chain mail includes a layer of quilted fabric worn underneath the mail to prevent chafing and to cushion the impact of blows. The suit includes gauntlets.","category":{"name":"Armor","key":"armor"},"weapon":null,"armor":{"name":"Chain mail","key":"srd_chain-mail","category":"heavy","ac_base":16,"ac_display":"16","ac_add_dexmod":false,"ac_cap_dexmod":null,"grants_stealth_disadvantage":true,"strength_score_required":13},"size":{"name":"Tiny","key":"tiny"},"weight":"55.000","weight_unit":"lb","cost":"75.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_chain-shirt', 'Chain shirt', 'Armor', '{"key":"srd_chain-shirt","name":"Chain shirt","desc":"Made of interlocking metal rings, a chain shirt is worn between layers of clothing or leather. This armor offers modest protection to the wearer''s upper body and allows the sound of the rings rubbing against one another to be muffled by outer layers.","category":{"name":"Armor","key":"armor"},"weapon":null,"armor":{"name":"Chain shirt","key":"srd_chain-shirt","category":"medium","ac_base":13,"ac_display":"13 + Dex modifier (max 2)","ac_add_dexmod":true,"ac_cap_dexmod":2,"grants_stealth_disadvantage":false,"strength_score_required":null},"size":{"name":"Tiny","key":"tiny"},"weight":"20.000","weight_unit":"lb","cost":"50.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
