  ('srd_climbers-kit', 'Climber''s Kit', 'Adventuring Gear', '{"key":"srd_climbers-kit","name":"Climber''s Kit","desc":"A climber''s kit includes special pitons, boot tips, gloves, and a harness. You can use the climber''s kit as an action to anchor yourself; when you do, you can''t fall more than 25 feet from the point where you anchored yourself, and you can''t climb more than 25 feet away from that point without undoing the anchor.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"12.000","weight_unit":"lb","cost":"25.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
