  ('srd_copper-piece', 'Copper Piece', 'Trade Good', '{"key":"srd_copper-piece","name":"Copper Piece","desc":"One silver piece is worth ten copper pieces, which are common among laborers and beggars. A single copper piece buys a candle, a torch, or a piece of chalk.","category":{"name":"Trade Good","key":"trade-good"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.020","weight_unit":"lb","cost":"0.01","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
