  ('srd_forgery-kit', 'Forgery kit', 'Tools', '{"key":"srd_forgery-kit","name":"Forgery kit","desc":"This small box contains a variety of papers and parchments, pens and inks, seals and sealing wax, gold and silver leaf, and other supplies necessary to create convincing forgeries of physical documents. \\n\\nProficiency with this kit lets you add your proficiency bonus to any ability checks you make to create a physical forgery of a document.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"5.000","weight_unit":"lb","cost":"15.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
