  ('srd_glaive', 'Glaive', 'Weapon', '{"key":"srd_glaive","name":"Glaive","desc":"A glaive.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Glaive","key":"srd_glaive","damage_type":{"name":"Slashing","key":"slashing"},"damage_dice":"1d10","properties":[{"property":{"name":"Reach","type":null,"desc":"This weapon adds 5 feet to your reach when you attack with it, as well as when determining your reach for opportunity attacks with it."},"detail":null},{"property":{"name":"Two-Handed","type":null,"desc":"This weapon requires two hands when you attack with it."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"6.000","weight_unit":"lb","cost":"20.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_glassblowers-tools', 'Glassblower''s Tools', 'Tools', '{"key":"srd_glassblowers-tools","name":"Glassblower''s Tools","desc":"These special tools include the items needed to pursue a craft or trade.\\n\\n\r\nProficiency with a set of artisan’s tools lets you add your proficiency bonus to any ability checks you make using the tools in your craft. Each type of artisan’s tools requires a separate proficiency.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"5.000","weight_unit":"lb","cost":"30.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
