  ('srd_gold', 'Gold', 'Trade Good', '{"key":"srd_gold","name":"Gold","desc":"1lb of gold.","category":{"name":"Trade Good","key":"trade-good"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"1.000","weight_unit":"lb","cost":"50.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_gold-piece', 'Gold Piece', 'Trade Good', '{"key":"srd_gold-piece","name":"Gold Piece","desc":"With one gold piece, a character can buy a bedroll, 50 feet of good rope, or a goat. A skilled (but not exceptional) artisan can earn one gold piece a day. The gold piece is the standard unit of measure for wealth, even if the coin itself is not commonly used. When merchants discuss deals that involve goods or services worth hundreds or thousands of gold pieces, the transactions don''t usually involve the exchange of individual coins. Rather, the gold piece is a standard measure of value, and the actual exchange is in gold bars, letters of credit, or valuable goods.","category":{"name":"Trade Good","key":"trade-good"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.020","weight_unit":"lb","cost":"1.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
