  ('srd_half-plate', 'Half plate', 'Armor', '{"key":"srd_half-plate","name":"Half plate","desc":"Half plate consists of shaped metal plates that cover most of the wearer''s body. It does not include leg protection beyond simple greaves that are attached with leather straps.","category":{"name":"Armor","key":"armor"},"weapon":null,"armor":{"name":"Half plate","key":"srd_half-plate","category":"medium","ac_base":15,"ac_display":"15 + Dex modifier (max 2)","ac_add_dexmod":true,"ac_cap_dexmod":2,"grants_stealth_disadvantage":true,"strength_score_required":null},"size":{"name":"Tiny","key":"tiny"},"weight":"40.000","weight_unit":"lb","cost":"750.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
