  ('srd_lock', 'Lock', 'Adventuring Gear', '{"key":"srd_lock","name":"Lock","desc":"A key is provided with the lock. Without the key, a creature proficient with thieves’ tools can pick this lock with a successful DC 15 Dexterity check. Your GM may decide that better locks are available for higher prices.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"1.000","weight_unit":"lb","cost":"10.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_longbow', 'Longbow', 'Weapon', '{"key":"srd_longbow","name":"Longbow","desc":"A longbow.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Longbow","key":"srd_longbow","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1d8","properties":[{"property":{"name":"Ammunition","type":null,"desc":"You can use a weapon that has the ammunition property to make a ranged attack only if you have ammunition to fire from the weapon. Each time you attack with the weapon, you expend one piece of ammunition. Drawing the ammunition from a quiver, case, or other container is part of the attack (you need a free hand to load a one-­‐‑handed weapon). At the end of the battle, you can recover half your expended ammunition by taking a minute to search the battlefield.\n\nIf you use a weapon that has the ammunition property to make a melee attack, you treat the weapon as an improvised weapon (see “Improvised Weapons” later in the section). A sling must be loaded to deal any damage when used in this way."},"detail":"range 150/600"},{"property":{"name":"Two-Handed","type":null,"desc":"This weapon requires two hands when you attack with it."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"50.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_longship', 'Longship', 'Waterborne Vehicle', '{"key":"srd_longship","name":"Longship","desc":"Waterborne vehicle. Speed 3mph.","category":{"name":"Waterborne Vehicle","key":"waterborne-vehicle"},"weapon":null,"armor":null,"size":{"name":"Gargantuan","key":"gargantuan"},"weight":"0.000","weight_unit":"lb","cost":"10000.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_longsword', 'Longsword', 'Weapon', '{"key":"srd_longsword","name":"Longsword","desc":"A longsword","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Longsword","key":"srd_longsword","damage_type":{"name":"Slashing","key":"slashing"},"damage_dice":"1d8","properties":[{"property":{"name":"Versatile","type":null,"desc":"This weapon can be used with one or two hands. A damage value in parentheses appears with the property—the damage when the weapon is used with two hands to make a melee attack."},"detail":"1d10"}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"3.000","weight_unit":"lb","cost":"15.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_lute', 'Lute', 'Tools', '{"key":"srd_lute","name":"Lute","desc":"Several of the most common types of musical instruments are shown on the table as examples. If you have proficiency with a given musical instrument, you can add your proficiency bonus to any ability checks you make to play music with the instrument. A bard can use a musical instrument as a spellcasting focus. Each type of musical instrument requires a separate proficiency.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"35.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_lyre', 'Lyre', 'Tools', '{"key":"srd_lyre","name":"Lyre","desc":"Several of the most common types of musical instruments are shown on the table as examples. If you have proficiency with a given musical instrument, you can add your proficiency bonus to any ability checks you make to play music with the instrument. A bard can use a musical instrument as a spellcasting focus. Each type of musical instrument requires a separate proficiency.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"30.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_mace', 'Mace', 'Weapon', '{"key":"srd_mace","name":"Mace","desc":"A mace.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Mace","key":"srd_mace","damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"damage_dice":"1d6","properties":[],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"4.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_magnifying-glass', 'Magnifying Glass', 'Adventuring Gear', '{"key":"srd_magnifying-glass","name":"Magnifying Glass","desc":"This lens allows a closer look at small objects. It is also useful as a substitute for flint and steel when starting fires. Lighting a fire with a magnifying glass requires light as bright as sunlight to focus, tinder to ignite, and about 5 minutes for the fire to ignite. A magnifying glass grants advantage on any ability check made to appraise or inspect an item that is small or highly detailed.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"100.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_malice', 'Malice', 'Poison', '{"key":"srd_malice","name":"Malice","desc":"A creature subjected to this poison must succeed on a DC 15 Constitution saving throw or become poisoned for 1 hour. The poisoned creature is blinded.\\n\\n**_Inhaled._** These poisons are powders or gases that take effect when inhaled. Blowing the powder or releasing the gas subjects creatures in a 5-foot cube to its effect. The resulting cloud dissipates immediately afterward. Holding one''s breath is ineffective against inhaled poisons, as they affect nasal membranes, tear ducts, and other parts of the body.","category":{"name":"Poison","key":"poison"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"250.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_manacles', 'Manacles', 'Adventuring Gear', '{"key":"srd_manacles","name":"Manacles","desc":"These metal restraints can bind a Small or Medium creature. Escaping the manacles requires a successful DC 20 Dexterity check. Breaking them requires a successful DC 20 Strength check. Each set of manacles comes with one key. Without the key, a creature proficient with thieves’ tools can pick the manacles’ lock with a successful DC 15 Dexterity check. Manacles have 15 hit points.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"6.000","weight_unit":"lb","cost":"2.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_masons-tools', 'Mason''s Tools', 'Tools', '{"key":"srd_masons-tools","name":"Mason''s Tools","desc":"These special tools include the items needed to pursue a craft or trade.\\n\\n\r\nProficiency with a set of artisan’s tools lets you add your proficiency bonus to any ability checks you make using the tools in your craft. Each type of artisan’s tools requires a separate proficiency.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"8.000","weight_unit":"lb","cost":"10.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_maul', 'Maul', 'Weapon', '{"key":"srd_maul","name":"Maul","desc":"A maul.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Maul","key":"srd_maul","damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"damage_dice":"2d6","properties":[{"property":{"name":"Two-Handed","type":null,"desc":"This weapon requires two hands when you attack with it."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"10.000","weight_unit":"lb","cost":"10.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_mess-kit', 'Mess Kit', 'Adventuring Gear', '{"key":"srd_mess-kit","name":"Mess Kit","desc":"This tin box contains a cup and simple cutlery. The box clamps together, and one side can be used as a cooking pan and the other as a plate or shallow bowl.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"1.000","weight_unit":"lb","cost":"0.20","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_midnight-tears', 'Midnight tears', 'Poison', '{"key":"srd_midnight-tears","name":"Midnight tears","desc":"A creature that ingests this poison suffers no effect until the stroke of midnight. If the poison has not been neutralized before then, the creature must succeed on a DC 17 Constitution saving throw, taking 31 (9d6) poison damage on a failed save, or half as much damage on a successful one.\\n\\n **_Ingested._** A creature must swallow an entire dose of ingested poison to suffer its effects. The dose can be delivered in food or a liquid. You may decide that a partial dose has a reduced effect, such as allowing advantage on the saving throw or dealing only half damage on a failed save.","category":{"name":"Poison","key":"poison"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"1500.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_mirror-steel', 'Mirror, steel', 'Adventuring Gear', '{"key":"srd_mirror-steel","name":"Mirror, steel","desc":"A mirror.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.500","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_morningstar', 'Morningstar', 'Weapon', '{"key":"srd_morningstar","name":"Morningstar","desc":"A morningstar","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Morningstar","key":"srd_morningstar","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1d8","properties":[],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"4.000","weight_unit":"lb","cost":"15.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_navigators-tools', 'Navigator''s tools', 'Tools', '{"key":"srd_navigators-tools","name":"Navigator''s tools","desc":"This set of instruments is used for navigation at sea. Proficiency with navigator''s tools lets you chart a ship''s course and follow navigation charts. In addition, these tools allow you to add your proficiency bonus to any ability check you make to avoid getting lost at sea.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"25.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_net', 'Net', 'Weapon', '{"key":"srd_net","name":"Net","desc":"A net.\r\n\r\nA Large or smaller creature hit by a net is restrained until it is freed. A net has no effect on creatures that are formless, or creatures that are Huge or larger. A creature can use its action to make a DC 10 Strength check, freeing itself or another creature within its reach on a success. Dealing 5 slashing damage to the net (AC 10) also frees the creature without harming it, ending the effect and destroying the net.\r\n\r\nWhen you use an action, bonus action, or reaction to attack with a net, you can make only one attack regardless of the number of attacks you can normally make.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Net","key":"srd_net","damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"damage_dice":"0","properties":[{"property":{"name":"Special (Net)","type":null,"desc":"A Large or smaller creature hit by a net is restrained until it is freed. A net has no effect on creatures that are formless, or creatures that are Huge or larger. A creature can use its action to make a DC 10 Strength check, freeing itself or another creature within its reach on a success. Dealing 5 slashing damage to the net (AC 10) also frees the creature without harming it, ending the effect and destroying the net.\n\nWhen you use an action, bonus action, or reaction to attack with a net, you can make only one attack regardless of the number of attacks you can normally make."},"detail":null},{"property":{"name":"Thrown","type":null,"desc":"If a weapon has the thrown property, you can throw the weapon to make a ranged attack. If the weapon is a melee weapon, you use the same ability modifier for that attack roll and damage roll that you would use for a melee attack with the weapon. For example, if you throw a handaxe, you use your Strength, but if you throw a dagger, you can use either your Strength or your Dexterity, since the dagger has the finesse property."},"detail":"range 5/15"}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"3.000","weight_unit":"lb","cost":"1.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_oil-of-taggit', 'Oil of taggit', 'Poison', '{"key":"srd_oil-of-taggit","name":"Oil of taggit","desc":"A creature subjected to this poison must succeed on a DC 13 Constitution saving throw or become poisoned for 24 hours. The poisoned creature is unconscious. The creature wakes up if it takes damage.\\n\\n **_Contact._** Contact poison can be smeared on an object and remains potent until it is touched or washed off. A creature that touches contact poison with exposed skin suffers its effects.","category":{"name":"Poison","key":"poison"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"400.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_orb', 'Orb', 'Adventuring Gear', '{"key":"srd_orb","name":"Orb","desc":"Can be used as an Arcane Focus.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"3.000","weight_unit":"lb","cost":"20.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_ox', 'Ox', 'Trade Good', '{"key":"srd_ox","name":"Ox","desc":"One ox.","category":{"name":"Trade Good","key":"trade-good"},"weapon":null,"armor":null,"size":{"name":"Large","key":"large"},"weight":"1500.000","weight_unit":"lb","cost":"15.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_padded-armor', 'Padded Armor', 'Armor', '{"key":"srd_padded-armor","name":"Padded Armor","desc":"Padded armor consists of quilted layers of cloth and batting.","category":{"name":"Armor","key":"armor"},"weapon":null,"armor":{"name":"Padded","key":"srd_padded","category":"light","ac_base":11,"ac_display":"11 + Dex modifier","ac_add_dexmod":true,"ac_cap_dexmod":null,"grants_stealth_disadvantage":true,"strength_score_required":null},"size":{"name":"Tiny","key":"tiny"},"weight":"8.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_painters-supplies', 'Painter''s Supplies', 'Tools', '{"key":"srd_painters-supplies","name":"Painter''s Supplies","desc":"These special tools include the items needed to pursue a craft or trade.\\n\\n\r\nProficiency with a set of artisan’s tools lets you add your proficiency bonus to any ability checks you make using the tools in your craft. Each type of artisan’s tools requires a separate proficiency.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"5.000","weight_unit":"lb","cost":"10.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_pale-tincture', 'Pale tincture', 'Poison', '{"key":"srd_pale-tincture","name":"Pale tincture","desc":"A creature subjected to this poison must succeed on a DC 16 Constitution saving throw or take 3 (1d6) poison damage and become poisoned. The poisoned creature must repeat the saving throw every 24 hours, taking 3 (1d6) poison damage on a failed save. Until this poison ends, the damage the poison deals can''t be healed by any means. After seven successful saving throws, the effect ends and the creature can heal normally. \\n\\n **_Ingested._** A creature must swallow an entire dose of ingested poison to suffer its effects. The dose can be delivered in food or a liquid. You may decide that a partial dose has a reduced effect, such as allowing advantage on the saving throw or dealing only half damage on a failed save.","category":{"name":"Poison","key":"poison"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"250.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_pan-flute', 'Pan flute', 'Tools', '{"key":"srd_pan-flute","name":"Pan flute","desc":"Several of the most common types of musical instruments are shown on the table as examples. If you have proficiency with a given musical instrument, you can add your proficiency bonus to any ability checks you make to play music with the instrument. A bard can use a musical instrument as a spellcasting focus. Each type of musical instrument requires a separate proficiency.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"2.000","weight_unit":"lb","cost":"12.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
