  ('srd_torpor', 'Torpor', 'Poison', '{"key":"srd_torpor","name":"Torpor","desc":"A creature subjected to this poison must succeed on a DC 15 Constitution saving throw or become poisoned for 4d6 hours. The poisoned creature is incapacitated.\r\n\\n\\n\r\n**_Ingested._** A creature must swallow an entire dose of ingested poison to suffer its effects. The dose can be delivered in food or a liquid. You may decide that a partial dose has a reduced effect, such as allowing advantage on the saving throw or dealing only half damage on a failed save.","category":{"name":"Poison","key":"poison"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"600.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
