  ('srd_whip', 'Whip', 'Weapon', '{"key":"srd_whip","name":"Whip","desc":"A whip.","category":{"name":"Weapon","key":"weapon"},"weapon":{"name":"Whip","key":"srd_whip","damage_type":{"name":"Slashing","key":"slashing"},"damage_dice":"1d4","properties":[{"property":{"name":"Reach","type":null,"desc":"This weapon adds 5 feet to your reach when you attack with it, as well as when determining your reach for opportunity attacks with it."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"3.000","weight_unit":"lb","cost":"2.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_woodcarvers-tools', 'Woodcarver''s tools', 'Tools', '{"key":"srd_woodcarvers-tools","name":"Woodcarver''s tools","desc":"These special tools include the items needed to pursue a craft or trade.\\n\\n\r\nProficiency with a set of artisan’s tools lets you add your proficiency bonus to any ability checks you make using the tools in your craft. Each type of artisan’s tools requires a separate proficiency.","category":{"name":"Tools","key":"tools"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"5.000","weight_unit":"lb","cost":"1.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_wooden-staff', 'Wooden staff', 'Adventuring Gear', '{"key":"srd_wooden-staff","name":"Wooden staff","desc":"Can be used as a druidic focus.","category":{"name":"Adventuring Gear","key":"adventuring-gear"},"weapon":{"name":"Quarterstaff","key":"srd_quarterstaff","damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"damage_dice":"1d6","properties":[{"property":{"name":"Versatile","type":null,"desc":"This weapon can be used with one or two hands. A damage value in parentheses appears with the property—the damage when the weapon is used with two hands to make a melee attack."},"detail":"1d8"}],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"},"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"4.000","weight_unit":"lb","cost":"5.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_wyvern-poison', 'Wyvern poison', 'Poison', '{"key":"srd_wyvern-poison","name":"Wyvern poison","desc":"This poison must be harvested from a dead or incapacitated wyvern. A creature subjected to this poison must make a DC 15 Constitution saving throw, taking 24 (7d6) poison damage on a failed save, or half as much damage on a successful one.\r\n\\n\\n\r\n**_Injury._** Injury poison can be applied to weapons, ammunition, trap components, and other objects that deal piercing or slashing damage and remains potent until delivered through a wound or washed off. A creature that takes piercing or slashing damage from an object coated with the poison is exposed to its effects.","category":{"name":"Poison","key":"poison"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"0.000","weight_unit":"lb","cost":"1200.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb),
  ('srd_yew-wand', 'Yew wand', 'Wand', '{"key":"srd_yew-wand","name":"Yew wand","desc":"Can be used as a druidic focus.","category":{"name":"Wand","key":"wand"},"weapon":null,"armor":null,"size":{"name":"Tiny","key":"tiny"},"weight":"1.000","weight_unit":"lb","cost":"10.00","document":{"name":"System Reference Document 5.1","key":"srd-2014","type":"SOURCE","display_name":"5e 2014 Rules","publisher":{"name":"Wizards of the Coast","key":"wizards-of-the-coast"},"gamesystem":{"name":"5th Edition 2014","key":"5e-2014"},"permalink":"https://dnd.wizards.com/resources/systems-reference-document"},"crossreferences":{"to":[]}}'::jsonb)
insert into srd_weapons (key, damage_type, damage_dice, is_simple, is_martial, is_improvised, data)
values
  ('srd-2024_battleaxe', 'Slashing', '1d8', false, true, false, '{"name":"Battleaxe","key":"srd-2024_battleaxe","damage_type":{"name":"Slashing","key":"slashing"},"damage_dice":"1d8","properties":[{"property":{"name":"Topple","type":"Mastery","desc":"If you hit a creature with this weapon, you can force the creature to make a Constitution saving throw (DC 8 plus the ability modifier used to make the attack roll and your Proficiency Bonus). On a failed save, the creature has the Prone condition."},"detail":null},{"property":{"name":"Versatile","type":null,"desc":"A Versatile weapon can be used with one or two hands. A damage value in parentheses appears with the property. The weapon deals that damage when used with two hands to make a melee attack."},"detail":"1d10"}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"}'::jsonb),
  ('srd-2024_blowgun', 'Piercing', '1', false, true, false, '{"name":"Blowgun","key":"srd-2024_blowgun","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1","properties":[{"property":{"name":"Ammunition","type":null,"desc":"You can use a weapon that has the Ammunition property to make a ranged attack only if you have ammunition to fire from it. The type of ammunition required is specified with the weapon''s range. Each attack expends one piece of ammunition. Drawing the ammunition is part of the attack (you need a free hand to load a one-handed weapon). After a fight, you can spend 1 minute to recover half the ammunition (round down) you used in the fight; the rest is lost."},"detail":"Range 25/100; Needle"},{"property":{"name":"Loading","type":null,"desc":"You can fire only one piece of ammunition from a Loading weapon when you use an action, a Bonus Action, or a Reaction to fire it, regardless of the number of attacks you can normally make."},"detail":null},{"property":{"name":"Vex","type":"Mastery","desc":"If you hit a creature with this weapon and deal damage to the creature, you have Advantage on your next attack roll against that creature before the end of your next turn."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"}'::jsonb),
  ('srd-2024_club', 'Bludgeoning', '1d4', true, false, false, '{"name":"Club","key":"srd-2024_club","damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"damage_dice":"1d4","properties":[{"property":{"name":"Light","type":null,"desc":"When you take the Attack action on your turn and attack with a Light weapon, you can make one extra attack as a Bonus Action later on the same turn. That extra attack must be made with a different Light weapon, and you don''t add your ability modifier to the extra attack''s damage unless that modifier is negative."},"detail":null},{"property":{"name":"Slow","type":"Mastery","desc":"If you hit a creature with this weapon and deal damage to it, you can reduce its Speed by 10 feet until the start of your next turn. If the creature is hit more than once by weapons that have this property, the Speed reduction doesn''t exceed 10 feet."},"detail":null}],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"}'::jsonb),
  ('srd-2024_dagger', 'Piercing', '1d4', true, false, false, '{"name":"Dagger","key":"srd-2024_dagger","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1d4","properties":[{"property":{"name":"Finesse","type":null,"desc":"When making an attack with a Finesse weapon, use your choice of your Strength or Dexterity modifier for the attack and damage rolls. You must use the same modifier for both rolls."},"detail":null},{"property":{"name":"Light","type":null,"desc":"When you take the Attack action on your turn and attack with a Light weapon, you can make one extra attack as a Bonus Action later on the same turn. That extra attack must be made with a different Light weapon, and you don''t add your ability modifier to the extra attack''s damage unless that modifier is negative."},"detail":null},{"property":{"name":"Nick","type":"Mastery","desc":"When you make the extra attack of the Light property, you can make it as part of the Attack action instead of as a Bonus Action. You can make this extra attack only once per turn."},"detail":null},{"property":{"name":"Thrown","type":null,"desc":"If a weapon has the Thrown property, you can throw the weapon to make a ranged attack, and you can draw that weapon as part of the attack. If the weapon is a Melee weapon, use the same ability modifier for the attack and damage rolls that you use for a melee attack with that weapon."},"detail":"Range 20/60"}],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"}'::jsonb),
  ('srd-2024_dart', 'Piercing', '1d4', true, false, false, '{"name":"Dart","key":"srd-2024_dart","damage_type":{"name":"Piercing","key":"piercing"},"damage_dice":"1d4","properties":[{"property":{"name":"Finesse","type":null,"desc":"When making an attack with a Finesse weapon, use your choice of your Strength or Dexterity modifier for the attack and damage rolls. You must use the same modifier for both rolls."},"detail":null},{"property":{"name":"Thrown","type":null,"desc":"If a weapon has the Thrown property, you can throw the weapon to make a ranged attack, and you can draw that weapon as part of the attack. If the weapon is a Melee weapon, use the same ability modifier for the attack and damage rolls that you use for a melee attack with that weapon."},"detail":"Range 20/60"},{"property":{"name":"Vex","type":"Mastery","desc":"If you hit a creature with this weapon and deal damage to the creature, you have Advantage on your next attack roll against that creature before the end of your next turn."},"detail":null}],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"}'::jsonb),
  ('srd-2024_flail', 'Bludgeoning', '1d8', false, true, false, '{"name":"Flail","key":"srd-2024_flail","damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"damage_dice":"1d8","properties":[{"property":{"name":"Sap","type":"Mastery","desc":"If you hit a creature with this weapon, that creature has Disadvantage on its next attack roll before the start of your next turn."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"}'::jsonb),
  ('srd-2024_glaive', 'Slashing', '1d10', false, true, false, '{"name":"Glaive","key":"srd-2024_glaive","damage_type":{"name":"Slashing","key":"slashing"},"damage_dice":"1d10","properties":[{"property":{"name":"Graze","type":"Mastery","desc":"If your attack roll with this weapon misses a creature, you can deal damage to that creature equal to the ability modifier you used to make the attack roll. This damage is the same type dealt by the weapon, and the damage can be increased only by increasing the ability modifier."},"detail":null},{"property":{"name":"Heavy","type":null,"desc":"You have Disadvantage on attack rolls with a Heavy weapon if it''s a Melee weapon and your Strength score isn''t at least 13 or if it''s a Ranged weapon and your Dexterity score isn''t at least 13."},"detail":null},{"property":{"name":"Reach","type":null,"desc":"A Reach weapon adds 5 feet to your reach when you attack with it, as well as when determining your reach for Opportunity Attacks with it."},"detail":null},{"property":{"name":"Two-Handed","type":null,"desc":"A Two-Handed weapon requires two hands when you attack with it."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"}'::jsonb),
  ('srd-2024_greataxe', 'Slashing', '1d12', false, true, false, '{"name":"Greataxe","key":"srd-2024_greataxe","damage_type":{"name":"Slashing","key":"slashing"},"damage_dice":"1d12","properties":[{"property":{"name":"Cleave","type":"Mastery","desc":"If you hit a creature with a melee attack roll using this weapon, you can make a melee attack roll with the weapon against a second creature within 5 feet of the first that is also within your reach. On a hit, the second creature takes the weapon''s damage, but don''t add your ability modifier to that damage unless that modifier is negative. You can make this extra attack only once per turn."},"detail":null},{"property":{"name":"Heavy","type":null,"desc":"You have Disadvantage on attack rolls with a Heavy weapon if it''s a Melee weapon and your Strength score isn''t at least 13 or if it''s a Ranged weapon and your Dexterity score isn''t at least 13."},"detail":null},{"property":{"name":"Two-Handed","type":null,"desc":"A Two-Handed weapon requires two hands when you attack with it."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"}'::jsonb),
  ('srd-2024_greatclub', 'Bludgeoning', '1d8', true, false, false, '{"name":"Greatclub","key":"srd-2024_greatclub","damage_type":{"name":"Bludgeoning","key":"bludgeoning"},"damage_dice":"1d8","properties":[{"property":{"name":"Push","type":"Mastery","desc":"If you hit a creature with this weapon, you can push the creature up to 10 feet straight away from yourself if it is Large or smaller."},"detail":null},{"property":{"name":"Two-Handed","type":null,"desc":"A Two-Handed weapon requires two hands when you attack with it."},"detail":null}],"is_simple":true,"is_martial":false,"is_improvised":false,"distance_unit":"feet"}'::jsonb),
  ('srd-2024_greatsword', 'Slashing', '2d6', false, true, false, '{"name":"Greatsword","key":"srd-2024_greatsword","damage_type":{"name":"Slashing","key":"slashing"},"damage_dice":"2d6","properties":[{"property":{"name":"Graze","type":"Mastery","desc":"If your attack roll with this weapon misses a creature, you can deal damage to that creature equal to the ability modifier you used to make the attack roll. This damage is the same type dealt by the weapon, and the damage can be increased only by increasing the ability modifier."},"detail":null},{"property":{"name":"Heavy","type":null,"desc":"You have Disadvantage on attack rolls with a Heavy weapon if it''s a Melee weapon and your Strength score isn''t at least 13 or if it''s a Ranged weapon and your Dexterity score isn''t at least 13."},"detail":null},{"property":{"name":"Two-Handed","type":null,"desc":"A Two-Handed weapon requires two hands when you attack with it."},"detail":null}],"is_simple":false,"is_martial":true,"is_improvised":false,"distance_unit":"feet"}'::jsonb),
